CREATE TABLE IF NOT EXISTS "public"."camaras" (
    "id" integer NOT NULL,
    "nombre" "text" NOT NULL,
    "capacidad" integer NOT NULL,
    "activa" boolean DEFAULT true
);


ALTER TABLE "public"."camaras" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_camara"("p_camara_id" integer, "p_nombre" "text", "p_capacidad" integer) RETURNS "public"."camaras"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_result public.camaras%ROWTYPE;
  v_nombre text := nullif(trim(coalesce(p_nombre, '')), '');
  v_capacidad_actual integer;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_permission('config.camaras.manage') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF v_nombre IS NULL THEN
    RAISE EXCEPTION 'Nombre requerido';
  END IF;

  IF p_capacidad IS NULL OR p_capacidad < 1 THEN
    RAISE EXCEPTION 'Capacidad invalida';
  END IF;

  SELECT capacidad
  INTO v_capacidad_actual
  FROM public.camaras
  WHERE id = p_camara_id;

  IF v_capacidad_actual IS NULL THEN
    RAISE EXCEPTION 'Camara no encontrada';
  END IF;

  IF p_capacidad <> v_capacidad_actual AND EXISTS (
    SELECT 1
    FROM public.slots
    WHERE camara_id = p_camara_id
      AND fecha >= current_date
  ) THEN
    RAISE EXCEPTION 'No se puede cambiar la capacidad de una camara con slots futuros existentes';
  END IF;

  UPDATE public.camaras
  SET nombre = v_nombre,
      capacidad = p_capacidad
  WHERE id = p_camara_id
  RETURNING * INTO v_result;

  IF v_result.id IS NULL THEN
    RAISE EXCEPTION 'Camara no encontrada';
  END IF;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_actualizar_camara"("p_camara_id" integer, "p_nombre" "text", "p_capacidad" integer) OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."campos_config" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "nombre" "text" NOT NULL,
    "tipo" "text" NOT NULL,
    "orden" integer DEFAULT 0,
    "created_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "campos_config_tipo_check" CHECK (("tipo" = ANY (ARRAY['texto'::"text", 'checkbox'::"text", 'numero'::"text"])))
);


ALTER TABLE "public"."campos_config" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_campo_config"("p_campo_id" "uuid", "p_nombre" "text", "p_tipo" "text") RETURNS "public"."campos_config"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := public.auth_current_profile_id();
  v_result public.campos_config%rowtype;
  v_nombre text := nullif(trim(coalesce(p_nombre, '')), '');
  v_tipo text := trim(coalesce(p_tipo, ''));
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('config.catalogos.manage') then
    raise exception 'Prohibido';
  end if;

  if v_nombre is null then
    raise exception 'Nombre requerido';
  end if;

  if v_tipo not in ('texto', 'checkbox', 'numero') then
    raise exception 'Tipo invalido';
  end if;

  if exists (
    select 1
    from public.campos_config
    where id <> p_campo_id
      and lower(trim(nombre)) = lower(v_nombre)
  ) then
    raise exception 'Ya existe un campo con ese nombre';
  end if;

  update public.campos_config
  set nombre = v_nombre,
      tipo = v_tipo
  where id = p_campo_id
  returning * into v_result;

  if v_result.id is null then
    raise exception 'Campo no encontrado';
  end if;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_actualizar_campo_config"("p_campo_id" "uuid", "p_nombre" "text", "p_tipo" "text") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."consultas_horarios_config" (
    "id" integer NOT NULL,
    "hora" "text" NOT NULL,
    "activo" boolean DEFAULT true NOT NULL,
    "orden" integer NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "public"."consultas_horarios_config" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_consulta_horario_config"("p_horario_id" integer, "p_hora" "text", "p_orden" integer) RETURNS "public"."consultas_horarios_config"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_result public.consultas_horarios_config%rowtype;
  v_hora text := nullif(trim(coalesce(p_hora, '')), '');
begin
  if not public.can_manage_consultas() then
    raise exception 'Prohibido';
  end if;
  if p_horario_id is null or v_hora is null or p_orden is null then
    raise exception 'Datos incompletos';
  end if;

  update public.consultas_horarios_config
  set hora = v_hora,
      orden = p_orden
  where id = p_horario_id
  returning * into v_result;

  if v_result.id is null then
    raise exception 'Horario no encontrado';
  end if;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_actualizar_consulta_horario_config"("p_horario_id" integer, "p_hora" "text", "p_orden" integer) OWNER TO "postgres";


