    "paciente_id" "uuid",
    "es_tanda" boolean DEFAULT false,
    "es_bloque_completo" boolean DEFAULT false,
    "referido_tercero" boolean DEFAULT false NOT NULL,
    "modalidad_cobro" "public"."modalidad_cobro_turno" DEFAULT 'particular'::"public"."modalidad_cobro_turno" NOT NULL,
    "obra_social_id" integer,
    "numero_autorizacion" "text",
    "obra_social_validada_por" "uuid",
    "obra_social_validada_at" timestamp with time zone,
    "apartado_por" "uuid",
    "apartado_ts" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    "medico_id" integer,
    "es_nuevo_ingreso" boolean DEFAULT false NOT NULL,
    "referente_id" integer,
    "tanda_id" "uuid",
    "sesiones_autorizadas" integer,
    "ciclo_obra_social_id" "uuid",
