    "monoxido_orden_medica" boolean DEFAULT false NOT NULL,
    "monoxido_resumen_clinico" boolean DEFAULT false NOT NULL
);


ALTER TABLE "public"."slots" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_datos_operativos_slot"("p_slot_id" "uuid", "p_referido_tercero" boolean DEFAULT false, "p_referente_id" integer DEFAULT NULL::integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno" DEFAULT 'particular'::"public"."modalidad_cobro_turno", "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_autorizacion" "text" DEFAULT NULL::"text", "p_convenio_corroborado" boolean DEFAULT false, "p_medico_id" integer DEFAULT NULL::integer, "p_es_nuevo_ingreso" boolean DEFAULT false) RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_profile_id uuid := public.auth_current_profile_id();
  v_result public.slots%ROWTYPE;
  v_current_slot public.slots%ROWTYPE;
  v_operativo_obra_social_id integer;
  v_operativo_numero_autorizacion text;
  v_operativo_sin_convenio boolean;
  v_convenio_corroborado boolean;
  v_obra_social_validada_por uuid;
  v_obra_social_validada_at timestamptz;
  v_medico_id integer;
  v_referente_id integer;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'No autorizado'; END IF;
  IF NOT EXISTS (SELECT 1 FROM public.perfiles WHERE id = v_user_id AND rol = 'admin') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;
  SELECT * INTO v_current_slot FROM public.slots WHERE id = p_slot_id AND estado = 'ocupado';
  IF v_current_slot.id IS NULL THEN RAISE EXCEPTION 'Turno ocupado no encontrado'; END IF;
  v_convenio_corroborado := coalesce(p_convenio_corroborado, false)
    OR (v_current_slot.obra_social_validada_por IS NOT NULL AND v_current_slot.obra_social_validada_at IS NOT NULL);
  SELECT obra_social_id, numero_autorizacion, sin_convenio
  INTO v_operativo_obra_social_id, v_operativo_numero_autorizacion, v_operativo_sin_convenio
  FROM public.admin_resolver_operativo_obra_social(
    v_current_slot.paciente_id, p_modalidad_cobro, p_obra_social_id, p_numero_autorizacion, v_convenio_corroborado
  );
  v_medico_id := public.admin_resolver_medico_operativo(p_medico_id, p_es_nuevo_ingreso, v_current_slot.medico_id);
  v_referente_id := public.admin_resolver_referente_operativo(p_referido_tercero, p_referente_id, v_current_slot.referente_id);
  v_obra_social_validada_por := CASE
    WHEN coalesce(p_modalidad_cobro, 'particular') <> 'obra_social' THEN null
    WHEN v_operativo_sin_convenio THEN coalesce(v_current_slot.obra_social_validada_por, v_user_id)
    ELSE null
  END;
  v_obra_social_validada_at := CASE
    WHEN coalesce(p_modalidad_cobro, 'particular') <> 'obra_social' THEN null
    WHEN v_operativo_sin_convenio THEN coalesce(v_current_slot.obra_social_validada_at, now())
    ELSE null
  END;
  UPDATE public.slots
  SET referido_tercero = coalesce(p_referido_tercero, false),
      referente_id = v_referente_id,
      modalidad_cobro = coalesce(p_modalidad_cobro, 'particular'),
      obra_social_id = v_operativo_obra_social_id,
      numero_autorizacion = v_operativo_numero_autorizacion,
      medico_id = v_medico_id,
      es_nuevo_ingreso = coalesce(p_es_nuevo_ingreso, false),
      obra_social_validada_por = v_obra_social_validada_por,
      obra_social_validada_at = v_obra_social_validada_at
  WHERE id = p_slot_id AND estado = 'ocupado'
  RETURNING * INTO v_result;
  PERFORM public.admin_insert_historial_bloque(
    v_result.fecha, v_result.hora, v_result.camara_id, v_result.id, v_result.lugar, 'datos_operativos_editados', v_result.paciente_id, v_user_id,
    null, v_result.referido_tercero, v_result.referente_id, v_result.modalidad_cobro, v_result.obra_social_id, v_result.numero_autorizacion,
    v_result.medico_id, v_result.es_nuevo_ingreso, v_result.obra_social_validada_por, v_result.obra_social_validada_at
  );
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_actualizar_datos_operativos_slot"("p_slot_id" "uuid", "p_referido_tercero" boolean, "p_referente_id" integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer, "p_numero_autorizacion" "text", "p_convenio_corroborado" boolean, "p_medico_id" integer, "p_es_nuevo_ingreso" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_datos_operativos_slot"("p_slot_id" "uuid", "p_referido_tercero" boolean DEFAULT false, "p_referente_id" integer DEFAULT NULL::integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno" DEFAULT 'particular'::"public"."modalidad_cobro_turno", "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_autorizacion" "text" DEFAULT NULL::"text", "p_sesiones_autorizadas" integer DEFAULT NULL::integer, "p_ciclo_obra_social_id" "uuid" DEFAULT NULL::"uuid", "p_iniciar_nuevo_ciclo_obra_social" boolean DEFAULT false, "p_convenio_corroborado" boolean DEFAULT false, "p_medico_id" integer DEFAULT NULL::integer, "p_es_nuevo_ingreso" boolean DEFAULT false, "p_es_monoxido" boolean DEFAULT false, "p_monoxido_orden_medica" boolean DEFAULT false, "p_monoxido_resumen_clinico" boolean DEFAULT false) RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_profile_id uuid := public.auth_current_profile_id();
  v_result public.slots%ROWTYPE;
  v_current_slot public.slots%ROWTYPE;
  v_operativo_obra_social_id integer;
  v_operativo_numero_autorizacion text;
  v_operativo_sesiones_autorizadas integer;
  v_operativo_ciclo_obra_social_id uuid;
  v_operativo_sin_convenio boolean;
  v_convenio_corroborado boolean;
  v_obra_social_validada_por uuid;
  v_obra_social_validada_at timestamptz;
  v_medico_id integer;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'No autorizado'; END IF;
  IF public.auth_current_profile_id() IS NULL THEN RAISE EXCEPTION 'Perfil no encontrado'; END IF;
  IF NOT public.can_turnos_asignar() THEN RAISE EXCEPTION 'Prohibido'; END IF;

  SELECT *
  INTO v_current_slot
  FROM public.slots
  WHERE id = p_slot_id
    AND estado = 'ocupado';

  IF v_current_slot.id IS NULL THEN
    RAISE EXCEPTION 'Turno ocupado no encontrado';
  END IF;

  IF coalesce(p_es_monoxido, false) AND (NOT coalesce(p_monoxido_orden_medica, false) OR NOT coalesce(p_monoxido_resumen_clinico, false)) THEN
    RAISE EXCEPTION 'Monoxido requiere orden medica y resumen clinico';
  END IF;

  v_convenio_corroborado := coalesce(p_convenio_corroborado, false)
    OR (v_current_slot.obra_social_validada_por IS NOT NULL AND v_current_slot.obra_social_validada_at IS NOT NULL);

  SELECT obra_social_id, numero_autorizacion, sesiones_autorizadas, ciclo_obra_social_id, sin_convenio
  INTO v_operativo_obra_social_id, v_operativo_numero_autorizacion, v_operativo_sesiones_autorizadas, v_operativo_ciclo_obra_social_id, v_operativo_sin_convenio
  FROM public.admin_resolver_operativo_obra_social(
    v_current_slot.paciente_id, p_modalidad_cobro, p_obra_social_id, p_numero_autorizacion, p_sesiones_autorizadas,
    p_ciclo_obra_social_id, p_iniciar_nuevo_ciclo_obra_social, v_convenio_corroborado
  );

  PERFORM public.admin_validar_tope_obra_social_serie(
    v_current_slot.paciente_id,
    p_modalidad_cobro,
    v_operativo_numero_autorizacion,
    v_operativo_sesiones_autorizadas,
    v_operativo_ciclo_obra_social_id,
    ARRAY[p_slot_id]::uuid[],
    1
  );

  v_medico_id := public.admin_resolver_medico_operativo(p_medico_id, p_es_nuevo_ingreso, v_current_slot.medico_id);
  v_obra_social_validada_por := CASE
    WHEN coalesce(p_modalidad_cobro, 'particular') <> 'obra_social' THEN null
    WHEN v_operativo_sin_convenio THEN coalesce(public.resolve_profile_id(v_current_slot.obra_social_validada_por), public.auth_current_profile_id())
    ELSE null
  END;
  v_obra_social_validada_at := CASE
    WHEN coalesce(p_modalidad_cobro, 'particular') <> 'obra_social' THEN null
    WHEN v_operativo_sin_convenio THEN coalesce(v_current_slot.obra_social_validada_at, now())
    ELSE null
  END;

  UPDATE public.slots
  SET referido_tercero = coalesce(p_referido_tercero, false),
      referente_id = public.admin_resolver_referente_operativo(p_referido_tercero, p_referente_id, v_current_slot.referente_id),
      modalidad_cobro = coalesce(p_modalidad_cobro, 'particular'),
      obra_social_id = v_operativo_obra_social_id,
      numero_autorizacion = v_operativo_numero_autorizacion,
      sesiones_autorizadas = v_operativo_sesiones_autorizadas,
      ciclo_obra_social_id = v_operativo_ciclo_obra_social_id,
      medico_id = v_medico_id,
      es_nuevo_ingreso = coalesce(p_es_nuevo_ingreso, false),
      obra_social_validada_por = v_obra_social_validada_por,
      obra_social_validada_at = v_obra_social_validada_at,
      es_monoxido = coalesce(p_es_monoxido, false),
      monoxido_orden_medica = CASE WHEN coalesce(p_es_monoxido, false) THEN coalesce(p_monoxido_orden_medica, false) ELSE false END,
      monoxido_resumen_clinico = CASE WHEN coalesce(p_es_monoxido, false) THEN coalesce(p_monoxido_resumen_clinico, false) ELSE false END
  WHERE id = p_slot_id
    AND estado = 'ocupado'
  RETURNING * INTO v_result;

  PERFORM public.admin_insert_historial_bloque(
    v_result.fecha, v_result.hora, v_result.camara_id, v_result.id, v_result.lugar, 'datos_operativos_editados', v_result.paciente_id, v_user_id,
    null, v_result.referido_tercero, v_result.referente_id, v_result.modalidad_cobro, v_result.obra_social_id,
    v_result.numero_autorizacion, v_result.sesiones_autorizadas, v_result.ciclo_obra_social_id, v_result.medico_id,
    v_result.es_nuevo_ingreso, v_result.obra_social_validada_por, v_result.obra_social_validada_at, v_result.tanda_id
  );
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_actualizar_datos_operativos_slot"("p_slot_id" "uuid", "p_referido_tercero" boolean, "p_referente_id" integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer, "p_numero_autorizacion" "text", "p_sesiones_autorizadas" integer, "p_ciclo_obra_social_id" "uuid", "p_iniciar_nuevo_ciclo_obra_social" boolean, "p_convenio_corroborado" boolean, "p_medico_id" integer, "p_es_nuevo_ingreso" boolean, "p_es_monoxido" boolean, "p_monoxido_orden_medica" boolean, "p_monoxido_resumen_clinico" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_datos_operativos_tanda"("p_tanda_id" "uuid", "p_referido_tercero" boolean DEFAULT false, "p_referente_id" integer DEFAULT NULL::integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno" DEFAULT 'particular'::"public"."modalidad_cobro_turno", "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_autorizacion" "text" DEFAULT NULL::"text", "p_sesiones_autorizadas" integer DEFAULT NULL::integer, "p_ciclo_obra_social_id" "uuid" DEFAULT NULL::"uuid", "p_iniciar_nuevo_ciclo_obra_social" boolean DEFAULT false, "p_convenio_corroborado" boolean DEFAULT false, "p_medico_id" integer DEFAULT NULL::integer, "p_es_nuevo_ingreso" boolean DEFAULT false) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_reference_slot public.slots%ROWTYPE;
  v_row public.slots%ROWTYPE;
  v_operativo_obra_social_id integer;
  v_operativo_numero_autorizacion text;
  v_operativo_sesiones_autorizadas integer;
  v_operativo_ciclo_obra_social_id uuid;
  v_operativo_sin_convenio boolean;
  v_convenio_corroborado boolean;
  v_obra_social_validada_por uuid;
  v_obra_social_validada_at timestamptz;
  v_medico_id integer;
  v_updated_count integer := 0;
  v_exclude_slot_ids uuid[];
  v_unidades_tanda integer := 0;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'No autorizado'; END IF;
  IF NOT EXISTS (SELECT 1 FROM public.perfiles WHERE id = v_user_id AND rol = 'admin') THEN RAISE EXCEPTION 'Prohibido'; END IF;
  IF p_tanda_id IS NULL THEN RAISE EXCEPTION 'Tanda invalida'; END IF;

  SELECT *
  INTO v_reference_slot
  FROM public.slots
  WHERE tanda_id = p_tanda_id
    AND estado = 'ocupado'
  ORDER BY fecha, hora, camara_id, lugar
  LIMIT 1;

  IF v_reference_slot.id IS NULL THEN
    RAISE EXCEPTION 'No hay turnos ocupados para esta tanda';
  END IF;

  SELECT array_agg(id ORDER BY fecha, hora, camara_id, lugar)
  INTO v_exclude_slot_ids
  FROM public.slots
  WHERE tanda_id = p_tanda_id
    AND estado = 'ocupado';

  SELECT count(*)
  INTO v_unidades_tanda
  FROM (
    SELECT fecha, hora, camara_id
    FROM public.slots
    WHERE tanda_id = p_tanda_id
      AND estado = 'ocupado'
    GROUP BY fecha, hora, camara_id
  ) units;

  v_convenio_corroborado := coalesce(p_convenio_corroborado, false)
    OR EXISTS (
      SELECT 1
      FROM public.slots
      WHERE tanda_id = p_tanda_id
        AND estado = 'ocupado'
        AND obra_social_validada_por IS NOT NULL
        AND obra_social_validada_at IS NOT NULL
    );

  SELECT obra_social_id, numero_autorizacion, sesiones_autorizadas, ciclo_obra_social_id, sin_convenio
  INTO v_operativo_obra_social_id, v_operativo_numero_autorizacion, v_operativo_sesiones_autorizadas, v_operativo_ciclo_obra_social_id, v_operativo_sin_convenio
  FROM public.admin_resolver_operativo_obra_social(
    v_reference_slot.paciente_id, p_modalidad_cobro, p_obra_social_id, p_numero_autorizacion, p_sesiones_autorizadas,
    p_ciclo_obra_social_id, p_iniciar_nuevo_ciclo_obra_social, v_convenio_corroborado
  );

  PERFORM public.admin_validar_tope_obra_social_serie(
    v_reference_slot.paciente_id,
    p_modalidad_cobro,
    v_operativo_numero_autorizacion,
    v_operativo_sesiones_autorizadas,
    v_operativo_ciclo_obra_social_id,
    coalesce(v_exclude_slot_ids, ARRAY[]::uuid[]),
    greatest(coalesce(v_unidades_tanda, 0), 1)
  );

  v_medico_id := public.admin_resolver_medico_operativo(p_medico_id, p_es_nuevo_ingreso, v_reference_slot.medico_id);
  v_obra_social_validada_por := CASE
    WHEN coalesce(p_modalidad_cobro, 'particular') <> 'obra_social' THEN null
    WHEN v_operativo_sin_convenio THEN v_user_id
    ELSE null
  END;
  v_obra_social_validada_at := CASE
    WHEN coalesce(p_modalidad_cobro, 'particular') <> 'obra_social' THEN null
    WHEN v_operativo_sin_convenio THEN now()
    ELSE null
  END;

  FOR v_row IN
    UPDATE public.slots
    SET referido_tercero = coalesce(p_referido_tercero, false),
        referente_id = public.admin_resolver_referente_operativo(p_referido_tercero, p_referente_id, referente_id),
        modalidad_cobro = coalesce(p_modalidad_cobro, 'particular'),
        obra_social_id = v_operativo_obra_social_id,
        numero_autorizacion = v_operativo_numero_autorizacion,
        sesiones_autorizadas = v_operativo_sesiones_autorizadas,
        ciclo_obra_social_id = v_operativo_ciclo_obra_social_id,
        medico_id = v_medico_id,
        es_nuevo_ingreso = coalesce(p_es_nuevo_ingreso, false),
        obra_social_validada_por = CASE
          WHEN coalesce(p_modalidad_cobro, 'particular') <> 'obra_social' THEN null
          WHEN v_operativo_sin_convenio THEN coalesce(obra_social_validada_por, v_obra_social_validada_por)
          ELSE null
        END,
        obra_social_validada_at = CASE
          WHEN coalesce(p_modalidad_cobro, 'particular') <> 'obra_social' THEN null
          WHEN v_operativo_sin_convenio THEN coalesce(obra_social_validada_at, v_obra_social_validada_at)
          ELSE null
        END
    WHERE tanda_id = p_tanda_id
      AND estado = 'ocupado'
    RETURNING *
  LOOP
    v_updated_count := v_updated_count + 1;
    PERFORM public.admin_insert_historial_bloque(
      v_row.fecha, v_row.hora, v_row.camara_id, v_row.id, v_row.lugar, 'datos_operativos_tanda_editados', v_row.paciente_id, v_user_id,
      null, v_row.referido_tercero, v_row.referente_id, v_row.modalidad_cobro, v_row.obra_social_id,
      v_row.numero_autorizacion, v_row.sesiones_autorizadas, v_row.ciclo_obra_social_id, v_row.medico_id,
      v_row.es_nuevo_ingreso, v_row.obra_social_validada_por, v_row.obra_social_validada_at, v_row.tanda_id
    );
  END LOOP;

  RETURN v_updated_count;
END;
$$;


ALTER FUNCTION "public"."admin_actualizar_datos_operativos_tanda"("p_tanda_id" "uuid", "p_referido_tercero" boolean, "p_referente_id" integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer, "p_numero_autorizacion" "text", "p_sesiones_autorizadas" integer, "p_ciclo_obra_social_id" "uuid", "p_iniciar_nuevo_ciclo_obra_social" boolean, "p_convenio_corroborado" boolean, "p_medico_id" integer, "p_es_nuevo_ingreso" boolean) OWNER TO "postgres";


