    "paciente_id" "uuid" NOT NULL,
    "numero" bigint NOT NULL,
    "antecedentes" "text",
    "alergias" "text",
    "medicacion_actual" "text",
    "observaciones_relevantes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "public"."historias_clinicas" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_historia_clinica"("p_paciente_id" "uuid", "p_antecedentes" "text" DEFAULT NULL::"text", "p_alergias" "text" DEFAULT NULL::"text", "p_medicacion_actual" "text" DEFAULT NULL::"text", "p_observaciones_relevantes" "text" DEFAULT NULL::"text") RETURNS "public"."historias_clinicas"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_result public.historias_clinicas%rowtype;
begin
  if not public.can_historia_clinica_editar_ficha() then
    raise exception 'Prohibido';
  end if;

  perform public.ensure_historia_clinica_for_patient(p_paciente_id);

  update public.historias_clinicas
  set antecedentes = nullif(trim(coalesce(p_antecedentes, '')), ''),
      alergias = nullif(trim(coalesce(p_alergias, '')), ''),
      medicacion_actual = nullif(trim(coalesce(p_medicacion_actual, '')), ''),
      observaciones_relevantes = nullif(trim(coalesce(p_observaciones_relevantes, '')), '')
  where paciente_id = p_paciente_id
  returning * into v_result;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_actualizar_historia_clinica"("p_paciente_id" "uuid", "p_antecedentes" "text", "p_alergias" "text", "p_medicacion_actual" "text", "p_observaciones_relevantes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_historia_clinica_numero"("p_paciente_id" "uuid", "p_numero" bigint) RETURNS "public"."historias_clinicas"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_result public.historias_clinicas%rowtype;
begin
  if not public.can_historia_clinica_editar_numero() then
    raise exception 'Prohibido';
  end if;

  if p_numero is null or p_numero <= 0 then
    raise exception 'Numero de HC invalido';
  end if;

  perform public.ensure_historia_clinica_for_patient(p_paciente_id);

  if exists (
    select 1
    from public.historias_clinicas
    where numero = p_numero
      and paciente_id <> p_paciente_id
  ) then
    raise exception 'Numero de HC duplicado';
  end if;

  update public.historias_clinicas
  set numero = p_numero
  where paciente_id = p_paciente_id
  returning * into v_result;

  perform setval(
    'public.historia_clinica_numero_seq',
    greatest(
      coalesce((select max(numero) from public.historias_clinicas), 0),
      p_numero
    ),
    true
  );

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_actualizar_historia_clinica_numero"("p_paciente_id" "uuid", "p_numero" bigint) OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."horarios_config" (
    "id" integer NOT NULL,
    "hora" "text" NOT NULL,
    "activo" boolean DEFAULT true NOT NULL,
    "orden" integer NOT NULL
);


ALTER TABLE "public"."horarios_config" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_horario_config"("p_horario_id" integer, "p_hora" "text", "p_orden" integer) RETURNS "public"."horarios_config"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_user_id uuid := auth.uid();
  v_result public.horarios_config%rowtype;
  v_hora text := nullif(trim(coalesce(p_hora, '')), '');
  v_hora_actual text;
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('config.horarios.manage') then
    raise exception 'Prohibido';
  end if;

  if v_hora is null or v_hora !~ '^[0-2][0-9]:[0-5][0-9]$' then
    raise exception 'Hora invalida';
  end if;

  if p_orden is null or p_orden < 1 then
    raise exception 'Orden invalido';
  end if;

  if exists (
    select 1
    from public.horarios_config
    where hora = v_hora
      and id <> p_horario_id
  ) then
    raise exception 'Ya existe un horario con esa hora';
  end if;

  select hora
  into v_hora_actual
  from public.horarios_config
  where id = p_horario_id;

  if v_hora_actual is null then
    raise exception 'Horario no encontrado';
  end if;

  if v_hora <> v_hora_actual and exists (
    select 1
    from public.slots
    where hora = v_hora_actual
      and fecha >= current_date
  ) then
    raise exception 'No se puede cambiar la hora de un horario con slots futuros existentes';
  end if;

  update public.horarios_config
  set hora = v_hora,
      orden = p_orden
  where id = p_horario_id
  returning * into v_result;

  if v_result.id is null then
    raise exception 'Horario no encontrado';
  end if;

  return v_result;
end;
$_$;


ALTER FUNCTION "public"."admin_actualizar_horario_config"("p_horario_id" integer, "p_hora" "text", "p_orden" integer) OWNER TO "postgres";


