CREATE OR REPLACE FUNCTION "public"."admin_actualizar_medico"("p_medico_id" integer, "p_nombre" "text") RETURNS "public"."medicos"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_result public.medicos%ROWTYPE;
  v_nombre text := nullif(trim(coalesce(p_nombre, '')), '');
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_permission('config.catalogos.manage') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF v_nombre IS NULL THEN
    RAISE EXCEPTION 'Nombre requerido';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.medicos
    WHERE id <> p_medico_id
      AND lower(nombre) = lower(v_nombre)
  ) THEN
    RAISE EXCEPTION 'Nombre duplicado';
  END IF;

  UPDATE public.medicos
  SET nombre = v_nombre
  WHERE id = p_medico_id
  RETURNING * INTO v_result;

  IF v_result.id IS NULL THEN
    RAISE EXCEPTION 'Medico no encontrado';
  END IF;

  RETURN v_result;
END;
$$;


