    "created_at" timestamp with time zone DEFAULT "now"(),
    "claustrofobico" boolean DEFAULT false,
    "notas" "text",
    "datos_extra" "jsonb" DEFAULT '{}'::"jsonb",
    "opt_in_whatsapp" boolean DEFAULT false NOT NULL,
