    "portal_ultima_activacion_at" timestamp with time zone,
    "documento_identidad_normalizado" "text",
    "primera_sesion_efectivizada" boolean DEFAULT false NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"(),
    "numero_credencial_obra_social" "text",
    "portal_access_token_issued_at" timestamp with time zone,
    "portal_access_token_expires_at" timestamp with time zone,
