ALTER TABLE "public"."perfiles" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_paciente"("p_paciente_id" "uuid", "p_email" "text" DEFAULT NULL::"text", "p_telefono" "text" DEFAULT NULL::"text", "p_documento_identidad" "text" DEFAULT NULL::"text", "p_nacionalidad" "text" DEFAULT NULL::"text", "p_condicion_iva_id" integer DEFAULT NULL::integer, "p_claustrofobico" boolean DEFAULT false, "p_notas" "text" DEFAULT NULL::"text", "p_datos_extra" "jsonb" DEFAULT '{}'::"jsonb", "p_actualizar_notas" boolean DEFAULT true) RETURNS "public"."perfiles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_result public.perfiles%ROWTYPE;
  v_email text := nullif(lower(trim(coalesce(p_email, ''))), '');
  v_telefono text := nullif(trim(coalesce(p_telefono, '')), '');
  v_documento_identidad text := nullif(trim(coalesce(p_documento_identidad, '')), '');
  v_documento_normalizado text := public.normalize_documento_identidad(p_documento_identidad);
  v_nacionalidad text := nullif(trim(coalesce(p_nacionalidad, '')), '');
  v_notas text := nullif(trim(coalesce(p_notas, '')), '');
  v_datos_extra jsonb := coalesce(p_datos_extra, '{}'::jsonb);
  v_portal_habilitado boolean := false;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.can_pacientes_editar() THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  SELECT portal_habilitado
  INTO v_portal_habilitado
  FROM public.perfiles
  WHERE id = p_paciente_id
    AND rol = 'paciente';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Paciente no encontrado';
  END IF;

  IF jsonb_typeof(v_datos_extra) IS DISTINCT FROM 'object' THEN
    RAISE EXCEPTION 'datos_extra invalido';
  END IF;

  IF v_telefono IS NULL THEN
    RAISE EXCEPTION 'Telefono requerido';
  END IF;

  IF v_documento_identidad IS NULL OR v_documento_normalizado IS NULL THEN
    RAISE EXCEPTION 'Documento de identidad requerido';
  END IF;

  IF p_condicion_iva_id IS NOT NULL AND NOT EXISTS (
    SELECT 1
    FROM public.condiciones_iva
    WHERE id = p_condicion_iva_id
  ) THEN
    RAISE EXCEPTION 'Condicion de IVA invalida';
  END IF;

  IF v_portal_habilitado AND EXISTS (
    SELECT 1
    FROM public.perfiles
    WHERE id <> p_paciente_id
      AND rol = 'paciente'
      AND portal_habilitado = true
      AND documento_identidad_normalizado = v_documento_normalizado
  ) THEN
    RAISE EXCEPTION 'Documento de identidad ya en uso para acceso al portal';
  END IF;

  UPDATE public.perfiles
  SET
    email = v_email,
    telefono = v_telefono,
    documento_identidad = v_documento_identidad,
    documento_identidad_normalizado = v_documento_normalizado,
    nacionalidad = CASE
      WHEN coalesce(v_documento_identidad, '') ~ '[A-Za-z]' THEN v_nacionalidad
      ELSE NULL
    END,
    condicion_iva_id = p_condicion_iva_id,
    claustrofobico = coalesce(p_claustrofobico, false),
    notas = CASE
      WHEN coalesce(p_actualizar_notas, true) THEN v_notas
      ELSE notas
    END,
    datos_extra = v_datos_extra
  WHERE id = p_paciente_id
  RETURNING * INTO v_result;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_actualizar_paciente"("p_paciente_id" "uuid", "p_email" "text", "p_telefono" "text", "p_documento_identidad" "text", "p_nacionalidad" "text", "p_condicion_iva_id" integer, "p_claustrofobico" boolean, "p_notas" "text", "p_datos_extra" "jsonb", "p_actualizar_notas" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_paciente"("p_paciente_id" "uuid", "p_email" "text" DEFAULT NULL::"text", "p_telefono" "text" DEFAULT NULL::"text", "p_documento_identidad" "text" DEFAULT NULL::"text", "p_nacionalidad" "text" DEFAULT NULL::"text", "p_condicion_iva_id" integer DEFAULT NULL::integer, "p_obra_social_id" integer DEFAULT NULL::integer, "p_claustrofobico" boolean DEFAULT false, "p_notas" "text" DEFAULT NULL::"text", "p_datos_extra" "jsonb" DEFAULT '{}'::"jsonb", "p_actualizar_notas" boolean DEFAULT true) RETURNS "public"."perfiles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_result public.perfiles%ROWTYPE;
  v_email text := nullif(lower(trim(coalesce(p_email, ''))), '');
  v_telefono text := nullif(trim(coalesce(p_telefono, '')), '');
  v_documento_identidad text := nullif(trim(coalesce(p_documento_identidad, '')), '');
  v_documento_normalizado text := public.normalize_documento_identidad(p_documento_identidad);
  v_nacionalidad text := nullif(trim(coalesce(p_nacionalidad, '')), '');
  v_notas text := nullif(trim(coalesce(p_notas, '')), '');
  v_datos_extra jsonb := coalesce(p_datos_extra, '{}'::jsonb);
  v_portal_habilitado boolean := false;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.perfiles WHERE id = v_user_id AND rol = 'admin'
  ) THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  SELECT portal_habilitado
  INTO v_portal_habilitado
  FROM public.perfiles
  WHERE id = p_paciente_id
    AND rol = 'paciente';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Paciente no encontrado';
  END IF;

  IF jsonb_typeof(v_datos_extra) IS DISTINCT FROM 'object' THEN
    RAISE EXCEPTION 'datos_extra invalido';
  END IF;

  IF v_telefono IS NULL THEN
    RAISE EXCEPTION 'Telefono requerido';
  END IF;

  IF v_documento_identidad IS NULL OR v_documento_normalizado IS NULL THEN
    RAISE EXCEPTION 'Documento de identidad requerido';
  END IF;

  IF p_condicion_iva_id IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM public.condiciones_iva WHERE id = p_condicion_iva_id
  ) THEN
    RAISE EXCEPTION 'Condicion de IVA invalida';
  END IF;

  IF p_obra_social_id IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM public.obras_sociales WHERE id = p_obra_social_id
  ) THEN
    RAISE EXCEPTION 'Obra social invalida';
  END IF;

  IF v_portal_habilitado AND EXISTS (
    SELECT 1
    FROM public.perfiles
    WHERE id <> p_paciente_id
      AND rol = 'paciente'
      AND portal_habilitado = true
      AND documento_identidad_normalizado = v_documento_normalizado
  ) THEN
    RAISE EXCEPTION 'Documento de identidad ya en uso para acceso al portal';
  END IF;

  UPDATE public.perfiles
  SET
    email = v_email,
    telefono = v_telefono,
    documento_identidad = v_documento_identidad,
    documento_identidad_normalizado = v_documento_normalizado,
    nacionalidad = CASE
      WHEN coalesce(v_documento_identidad, '') ~ '[A-Za-z]' THEN v_nacionalidad
      ELSE NULL
    END,
    condicion_iva_id = p_condicion_iva_id,
    obra_social_id = p_obra_social_id,
    claustrofobico = coalesce(p_claustrofobico, false),
    notas = CASE
      WHEN coalesce(p_actualizar_notas, true) THEN v_notas
      ELSE notas
    END,
    datos_extra = v_datos_extra
  WHERE id = p_paciente_id
  RETURNING * INTO v_result;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_actualizar_paciente"("p_paciente_id" "uuid", "p_email" "text", "p_telefono" "text", "p_documento_identidad" "text", "p_nacionalidad" "text", "p_condicion_iva_id" integer, "p_obra_social_id" integer, "p_claustrofobico" boolean, "p_notas" "text", "p_datos_extra" "jsonb", "p_actualizar_notas" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_paciente"("p_paciente_id" "uuid", "p_email" "text" DEFAULT NULL::"text", "p_telefono" "text" DEFAULT NULL::"text", "p_documento_identidad" "text" DEFAULT NULL::"text", "p_nacionalidad" "text" DEFAULT NULL::"text", "p_condicion_iva_id" integer DEFAULT NULL::integer, "p_obra_social_id" integer DEFAULT NULL::integer, "p_claustrofobico" boolean DEFAULT false, "p_notas" "text" DEFAULT NULL::"text", "p_datos_extra" "jsonb" DEFAULT '{}'::"jsonb", "p_actualizar_notas" boolean DEFAULT true, "p_opt_in_whatsapp" boolean DEFAULT false, "p_opt_in_source" "text" DEFAULT NULL::"text") RETURNS "public"."perfiles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_result public.perfiles%ROWTYPE;
  v_email text := nullif(lower(trim(coalesce(p_email, ''))), '');
  v_telefono text := nullif(trim(coalesce(p_telefono, '')), '');
  v_documento_identidad text := nullif(trim(coalesce(p_documento_identidad, '')), '');
  v_documento_normalizado text := public.normalize_documento_identidad(p_documento_identidad);
  v_nacionalidad text := nullif(trim(coalesce(p_nacionalidad, '')), '');
  v_notas text := nullif(trim(coalesce(p_notas, '')), '');
  v_datos_extra jsonb := coalesce(p_datos_extra, '{}'::jsonb);
  v_portal_habilitado boolean := false;
  v_opt_in_source text := nullif(trim(coalesce(p_opt_in_source, '')), '');
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.perfiles WHERE id = v_user_id AND rol = 'admin'
  ) THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  SELECT portal_habilitado
  INTO v_portal_habilitado
  FROM public.perfiles
  WHERE id = p_paciente_id
    AND rol = 'paciente';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Paciente no encontrado';
  END IF;

  IF jsonb_typeof(v_datos_extra) IS DISTINCT FROM 'object' THEN
    RAISE EXCEPTION 'datos_extra invalido';
  END IF;

  IF v_telefono IS NULL THEN
    RAISE EXCEPTION 'Telefono requerido';
  END IF;

  IF v_documento_identidad IS NULL OR v_documento_normalizado IS NULL THEN
    RAISE EXCEPTION 'Documento de identidad requerido';
  END IF;

  IF p_condicion_iva_id IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM public.condiciones_iva WHERE id = p_condicion_iva_id
  ) THEN
    RAISE EXCEPTION 'Condicion de IVA invalida';
  END IF;

  IF p_obra_social_id IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM public.obras_sociales WHERE id = p_obra_social_id
  ) THEN
    RAISE EXCEPTION 'Obra social invalida';
  END IF;

  IF v_portal_habilitado AND EXISTS (
    SELECT 1
    FROM public.perfiles p
    WHERE p.id <> p_paciente_id
      AND p.rol = 'paciente'
      AND p.portal_habilitado = true
      AND p.documento_identidad_normalizado = v_documento_normalizado
  ) THEN
    RAISE EXCEPTION 'Documento de identidad ya en uso para acceso al portal';
  END IF;

  UPDATE public.perfiles
  SET
    email = v_email,
    telefono = v_telefono,
    documento_identidad = v_documento_identidad,
    documento_identidad_normalizado = v_documento_normalizado,
    nacionalidad = CASE
      WHEN coalesce(v_documento_identidad, '') ~ '[A-Za-z]' THEN v_nacionalidad
      ELSE NULL
    END,
    condicion_iva_id = p_condicion_iva_id,
    obra_social_id = p_obra_social_id,
    claustrofobico = coalesce(p_claustrofobico, false),
    notas = CASE
      WHEN coalesce(p_actualizar_notas, true) THEN v_notas
      ELSE notas
    END,
    datos_extra = v_datos_extra,
    opt_in_whatsapp = coalesce(p_opt_in_whatsapp, false),
    opt_in_at = CASE
      WHEN coalesce(p_opt_in_whatsapp, false) THEN
        CASE WHEN coalesce(opt_in_whatsapp, false) THEN coalesce(opt_in_at, now()) ELSE now() END
      ELSE NULL
    END,
    opt_in_source = CASE
      WHEN coalesce(p_opt_in_whatsapp, false) THEN coalesce(v_opt_in_source, opt_in_source, 'admin_edicion')
      ELSE NULL
    END
  WHERE id = p_paciente_id
  RETURNING * INTO v_result;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_actualizar_paciente"("p_paciente_id" "uuid", "p_email" "text", "p_telefono" "text", "p_documento_identidad" "text", "p_nacionalidad" "text", "p_condicion_iva_id" integer, "p_obra_social_id" integer, "p_claustrofobico" boolean, "p_notas" "text", "p_datos_extra" "jsonb", "p_actualizar_notas" boolean, "p_opt_in_whatsapp" boolean, "p_opt_in_source" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_paciente"("p_paciente_id" "uuid", "p_email" "text" DEFAULT NULL::"text", "p_telefono" "text" DEFAULT NULL::"text", "p_documento_identidad" "text" DEFAULT NULL::"text", "p_nacionalidad" "text" DEFAULT NULL::"text", "p_condicion_iva_id" integer DEFAULT NULL::integer, "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_credencial_obra_social" "text" DEFAULT NULL::"text", "p_claustrofobico" boolean DEFAULT false, "p_notas" "text" DEFAULT NULL::"text", "p_datos_extra" "jsonb" DEFAULT '{}'::"jsonb", "p_actualizar_notas" boolean DEFAULT true, "p_opt_in_whatsapp" boolean DEFAULT false, "p_opt_in_source" "text" DEFAULT NULL::"text") RETURNS "public"."perfiles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_result public.perfiles%rowtype;
  v_email text := nullif(lower(trim(coalesce(p_email, ''))), '');
  v_telefono text := nullif(trim(coalesce(p_telefono, '')), '');
  v_documento_identidad text := nullif(trim(coalesce(p_documento_identidad, '')), '');
  v_documento_normalizado text := public.normalize_documento_identidad(p_documento_identidad);
  v_nacionalidad text := nullif(trim(coalesce(p_nacionalidad, '')), '');
  v_numero_credencial_obra_social text := nullif(trim(coalesce(p_numero_credencial_obra_social, '')), '');
  v_notas text := nullif(trim(coalesce(p_notas, '')), '');
  v_datos_extra jsonb := coalesce(p_datos_extra, '{}'::jsonb);
  v_portal_habilitado boolean := false;
  v_opt_in_source text := nullif(trim(coalesce(p_opt_in_source, '')), '');
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('pacientes.editar') then
    raise exception 'Prohibido';
  end if;

  select portal_habilitado
  into v_portal_habilitado
  from public.perfiles
  where id = p_paciente_id
    and rol = 'paciente';

  if not found then
    raise exception 'Paciente no encontrado';
  end if;

  if jsonb_typeof(v_datos_extra) is distinct from 'object' then
    raise exception 'datos_extra invalido';
  end if;

  if v_telefono is null then
    raise exception 'Telefono requerido';
  end if;

  if v_documento_identidad is null or v_documento_normalizado is null then
    raise exception 'Documento de identidad requerido';
  end if;

  if p_condicion_iva_id is not null and not exists (
    select 1 from public.condiciones_iva where id = p_condicion_iva_id
  ) then
    raise exception 'Condicion de IVA invalida';
  end if;

  if p_obra_social_id is not null and not exists (
    select 1 from public.obras_sociales where id = p_obra_social_id
  ) then
    raise exception 'Obra social invalida';
  end if;

  if v_portal_habilitado and exists (
    select 1
    from public.perfiles p
    where p.id <> p_paciente_id
      and p.rol = 'paciente'
      and p.portal_habilitado = true
      and p.documento_identidad_normalizado = v_documento_normalizado
  ) then
    raise exception 'Documento de identidad ya en uso para acceso al portal';
  end if;

  update public.perfiles
  set
    email = v_email,
    telefono = v_telefono,
    documento_identidad = v_documento_identidad,
    documento_identidad_normalizado = v_documento_normalizado,
    nacionalidad = case
      when coalesce(v_documento_identidad, '') ~ '[A-Za-z]' then v_nacionalidad
      else null
    end,
    condicion_iva_id = p_condicion_iva_id,
    obra_social_id = p_obra_social_id,
    numero_credencial_obra_social = v_numero_credencial_obra_social,
    claustrofobico = coalesce(p_claustrofobico, false),
    notas = case
      when coalesce(p_actualizar_notas, true) then v_notas
      else notas
    end,
    datos_extra = v_datos_extra,
    opt_in_whatsapp = coalesce(p_opt_in_whatsapp, false),
    opt_in_at = case
      when coalesce(p_opt_in_whatsapp, false) then
        case when coalesce(opt_in_whatsapp, false) then coalesce(opt_in_at, now()) else now() end
      else null
    end,
    opt_in_source = case
      when coalesce(p_opt_in_whatsapp, false) then coalesce(v_opt_in_source, opt_in_source, 'admin_edicion')
      else null
    end
  where id = p_paciente_id
  returning * into v_result;

  return v_result;
end;
$$;


