CREATE TABLE IF NOT EXISTS "public"."referentes" (
    "id" integer NOT NULL,
    "nombre" "text" NOT NULL,
    "tipo" "text" NOT NULL,
    "activo" boolean DEFAULT true NOT NULL,
    "orden" integer DEFAULT 0 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "referentes_tipo_check" CHECK (("tipo" = ANY (ARRAY['doctor'::"text", 'agencia'::"text", 'otro'::"text"])))
);


ALTER TABLE "public"."referentes" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_referente"("p_referente_id" integer, "p_nombre" "text", "p_tipo" "text") RETURNS "public"."referentes"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_nombre text := nullif(trim(coalesce(p_nombre, '')), '');
  v_tipo text;
  v_result public.referentes%ROWTYPE;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_permission('config.catalogos.manage') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF v_nombre IS NULL THEN
    RAISE EXCEPTION 'Nombre requerido';
  END IF;

  v_tipo := public.admin_normalizar_tipo_referente(p_tipo);

  IF EXISTS (
    SELECT 1 FROM public.referentes
    WHERE id <> p_referente_id
      AND lower(btrim(nombre)) = lower(btrim(v_nombre))
      AND tipo = v_tipo
  ) THEN
    RAISE EXCEPTION 'Ya existe un referente con ese nombre y tipo';
  END IF;

  UPDATE public.referentes
  SET nombre = v_nombre,
      tipo = v_tipo,
      updated_at = now()
  WHERE id = p_referente_id
  RETURNING * INTO v_result;

  IF v_result.id IS NULL THEN
    RAISE EXCEPTION 'Referente no encontrado';
  END IF;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_actualizar_referente"("p_referente_id" integer, "p_nombre" "text", "p_tipo" "text") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."whatsapp_message_settings" (
    "key" "text" NOT NULL,
    "label" "text" NOT NULL,
    "description" "text",
    "message_text" "text" NOT NULL,
    "active" boolean DEFAULT true NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "public"."whatsapp_message_settings" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_actualizar_whatsapp_message_setting"("p_key" "text", "p_message_text" "text", "p_active" boolean DEFAULT true) RETURNS "public"."whatsapp_message_settings"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_key text := nullif(trim(coalesce(p_key, '')), '');
  v_message_text text := nullif(trim(coalesce(p_message_text, '')), '');
  v_result public.whatsapp_message_settings%ROWTYPE;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_permission('config.whatsapp.manage') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF v_key IS NULL THEN
    RAISE EXCEPTION 'Clave requerida';
  END IF;

  IF coalesce(p_active, true) AND v_message_text IS NULL THEN
    RAISE EXCEPTION 'El mensaje no puede estar vacio si la configuracion esta activa';
  END IF;

  IF v_message_text IS NOT NULL AND char_length(v_message_text) > 500 THEN
    RAISE EXCEPTION 'El mensaje no puede superar los 500 caracteres';
  END IF;

  UPDATE public.whatsapp_message_settings
  SET
    message_text = coalesce(v_message_text, message_text),
    active = coalesce(p_active, true)
  WHERE key = v_key
  RETURNING * INTO v_result;

  IF v_result.key IS NULL THEN
    RAISE EXCEPTION 'Configuracion no encontrada';
  END IF;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_actualizar_whatsapp_message_setting"("p_key" "text", "p_message_text" "text", "p_active" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_apartar_slot"("p_slot_id" "uuid", "p_paciente_id" "uuid" DEFAULT NULL::"uuid", "p_es_monoxido" boolean DEFAULT false) RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := public.auth_current_profile_id();
  v_result public.slots%ROWTYPE;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No se encontro el perfil del usuario autenticado';
  END IF;

  IF NOT public.can_reportes_export() THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF p_paciente_id IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM public.perfiles WHERE id = p_paciente_id AND rol = 'paciente'
  ) THEN
    RAISE EXCEPTION 'Paciente no valido';
  END IF;

  UPDATE public.slots
  SET estado = 'apartado',
      paciente_id = p_paciente_id,
      apartado_por = v_user_id,
      apartado_ts = now(),
      referido_tercero = false,
      modalidad_cobro = 'particular',
      obra_social_id = null,
      numero_autorizacion = null,
      obra_social_validada_por = null,
      obra_social_validada_at = null,
      es_monoxido = coalesce(p_es_monoxido, false),
      monoxido_orden_medica = false,
      monoxido_resumen_clinico = false
  WHERE id = p_slot_id
  RETURNING * INTO v_result;

  IF v_result.id IS NULL THEN
    RAISE EXCEPTION 'Slot no encontrado';
  END IF;

  PERFORM public.admin_insert_historial_bloque(
    v_result.fecha,
    v_result.hora,
    v_result.camara_id,
    v_result.id,
    v_result.lugar,
    'apartado',
    p_paciente_id,
    v_user_id,
    null::text,
    false,
    null::integer,
    'particular'::public.modalidad_cobro_turno,
    null::integer,
    null::text,
    null::integer,
    null::uuid,
    null::integer,
    false,
    null::uuid,
    null::timestamptz
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_apartar_slot"("p_slot_id" "uuid", "p_paciente_id" "uuid", "p_es_monoxido" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_append_event"("p_occurred_at" timestamp with time zone DEFAULT "now"(), "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_actor_label" "text" DEFAULT NULL::"text", "p_action_code" "text" DEFAULT NULL::"text", "p_action_family" "text" DEFAULT NULL::"text", "p_entity_type" "text" DEFAULT NULL::"text", "p_entity_id" "text" DEFAULT NULL::"text", "p_agenda_type" "text" DEFAULT NULL::"text", "p_paciente_id" "uuid" DEFAULT NULL::"uuid", "p_paciente_nombre" "text" DEFAULT NULL::"text", "p_medico_id" integer DEFAULT NULL::integer, "p_medico_nombre" "text" DEFAULT NULL::"text", "p_title" "text" DEFAULT NULL::"text", "p_summary" "text" DEFAULT NULL::"text", "p_source_system" "text" DEFAULT NULL::"text", "p_source_record_key" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS bigint
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id bigint;
  v_actor_label text := nullif(trim(coalesce(p_actor_label, '')), '');
  v_paciente_nombre text := nullif(trim(coalesce(p_paciente_nombre, '')), '');
  v_medico_nombre text := nullif(trim(coalesce(p_medico_nombre, '')), '');
begin
  if v_actor_label is null and p_actor_user_id is not null then
    select nullif(trim(coalesce(nombre, '')), '')
    into v_actor_label
    from public.perfiles
    where id = p_actor_user_id;
  end if;

  if v_paciente_nombre is null and p_paciente_id is not null then
    select nullif(trim(coalesce(nombre, '')), '')
    into v_paciente_nombre
    from public.perfiles
    where id = p_paciente_id;
  end if;

  if v_medico_nombre is null and p_medico_id is not null then
    select nullif(trim(coalesce(nombre, '')), '')
    into v_medico_nombre
    from public.medicos
    where id = p_medico_id;
  end if;

  insert into public.admin_event_feed (
    occurred_at,
    actor_user_id,
    actor_label,
    action_code,
    action_family,
    entity_type,
    entity_id,
    agenda_type,
    paciente_id,
    paciente_nombre,
    medico_id,
    medico_nombre,
    title,
    summary,
    source_system,
    source_record_key,
    metadata
  )
  values (
    coalesce(p_occurred_at, now()),
    p_actor_user_id,
    coalesce(v_actor_label, 'Sistema'),
    p_action_code,
    p_action_family,
    p_entity_type,
    p_entity_id,
    nullif(trim(coalesce(p_agenda_type, '')), ''),
    p_paciente_id,
    v_paciente_nombre,
    p_medico_id,
    v_medico_nombre,
    p_title,
    p_summary,
    p_source_system,
    p_source_record_key,
    coalesce(p_metadata, '{}'::jsonb)
  )
  on conflict (source_system, source_record_key) do update
  set occurred_at = excluded.occurred_at,
      actor_user_id = excluded.actor_user_id,
      actor_label = excluded.actor_label,
      action_code = excluded.action_code,
      action_family = excluded.action_family,
      entity_type = excluded.entity_type,
      entity_id = excluded.entity_id,
      agenda_type = excluded.agenda_type,
      paciente_id = excluded.paciente_id,
      paciente_nombre = excluded.paciente_nombre,
      medico_id = excluded.medico_id,
      medico_nombre = excluded.medico_nombre,
      title = excluded.title,
      summary = excluded.summary,
      metadata = excluded.metadata
  returning id into v_id;

  return v_id;
end;
$$;


ALTER FUNCTION "public"."admin_append_event"("p_occurred_at" timestamp with time zone, "p_actor_user_id" "uuid", "p_actor_label" "text", "p_action_code" "text", "p_action_family" "text", "p_entity_type" "text", "p_entity_id" "text", "p_agenda_type" "text", "p_paciente_id" "uuid", "p_paciente_nombre" "text", "p_medico_id" integer, "p_medico_nombre" "text", "p_title" "text", "p_summary" "text", "p_source_system" "text", "p_source_record_key" "text", "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_asignar_bloque_completo"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_paciente_id" "uuid", "p_referido_tercero" boolean DEFAULT false, "p_modalidad_cobro" "public"."modalidad_cobro_turno" DEFAULT 'particular'::"public"."modalidad_cobro_turno", "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_autorizacion" "text" DEFAULT NULL::"text", "p_convenio_corroborado" boolean DEFAULT false, "p_medico_id" integer DEFAULT NULL::integer, "p_es_nuevo_ingreso" boolean DEFAULT false) RETURNS SETOF "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_patient_exists boolean;
  v_conflicto_otros_pacientes boolean;
  v_conflicto_consecutivo boolean;
  v_logged boolean := false;
  v_row public.slots%ROWTYPE;
  v_operativo_obra_social_id integer;
  v_operativo_numero_autorizacion text;
  v_operativo_sin_convenio boolean;
  v_obra_social_validada_por uuid;
  v_obra_social_validada_at timestamptz;
  v_medico_id integer;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM public.perfiles WHERE id = v_user_id AND rol = 'admin') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;
  SELECT EXISTS (SELECT 1 FROM public.perfiles WHERE id = p_paciente_id AND rol = 'paciente')
  INTO v_patient_exists;
  IF NOT v_patient_exists THEN
    RAISE EXCEPTION 'Paciente no valido';
  END IF;

  SELECT obra_social_id, numero_autorizacion, sin_convenio
  INTO v_operativo_obra_social_id, v_operativo_numero_autorizacion, v_operativo_sin_convenio
  FROM public.admin_resolver_operativo_obra_social(
    p_paciente_id, p_modalidad_cobro, p_obra_social_id, p_numero_autorizacion, p_convenio_corroborado
  );

  v_medico_id := public.admin_resolver_medico_operativo(p_medico_id, p_es_nuevo_ingreso, null);
  v_obra_social_validada_por := CASE WHEN v_operativo_sin_convenio THEN v_user_id ELSE null END;
  v_obra_social_validada_at := CASE WHEN v_operativo_sin_convenio THEN now() ELSE null END;

  FOR v_row IN
    UPDATE public.slots
    SET paciente_id = p_paciente_id,
        estado = 'ocupado',
        es_bloque_completo = true,
        es_tanda = true,
        apartado_por = null,
        apartado_ts = null,
        referido_tercero = coalesce(p_referido_tercero, false),
        modalidad_cobro = coalesce(p_modalidad_cobro, 'particular'),
        obra_social_id = v_operativo_obra_social_id,
        numero_autorizacion = v_operativo_numero_autorizacion,
        medico_id = v_medico_id,
        es_nuevo_ingreso = coalesce(p_es_nuevo_ingreso, false),
        obra_social_validada_por = v_obra_social_validada_por,
        obra_social_validada_at = v_obra_social_validada_at
    WHERE fecha = p_fecha AND hora = p_hora AND camara_id = p_camara_id
    RETURNING *
  LOOP
    IF NOT v_logged THEN
      PERFORM public.admin_insert_historial_bloque(
        v_row.fecha, v_row.hora, v_row.camara_id, null, null, 'bloque_asignado', p_paciente_id, v_user_id,
        null, v_row.referido_tercero, v_row.modalidad_cobro, v_row.obra_social_id, v_row.numero_autorizacion,
        v_row.medico_id, v_row.es_nuevo_ingreso, v_row.obra_social_validada_por, v_row.obra_social_validada_at
      );
      v_logged := true;
    END IF;
    RETURN NEXT v_row;
  END LOOP;

  IF NOT v_logged THEN
    RAISE EXCEPTION 'Bloque no encontrado';
  END IF;
END;
$$;


