CREATE OR REPLACE FUNCTION "public"."admin_asignar_bloque_completo"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_paciente_id" "uuid", "p_referido_tercero" boolean DEFAULT false, "p_referente_id" integer DEFAULT NULL::integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno" DEFAULT 'particular'::"public"."modalidad_cobro_turno", "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_autorizacion" "text" DEFAULT NULL::"text", "p_convenio_corroborado" boolean DEFAULT false, "p_medico_id" integer DEFAULT NULL::integer, "p_es_nuevo_ingreso" boolean DEFAULT false) RETURNS SETOF "public"."slots"
