ALTER FUNCTION "public"."admin_asignar_bloque_completo"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_paciente_id" "uuid", "p_referido_tercero" boolean, "p_referente_id" integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer, "p_numero_autorizacion" "text", "p_convenio_corroborado" boolean, "p_medico_id" integer, "p_es_nuevo_ingreso" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_asignar_bloque_completo"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_paciente_id" "uuid", "p_es_tanda" boolean DEFAULT false, "p_tanda_id" "uuid" DEFAULT NULL::"uuid", "p_referido_tercero" boolean DEFAULT false, "p_referente_id" integer DEFAULT NULL::integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno" DEFAULT 'particular'::"public"."modalidad_cobro_turno", "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_autorizacion" "text" DEFAULT NULL::"text", "p_convenio_corroborado" boolean DEFAULT false, "p_medico_id" integer DEFAULT NULL::integer, "p_es_nuevo_ingreso" boolean DEFAULT false) RETURNS SETOF "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_actor_profile_id uuid := public.auth_current_profile_id();
  v_patient_exists boolean;
  v_conflicto_otros_pacientes boolean;
  v_conflicto_consecutivo boolean;
  v_logged boolean := false;
  v_row public.slots%rowtype;
  v_operativo_obra_social_id integer;
  v_operativo_numero_autorizacion text;
  v_operativo_sin_convenio boolean;
  v_obra_social_validada_por uuid;
  v_obra_social_validada_at timestamptz;
  v_medico_id integer;
  v_referente_id integer;
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_any_permission(array['turnos.bloque_completo', 'turnos.asignar', 'turnos.tanda']::text[]) then
    raise exception 'Prohibido';
  end if;

  if v_actor_profile_id is null then
    raise exception 'Perfil no encontrado';
  end if;

  select exists (select 1 from public.perfiles where id = p_paciente_id and rol = 'paciente')
  into v_patient_exists;
  if not v_patient_exists then
    raise exception 'Paciente no valido';
  end if;

  select exists (
    select 1
    from public.slots s
    where s.fecha = p_fecha
      and s.hora = p_hora
      and s.camara_id = p_camara_id
      and s.estado = 'ocupado'
      and s.paciente_id is not null
      and s.paciente_id <> p_paciente_id
  ) into v_conflicto_otros_pacientes;

  if v_conflicto_otros_pacientes then
    raise exception 'No es posible reservar el bloque completo porque ya hay otros pacientes asignados';
  end if;

  select exists (
    select 1
    from public.slots s
    join public.horarios_config hs on hs.hora = s.hora
    where s.fecha = p_fecha
      and s.paciente_id = p_paciente_id
      and s.estado = 'ocupado'
      and s.es_bloque_completo = true
      and s.camara_id = p_camara_id
      and abs(hs.orden - (select orden from public.horarios_config where hora = p_hora)) <= 1
  ) into v_conflicto_consecutivo;

  if v_conflicto_consecutivo then
    raise exception 'No se pueden asignar turnos en bloques seguidos';
  end if;

  select obra_social_id, numero_autorizacion, sin_convenio
  into v_operativo_obra_social_id, v_operativo_numero_autorizacion, v_operativo_sin_convenio
  from public.admin_resolver_operativo_obra_social(
    p_paciente_id, p_modalidad_cobro, p_obra_social_id, p_numero_autorizacion, null,
    null, false, p_convenio_corroborado
  );

  v_medico_id := public.admin_resolver_medico_operativo(p_medico_id, p_es_nuevo_ingreso, null);
  v_referente_id := public.admin_resolver_referente_operativo(p_referido_tercero, p_referente_id, null);
  v_obra_social_validada_por := case when v_operativo_sin_convenio then v_actor_profile_id else null end;
  v_obra_social_validada_at := case when v_operativo_sin_convenio then now() else null end;

  for v_row in
    update public.slots
    set paciente_id = p_paciente_id,
        estado = 'ocupado',
        es_bloque_completo = true,
        es_tanda = coalesce(p_es_tanda, false),
        tanda_id = case when coalesce(p_es_tanda, false) then p_tanda_id else null end,
        apartado_por = null,
        apartado_ts = null,
        referido_tercero = coalesce(p_referido_tercero, false),
        referente_id = v_referente_id,
        modalidad_cobro = coalesce(p_modalidad_cobro, 'particular'),
        obra_social_id = v_operativo_obra_social_id,
        numero_autorizacion = v_operativo_numero_autorizacion,
        medico_id = v_medico_id,
        es_nuevo_ingreso = coalesce(p_es_nuevo_ingreso, false),
        obra_social_validada_por = v_obra_social_validada_por,
        obra_social_validada_at = v_obra_social_validada_at
    where fecha = p_fecha and hora = p_hora and camara_id = p_camara_id
    returning *
  loop
    if not v_logged then
      perform public.admin_insert_historial_bloque(
        v_row.fecha, v_row.hora, v_row.camara_id, null, null, 'bloque_asignado', p_paciente_id, v_actor_profile_id,
        null, v_row.referido_tercero, v_row.referente_id, v_row.modalidad_cobro, v_row.obra_social_id,
        v_row.numero_autorizacion, v_row.medico_id, v_row.es_nuevo_ingreso, v_row.obra_social_validada_por, v_row.obra_social_validada_at
      );
      v_logged := true;
    end if;
    return next v_row;
  end loop;

  if not v_logged then
    raise exception 'Bloque no encontrado';
  end if;
end;
$$;


ALTER FUNCTION "public"."admin_asignar_bloque_completo"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_paciente_id" "uuid", "p_es_tanda" boolean, "p_tanda_id" "uuid", "p_referido_tercero" boolean, "p_referente_id" integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer, "p_numero_autorizacion" "text", "p_convenio_corroborado" boolean, "p_medico_id" integer, "p_es_nuevo_ingreso" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_asignar_bloque_completo"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_paciente_id" "uuid", "p_es_tanda" boolean DEFAULT false, "p_tanda_id" "uuid" DEFAULT NULL::"uuid", "p_referido_tercero" boolean DEFAULT false, "p_referente_id" integer DEFAULT NULL::integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno" DEFAULT 'particular'::"public"."modalidad_cobro_turno", "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_autorizacion" "text" DEFAULT NULL::"text", "p_sesiones_autorizadas" integer DEFAULT NULL::integer, "p_ciclo_obra_social_id" "uuid" DEFAULT NULL::"uuid", "p_iniciar_nuevo_ciclo_obra_social" boolean DEFAULT false, "p_convenio_corroborado" boolean DEFAULT false, "p_medico_id" integer DEFAULT NULL::integer, "p_es_nuevo_ingreso" boolean DEFAULT false, "p_es_monoxido" boolean DEFAULT false, "p_monoxido_orden_medica" boolean DEFAULT false, "p_monoxido_resumen_clinico" boolean DEFAULT false) RETURNS SETOF "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_profile_id uuid := public.auth_current_profile_id();
  v_row public.slots%ROWTYPE;
  v_logged boolean := false;
  v_operativo_obra_social_id integer;
  v_operativo_numero_autorizacion text;
  v_operativo_sesiones_autorizadas integer;
  v_operativo_ciclo_obra_social_id uuid;
  v_operativo_sin_convenio boolean;
  v_obra_social_validada_por uuid;
  v_obra_social_validada_at timestamptz;
  v_medico_id integer;
  v_referente_id integer;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'No autorizado'; END IF;
  IF v_profile_id IS NULL THEN RAISE EXCEPTION 'Perfil no encontrado'; END IF;
  IF NOT public.can_turnos_bloque_completo() THEN RAISE EXCEPTION 'Prohibido'; END IF;
  IF p_paciente_id IS NULL OR NOT EXISTS (SELECT 1 FROM public.perfiles WHERE id = p_paciente_id AND rol = 'paciente') THEN RAISE EXCEPTION 'Paciente no valido'; END IF;
  IF coalesce(p_es_monoxido, false) AND (NOT coalesce(p_monoxido_orden_medica, false) OR NOT coalesce(p_monoxido_resumen_clinico, false)) THEN
    RAISE EXCEPTION 'Monoxido requiere orden medica y resumen clinico';
  END IF;

  SELECT obra_social_id, numero_autorizacion, sesiones_autorizadas, ciclo_obra_social_id, sin_convenio
  INTO v_operativo_obra_social_id, v_operativo_numero_autorizacion, v_operativo_sesiones_autorizadas, v_operativo_ciclo_obra_social_id, v_operativo_sin_convenio
  FROM public.admin_resolver_operativo_obra_social(
    p_paciente_id, p_modalidad_cobro, p_obra_social_id, p_numero_autorizacion, p_sesiones_autorizadas,
    p_ciclo_obra_social_id, p_iniciar_nuevo_ciclo_obra_social, p_convenio_corroborado
  );

  PERFORM public.admin_validar_tope_obra_social_serie(
    p_paciente_id, p_modalidad_cobro, v_operativo_numero_autorizacion, v_operativo_sesiones_autorizadas, v_operativo_ciclo_obra_social_id
  );

  v_medico_id := public.admin_resolver_medico_operativo(p_medico_id, p_es_nuevo_ingreso, null);
  v_referente_id := public.admin_resolver_referente_operativo(p_referido_tercero, p_referente_id, null);
  v_obra_social_validada_por := CASE WHEN v_operativo_sin_convenio THEN v_profile_id ELSE null END;
  v_obra_social_validada_at := CASE WHEN v_operativo_sin_convenio THEN now() ELSE null END;

  FOR v_row IN
    UPDATE public.slots
    SET paciente_id = p_paciente_id,
        estado = 'ocupado',
        es_bloque_completo = true,
        es_tanda = coalesce(p_es_tanda, false),
        tanda_id = CASE WHEN coalesce(p_es_tanda, false) THEN p_tanda_id ELSE null END,
        apartado_por = null,
        apartado_ts = null,
        referido_tercero = coalesce(p_referido_tercero, false),
        referente_id = v_referente_id,
        modalidad_cobro = coalesce(p_modalidad_cobro, 'particular'),
        obra_social_id = v_operativo_obra_social_id,
        numero_autorizacion = v_operativo_numero_autorizacion,
        sesiones_autorizadas = v_operativo_sesiones_autorizadas,
        ciclo_obra_social_id = v_operativo_ciclo_obra_social_id,
        medico_id = v_medico_id,
        es_nuevo_ingreso = coalesce(p_es_nuevo_ingreso, false),
        obra_social_validada_por = v_obra_social_validada_por,
        obra_social_validada_at = v_obra_social_validada_at,
        es_monoxido = coalesce(p_es_monoxido, false),
        monoxido_orden_medica = CASE WHEN coalesce(p_es_monoxido, false) THEN coalesce(p_monoxido_orden_medica, false) ELSE false END,
        monoxido_resumen_clinico = CASE WHEN coalesce(p_es_monoxido, false) THEN coalesce(p_monoxido_resumen_clinico, false) ELSE false END
    WHERE fecha = p_fecha AND hora = p_hora AND camara_id = p_camara_id
    RETURNING *
  LOOP
    IF NOT v_logged THEN
      PERFORM public.admin_insert_historial_bloque(
        v_row.fecha, v_row.hora, v_row.camara_id, null, null, 'bloque_asignado', p_paciente_id, v_user_id,
        null, v_row.referido_tercero, v_row.referente_id, v_row.modalidad_cobro, v_row.obra_social_id,
        v_row.numero_autorizacion, v_row.sesiones_autorizadas, v_row.ciclo_obra_social_id, v_row.medico_id,
        v_row.es_nuevo_ingreso, v_row.obra_social_validada_por, v_row.obra_social_validada_at, v_row.tanda_id
      );
      v_logged := true;
    END IF;
    RETURN NEXT v_row;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."admin_asignar_bloque_completo"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_paciente_id" "uuid", "p_es_tanda" boolean, "p_tanda_id" "uuid", "p_referido_tercero" boolean, "p_referente_id" integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer, "p_numero_autorizacion" "text", "p_sesiones_autorizadas" integer, "p_ciclo_obra_social_id" "uuid", "p_iniciar_nuevo_ciclo_obra_social" boolean, "p_convenio_corroborado" boolean, "p_medico_id" integer, "p_es_nuevo_ingreso" boolean, "p_es_monoxido" boolean, "p_monoxido_orden_medica" boolean, "p_monoxido_resumen_clinico" boolean) OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."consultas_slots" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "fecha" "date" NOT NULL,
    "hora" "text" NOT NULL,
    "estado" "text" DEFAULT 'libre'::"text" NOT NULL,
    "paciente_id" "uuid",
    "medico_id" integer,
    "motivo_cancelacion" "text",
    "observaciones_admin" "text",
    "confirmado_at" timestamp with time zone,
    "confirmado_por" "uuid",
    "cerrado_at" timestamp with time zone,
    "cerrado_por" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "consultas_slots_estado_check" CHECK (("estado" = ANY (ARRAY['libre'::"text", 'confirmada'::"text", 'cancelada'::"text", 'completada'::"text", 'ausente'::"text"])))
);


ALTER TABLE "public"."consultas_slots" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_asignar_consulta"("p_slot_id" "uuid", "p_paciente_id" "uuid", "p_medico_id" integer, "p_observaciones_admin" "text" DEFAULT NULL::"text") RETURNS "public"."consultas_slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor_perfil_id uuid := public.auth_current_profile_id();
  v_slot public.consultas_slots%rowtype;
  v_result public.consultas_slots%rowtype;
begin
  if v_actor_perfil_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.can_manage_consultas() then
    raise exception 'Prohibido';
  end if;

  if p_slot_id is null or p_paciente_id is null or p_medico_id is null then
    raise exception 'Datos incompletos';
  end if;

  select *
  into v_slot
  from public.consultas_slots
  where id = p_slot_id
  for update;

  if v_slot.id is null then
    raise exception 'Consulta no encontrada';
  end if;
  if v_slot.estado not in ('libre', 'cancelada') then
    raise exception 'La consulta no esta disponible';
  end if;

  perform public.admin_validar_conflicto_consulta(p_paciente_id, v_slot.fecha, v_slot.hora, v_slot.id);
  perform public.admin_resolver_medico_operativo(p_medico_id, false, null);
  perform public.ensure_historia_clinica_for_patient(p_paciente_id);

  update public.consultas_slots
  set estado = 'confirmada',
      paciente_id = p_paciente_id,
      medico_id = p_medico_id,
      motivo_cancelacion = null,
      observaciones_admin = nullif(trim(coalesce(p_observaciones_admin, '')), ''),
      confirmado_at = now(),
      confirmado_por = v_actor_perfil_id,
      cerrado_at = null,
      cerrado_por = null
  where id = p_slot_id
  returning * into v_result;

  perform public.admin_insert_historial_consulta(
    v_result.id,
    v_result.fecha,
    v_result.hora,
    'confirmada',
    v_result.paciente_id,
    v_result.medico_id,
    v_actor_perfil_id,
    null,
    jsonb_build_object('estado', v_result.estado)
  );

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_asignar_consulta"("p_slot_id" "uuid", "p_paciente_id" "uuid", "p_medico_id" integer, "p_observaciones_admin" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_asignar_slot"("p_slot_id" "uuid", "p_paciente_id" "uuid", "p_es_tanda" boolean DEFAULT false, "p_tanda_id" "uuid" DEFAULT NULL::"uuid", "p_accion" "text" DEFAULT 'asignado'::"text", "p_referido_tercero" boolean DEFAULT false, "p_referente_id" integer DEFAULT NULL::integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno" DEFAULT 'particular'::"public"."modalidad_cobro_turno", "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_autorizacion" "text" DEFAULT NULL::"text", "p_sesiones_autorizadas" integer DEFAULT NULL::integer, "p_ciclo_obra_social_id" "uuid" DEFAULT NULL::"uuid", "p_iniciar_nuevo_ciclo_obra_social" boolean DEFAULT false, "p_convenio_corroborado" boolean DEFAULT false, "p_medico_id" integer DEFAULT NULL::integer, "p_es_nuevo_ingreso" boolean DEFAULT false, "p_es_monoxido" boolean DEFAULT false, "p_monoxido_orden_medica" boolean DEFAULT false, "p_monoxido_resumen_clinico" boolean DEFAULT false) RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_profile_id uuid := public.auth_current_profile_id();
  v_result public.slots%ROWTYPE;
  v_accion text := nullif(trim(coalesce(p_accion, '')), '');
  v_operativo_obra_social_id integer;
  v_operativo_numero_autorizacion text;
  v_operativo_sesiones_autorizadas integer;
  v_operativo_ciclo_obra_social_id uuid;
  v_operativo_sin_convenio boolean;
  v_obra_social_validada_por uuid;
  v_obra_social_validada_at timestamptz;
  v_medico_id integer;
  v_referente_id integer;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'No autorizado'; END IF;
  IF v_profile_id IS NULL THEN RAISE EXCEPTION 'Perfil no encontrado'; END IF;
  IF NOT public.can_turnos_asignar() THEN RAISE EXCEPTION 'Prohibido'; END IF;
  IF p_paciente_id IS NULL OR NOT EXISTS (SELECT 1 FROM public.perfiles WHERE id = p_paciente_id AND rol = 'paciente') THEN RAISE EXCEPTION 'Paciente no valido'; END IF;
  IF v_accion IS NULL THEN RAISE EXCEPTION 'Accion invalida'; END IF;
  IF coalesce(p_es_monoxido, false) AND (NOT coalesce(p_monoxido_orden_medica, false) OR NOT coalesce(p_monoxido_resumen_clinico, false)) THEN
    RAISE EXCEPTION 'Monoxido requiere orden medica y resumen clinico';
  END IF;

  SELECT obra_social_id, numero_autorizacion, sesiones_autorizadas, ciclo_obra_social_id, sin_convenio
  INTO v_operativo_obra_social_id, v_operativo_numero_autorizacion, v_operativo_sesiones_autorizadas, v_operativo_ciclo_obra_social_id, v_operativo_sin_convenio
  FROM public.admin_resolver_operativo_obra_social(
    p_paciente_id, p_modalidad_cobro, p_obra_social_id, p_numero_autorizacion, p_sesiones_autorizadas,
    p_ciclo_obra_social_id, p_iniciar_nuevo_ciclo_obra_social, p_convenio_corroborado
  );

  PERFORM public.admin_validar_tope_obra_social_serie(
    p_paciente_id, p_modalidad_cobro, v_operativo_numero_autorizacion, v_operativo_sesiones_autorizadas, v_operativo_ciclo_obra_social_id
  );

  v_medico_id := public.admin_resolver_medico_operativo(p_medico_id, p_es_nuevo_ingreso, null);
  v_referente_id := public.admin_resolver_referente_operativo(p_referido_tercero, p_referente_id, null);
  v_obra_social_validada_por := CASE WHEN v_operativo_sin_convenio THEN v_profile_id ELSE null END;
  v_obra_social_validada_at := CASE WHEN v_operativo_sin_convenio THEN now() ELSE null END;

  UPDATE public.slots
  SET paciente_id = p_paciente_id,
      estado = 'ocupado',
      es_tanda = coalesce(p_es_tanda, false),
      tanda_id = CASE WHEN coalesce(p_es_tanda, false) THEN p_tanda_id ELSE null END,
      es_bloque_completo = false,
      apartado_por = null,
      apartado_ts = null,
      referido_tercero = coalesce(p_referido_tercero, false),
      referente_id = v_referente_id,
      modalidad_cobro = coalesce(p_modalidad_cobro, 'particular'),
      obra_social_id = v_operativo_obra_social_id,
      numero_autorizacion = v_operativo_numero_autorizacion,
      sesiones_autorizadas = v_operativo_sesiones_autorizadas,
      ciclo_obra_social_id = v_operativo_ciclo_obra_social_id,
      medico_id = v_medico_id,
      es_nuevo_ingreso = coalesce(p_es_nuevo_ingreso, false),
      obra_social_validada_por = v_obra_social_validada_por,
      obra_social_validada_at = v_obra_social_validada_at,
      es_monoxido = coalesce(p_es_monoxido, false),
      monoxido_orden_medica = CASE WHEN coalesce(p_es_monoxido, false) THEN coalesce(p_monoxido_orden_medica, false) ELSE false END,
      monoxido_resumen_clinico = CASE WHEN coalesce(p_es_monoxido, false) THEN coalesce(p_monoxido_resumen_clinico, false) ELSE false END
  WHERE id = p_slot_id
  RETURNING * INTO v_result;
  IF v_result.id IS NULL THEN RAISE EXCEPTION 'Slot no encontrado'; END IF;
  PERFORM public.admin_insert_historial_bloque(
    v_result.fecha, v_result.hora, v_result.camara_id, v_result.id, v_result.lugar, v_accion, p_paciente_id, v_user_id,
    null, v_result.referido_tercero, v_result.referente_id, v_result.modalidad_cobro, v_result.obra_social_id,
    v_result.numero_autorizacion, v_result.sesiones_autorizadas, v_result.ciclo_obra_social_id, v_result.medico_id,
    v_result.es_nuevo_ingreso, v_result.obra_social_validada_por, v_result.obra_social_validada_at, v_result.tanda_id
  );
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_asignar_slot"("p_slot_id" "uuid", "p_paciente_id" "uuid", "p_es_tanda" boolean, "p_tanda_id" "uuid", "p_accion" "text", "p_referido_tercero" boolean, "p_referente_id" integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer, "p_numero_autorizacion" "text", "p_sesiones_autorizadas" integer, "p_ciclo_obra_social_id" "uuid", "p_iniciar_nuevo_ciclo_obra_social" boolean, "p_convenio_corroborado" boolean, "p_medico_id" integer, "p_es_nuevo_ingreso" boolean, "p_es_monoxido" boolean, "p_monoxido_orden_medica" boolean, "p_monoxido_resumen_clinico" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_assign_user_roles"("p_user_id" "uuid", "p_role_slugs" "text"[], "p_primary_role_slug" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor_id uuid := public.auth_current_profile_id();
  v_role_id bigint;
  v_primary_role_id bigint;
  v_has_staff boolean := false;
  v_has_paciente boolean := false;
begin
  if not public.auth_has_permission('rbac.manage') then
    raise exception 'Prohibido';
  end if;

  if p_user_id is null then
    raise exception 'Usuario requerido';
  end if;

  if not exists (select 1 from public.perfiles where id = p_user_id) then
    raise exception 'Usuario no encontrado';
  end if;

  if coalesce(array_length(p_role_slugs, 1), 0) = 0 then
    raise exception 'Debe seleccionar al menos un rol';
  end if;

  delete from public.rbac_user_roles where user_id = p_user_id;

  for v_role_id in
    select id
    from public.rbac_roles
    where slug = any(
      select lower(trim(x))
      from unnest(p_role_slugs) as x
    )
      and activo = true
  loop
    insert into public.rbac_user_roles(user_id, role_id, is_primary, assigned_by)
    values (p_user_id, v_role_id, false, v_actor_id)
    on conflict (user_id, role_id) do nothing;
  end loop;

  select exists (
    select 1
    from public.rbac_user_roles ur
    join public.rbac_roles r on r.id = ur.role_id
    where ur.user_id = p_user_id
      and r.is_staff = true
  )
  into v_has_staff;

  select exists (
    select 1
    from public.rbac_user_roles ur
    join public.rbac_roles r on r.id = ur.role_id
    where ur.user_id = p_user_id
      and r.slug = 'paciente'
  )
  into v_has_paciente;

  if v_has_staff and v_has_paciente then
    raise exception 'No se permite mezclar roles staff y paciente en la misma cuenta';
  end if;

  if nullif(trim(coalesce(p_primary_role_slug, '')), '') is not null then
    select r.id
    into v_primary_role_id
    from public.rbac_roles r
    join public.rbac_user_roles ur on ur.role_id = r.id and ur.user_id = p_user_id
    where r.slug = lower(trim(p_primary_role_slug))
    limit 1;
  else
    select ur.role_id
    into v_primary_role_id
    from public.rbac_user_roles ur
    join public.rbac_roles r on r.id = ur.role_id
    where ur.user_id = p_user_id
    order by case when r.slug = 'admin' then 0 else 1 end, r.slug
    limit 1;
  end if;

  update public.rbac_user_roles
  set is_primary = (role_id = v_primary_role_id)
  where user_id = p_user_id;

  update public.perfiles
  set rol = case when v_has_paciente then 'paciente'::public.rol_usuario else 'admin'::public.rol_usuario end
  where id = p_user_id;

  perform public.rbac_rebuild_effective_permissions(p_user_id);
end;
$$;


ALTER FUNCTION "public"."admin_assign_user_roles"("p_user_id" "uuid", "p_role_slugs" "text"[], "p_primary_role_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_backfill_event_feed"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if not public.auth_has_permission('rbac.manage') then
    raise exception 'Prohibido';
  end if;

  insert into public.admin_event_feed (
    occurred_at, actor_user_id, actor_label, action_code, action_family,
    entity_type, entity_id, agenda_type, paciente_id, paciente_nombre,
    medico_id, medico_nombre, title, summary, source_system, source_record_key, metadata
  )
  select
    hb.created_at,
    hb.realizado_por,
    coalesce(actor.nombre, 'Sistema'),
    case
      when hb.accion in ('asignado', 'bloque_asignado') then 'turno.asignado'
      when hb.accion = 'reasignado' then 'turno.reasignado'
      when hb.accion in ('cancelado', 'bloque_cancelado', 'cancelado_por_whatsapp') then 'turno.cancelado'
      when hb.accion = 'apartado' then 'turno.apartado'
      when hb.accion = 'confirmado' then 'turno.confirmado'
      when hb.accion = 'liberado' then 'turno.liberado'
      else 'turno.actualizado'
    end,
    case
      when hb.accion in ('cancelado', 'bloque_cancelado', 'cancelado_por_whatsapp') then 'cancelaciones'
      else 'turnos'
    end,
    case when hb.tanda_id is not null then 'tanda' else 'slot' end,
    coalesce(hb.tanda_id::text, hb.slot_id::text, hb.id::text),
    'camaras',
    hb.paciente_id,
    paciente.nombre,
    hb.medico_id,
    medico.nombre,
    case
      when hb.accion = 'bloque_asignado' then 'Bloque asignado'
      when hb.accion in ('asignado') then 'Turno asignado'
      when hb.accion = 'reasignado' then 'Turno reasignado'
      when hb.accion in ('cancelado', 'bloque_cancelado', 'cancelado_por_whatsapp') then 'Turno cancelado'
      when hb.accion = 'apartado' then 'Turno apartado'
      when hb.accion = 'confirmado' then 'Turno confirmado'
      when hb.accion = 'liberado' then 'Turno liberado'
      else 'Turno actualizado'
    end,
    trim(both ' ' from concat(
      coalesce(paciente.nombre, 'Paciente sin nombre'),
      ' Â· ',
      to_char(hb.fecha, 'DD/MM/YYYY'),
      ' ',
      coalesce(hb.hora, ''),
      ' hs',
      case when camara.nombre is not null then ' Â· ' || camara.nombre else '' end,
      case when hb.motivo is not null then ' Â· ' || hb.motivo else '' end
    )),
    'historial_bloques',
    hb.id::text,
    jsonb_strip_nulls(jsonb_build_object(
      'accion_original', hb.accion,
      'fecha', hb.fecha,
      'hora', hb.hora,
      'camara_id', hb.camara_id,
      'camara_nombre', camara.nombre,
      'slot_id', hb.slot_id,
      'lugar', hb.lugar,
      'motivo', hb.motivo,
      'medico_nombre', medico.nombre
    ))
  from public.historial_bloques hb
  left join public.perfiles actor on actor.id = hb.realizado_por
  left join public.perfiles paciente on paciente.id = hb.paciente_id
  left join public.medicos medico on medico.id = hb.medico_id
  left join public.camaras camara on camara.id = hb.camara_id
  on conflict (source_system, source_record_key) do nothing;

  insert into public.admin_event_feed (
    occurred_at, actor_user_id, actor_label, action_code, action_family,
    entity_type, entity_id, agenda_type, paciente_id, paciente_nombre,
    medico_id, medico_nombre, title, summary, source_system, source_record_key, metadata
  )
  select
    c.created_at,
    c.id,
    'Sistema',
    'config.horario.actualizado',
    'configuracion',
    'horario',
    c.id::text,
    null,
    null,
    null,
    null,
    null,
    'Horario actualizado',
    c.hora,
    'horarios_config',
    c.id::text,
    jsonb_build_object('hora', c.hora, 'activo', c.activo, 'orden', c.orden)
  from public.horarios_config c
  on conflict (source_system, source_record_key) do nothing;
end;
$$;


ALTER FUNCTION "public"."admin_backfill_event_feed"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_build_cierre_diario_preview_rows"("p_fecha" "date") RETURNS TABLE("slot_id" "uuid", "turno_fuera_horario_id" "uuid", "slot_ids" "uuid"[], "paciente_id" "uuid", "fecha" "date", "hora" "text", "camara_id" integer, "paciente_numero_dia" integer, "nombre_paciente" "text", "sesion_numero" integer, "sesion_numero_historico" integer, "modalidad_cobro" "public"."modalidad_cobro_turno", "obra_social_id" integer, "obra_social_nombre" "text", "obra_social_abreviatura" "text", "numero_autorizacion" "text", "sesiones_autorizadas" integer, "ciclo_obra_social_id" "uuid", "es_nuevo_ingreso" boolean, "medico_id" integer, "medico_nombre" "text", "es_monoxido" boolean, "operador_camara_id" "uuid", "operador_camara_nombre" "text", "es_oxibarica" boolean)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with slot_grouped as (
    select
      (array_agg(s.id order by s.lugar, s.id))[1] as slot_id,
      null::uuid as turno_fuera_horario_id,
      array_agg(s.id order by s.lugar) as slot_ids,
      s.paciente_id,
      s.fecha,
      s.hora,
      s.camara_id,
      min(s.lugar) as lugar_orden,
      max(p.nombre) as nombre_paciente,
      coalesce(bool_or(coalesce(s.referido_tercero, false)), false) as referido_tercero,
      max(r.tipo) as referente_tipo,
      max(r.nombre) as referente_nombre,
      max(coalesce(s.modalidad_cobro, 'particular'::public.modalidad_cobro_turno)) as modalidad_cobro,
      max(s.obra_social_id) as obra_social_id,
      max(os.nombre) as obra_social_nombre,
      max(nullif(trim(coalesce(os.abreviatura, '')), '')) as obra_social_abreviatura,
      max(nullif(trim(coalesce(s.numero_autorizacion, '')), '')) as numero_autorizacion,
      max(s.sesiones_autorizadas) as sesiones_autorizadas,
      (array_agg(s.ciclo_obra_social_id order by s.lugar, s.id) filter (where s.ciclo_obra_social_id is not null))[1] as ciclo_obra_social_id,
      coalesce(bool_or(coalesce(s.es_nuevo_ingreso, false)), false) as es_nuevo_ingreso,
      coalesce(bool_or(coalesce(s.es_monoxido, false)), false) as es_monoxido,
      max(s.medico_id) as medico_id,
      max(m.nombre) as medico_nombre,
      null::uuid as operador_camara_id,
      null::text as operador_camara_nombre
    from public.slots s
    join public.perfiles p on p.id = s.paciente_id
    left join public.obras_sociales os on os.id = s.obra_social_id
    left join public.medicos m on m.id = s.medico_id
    left join public.referentes r on r.id = s.referente_id
    where s.fecha = p_fecha
      and s.estado = 'ocupado'
      and s.paciente_id is not null
    group by s.paciente_id, s.fecha, s.hora, s.camara_id
  ),
  extra_rows as (
    select
      null::uuid as slot_id,
      t.id as turno_fuera_horario_id,
      array[]::uuid[] as slot_ids,
      t.paciente_id,
      t.fecha,
      t.hora,
      null::integer as camara_id,
      999999 as lugar_orden,
      p.nombre as nombre_paciente,
      false as referido_tercero,
      null::text as referente_tipo,
      null::text as referente_nombre,
      'particular'::public.modalidad_cobro_turno as modalidad_cobro,
      null::integer as obra_social_id,
      null::text as obra_social_nombre,
      null::text as obra_social_abreviatura,
      null::text as numero_autorizacion,
      null::integer as sesiones_autorizadas,
      null::uuid as ciclo_obra_social_id,
      false as es_nuevo_ingreso,
      coalesce(t.es_monoxido, false) as es_monoxido,
      case when coalesce(t.es_monoxido, false) then t.monoxido_medico_id else null end as medico_id,
      case when coalesce(t.es_monoxido, false) then mm.nombre else null end as medico_nombre,
      t.operador_camara_id,
      op.nombre as operador_camara_nombre
    from public.turnos_fuera_horario t
    join public.perfiles p on p.id = t.paciente_id
    join public.perfiles op on op.id = t.operador_camara_id
    left join public.medicos mm on mm.id = t.monoxido_medico_id
    where t.fecha = p_fecha
  ),
  raw_rows as (
    select * from slot_grouped
    union all
    select * from extra_rows
  ),
  patient_firsts as (
    select distinct on (paciente_id)
      paciente_id,
      hora as first_hora,
      camara_id as first_camara_id,
      lugar_orden as first_lugar_orden,
      lower(nombre_paciente) as first_nombre
    from raw_rows
    order by paciente_id, hora, camara_id nulls last, lugar_orden, lower(nombre_paciente), slot_id, turno_fuera_horario_id
  ),
  patient_numbers as (
    select
      paciente_id,
      dense_rank() over (
        order by first_hora, first_camara_id nulls last, first_lugar_orden, first_nombre, paciente_id
      ) as paciente_numero_dia
    from patient_firsts
  ),
  sequenced_rows as (
    select
      r.*,
      pn.paciente_numero_dia,
      row_number() over (
        partition by r.paciente_id, r.modalidad_cobro
        order by r.hora, r.camara_id nulls last, r.lugar_orden, lower(r.nombre_paciente), r.slot_id, r.turno_fuera_horario_id
      ) as misma_modalidad_orden_dia
    from raw_rows r
    join patient_numbers pn on pn.paciente_id = r.paciente_id
  ),
  historical_rows as (
    select
      s.*,
      (
        select count(*)
        from public.sesiones prev
        where prev.paciente_id = s.paciente_id
          and coalesce(prev.modalidad_cobro, 'particular'::public.modalidad_cobro_turno) = s.modalidad_cobro
          and (
            prev.fecha < s.fecha
            or (
              prev.fecha = s.fecha
              and (
                prev.hora < s.hora
                or (
                  prev.hora = s.hora
                  and coalesce(prev.camara_id, -1) < coalesce(s.camara_id, 2147483647)
                )
              )
            )
          )
      ) as sesiones_previas
    from sequenced_rows s
  )
  select
    c.slot_id,
    c.turno_fuera_horario_id,
    c.slot_ids,
    c.paciente_id,
    c.fecha,
    c.hora,
    c.camara_id,
    c.paciente_numero_dia,
    c.nombre_paciente,
    (c.sesiones_previas + c.misma_modalidad_orden_dia)::integer as sesion_numero,
    (c.sesiones_previas + c.misma_modalidad_orden_dia)::integer as sesion_numero_historico,
    c.modalidad_cobro,
    case when c.modalidad_cobro = 'obra_social' then c.obra_social_id else null end as obra_social_id,
    case when c.modalidad_cobro = 'obra_social' then c.obra_social_nombre else null end as obra_social_nombre,
    case when c.modalidad_cobro = 'obra_social' then c.obra_social_abreviatura else null end as obra_social_abreviatura,
    case when c.modalidad_cobro = 'obra_social' then c.numero_autorizacion else null end as numero_autorizacion,
    case when c.modalidad_cobro = 'obra_social' then c.sesiones_autorizadas else null end as sesiones_autorizadas,
    case when c.modalidad_cobro = 'obra_social' then c.ciclo_obra_social_id else null end as ciclo_obra_social_id,
    c.es_nuevo_ingreso,
    c.medico_id,
    c.medico_nombre,
    c.es_monoxido,
    c.operador_camara_id,
    c.operador_camara_nombre,
    (
      c.referido_tercero
      and coalesce(c.referente_tipo, '') = 'agencia'
      and coalesce(lower(trim(c.referente_nombre)), 'oxibarica') = 'oxibarica'
    ) as es_oxibarica
  from historical_rows c
  order by c.hora, c.camara_id nulls last, c.lugar_orden, lower(c.nombre_paciente), c.slot_id, c.turno_fuera_horario_id;
$$;


ALTER FUNCTION "public"."admin_build_cierre_diario_preview_rows"("p_fecha" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_cancelar_bloque_completo"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_paciente_id" "uuid") RETURNS SETOF "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_patient_exists boolean;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.perfiles WHERE id = v_user_id AND rol = 'admin'
  ) THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.perfiles WHERE id = p_paciente_id AND rol = 'paciente'
  )
  INTO v_patient_exists;

  IF NOT v_patient_exists THEN
    RAISE EXCEPTION 'Paciente no valido';
  END IF;

  RETURN QUERY
  UPDATE public.slots
  SET paciente_id = null,
      estado = 'cancelado',
      es_tanda = false,
      es_bloque_completo = false
  WHERE fecha = p_fecha
    AND hora = p_hora
    AND camara_id = p_camara_id
    AND paciente_id = p_paciente_id
    AND es_bloque_completo = true
  RETURNING *;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Bloque no encontrado';
  END IF;
END;
$$;


ALTER FUNCTION "public"."admin_cancelar_bloque_completo"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_paciente_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_cancelar_bloque_completo"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_paciente_id" "uuid", "p_motivo" "text" DEFAULT NULL::"text") RETURNS SETOF "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_actor_profile_id uuid := public.auth_current_profile_id();
  v_patient_exists boolean;
  v_logged boolean := false;
  v_row public.slots%rowtype;
  v_cancelled_slot_ids uuid[] := ARRAY[]::uuid[];
  v_referido_tercero boolean := false;
  v_modalidad_cobro public.modalidad_cobro_turno := 'particular';
  v_obra_social_id integer;
  v_numero_autorizacion text;
  v_medico_id integer;
  v_es_nuevo_ingreso boolean := false;
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.can_turnos_bloque_completo() then
    raise exception 'Prohibido';
  end if;

  if v_actor_profile_id is null then
    raise exception 'Perfil no encontrado';
  end if;

  select exists (select 1 from public.perfiles where id = p_paciente_id and rol = 'paciente')
  into v_patient_exists;
  if not v_patient_exists then
    raise exception 'Paciente no valido';
  end if;

  select coalesce(referido_tercero, false), coalesce(modalidad_cobro, 'particular'), obra_social_id, numero_autorizacion, medico_id, coalesce(es_nuevo_ingreso, false)
  into v_referido_tercero, v_modalidad_cobro, v_obra_social_id, v_numero_autorizacion, v_medico_id, v_es_nuevo_ingreso
  from public.slots
  where fecha = p_fecha and hora = p_hora and camara_id = p_camara_id and paciente_id = p_paciente_id and es_bloque_completo = true
  limit 1;

  for v_row in
    update public.slots
    set paciente_id = null,
        estado = 'cancelado',
        es_tanda = false,
        es_bloque_completo = false,
        referido_tercero = false,
        modalidad_cobro = 'particular',
        obra_social_id = null,
        numero_autorizacion = null,
        medico_id = null,
        es_nuevo_ingreso = false
    where fecha = p_fecha and hora = p_hora and camara_id = p_camara_id and paciente_id = p_paciente_id and es_bloque_completo = true
    returning *
  loop
    if not v_logged then
      perform public.admin_insert_historial_bloque(
        v_row.fecha, v_row.hora, v_row.camara_id, null, null, 'bloque_cancelado', p_paciente_id, v_actor_profile_id,
        p_motivo, v_referido_tercero, v_modalidad_cobro, v_obra_social_id, v_numero_autorizacion, v_medico_id, v_es_nuevo_ingreso
      );
      v_logged := true;
    end if;
    v_cancelled_slot_ids := array_append(v_cancelled_slot_ids, v_row.id);
    return next v_row;
  end loop;

  if not v_logged then
    raise exception 'Bloque no encontrado';
  end if;

  if coalesce(array_length(v_cancelled_slot_ids, 1), 0) = 1 then
    perform public.whatsapp_enqueue_cancelacion_turno(
      p_paciente_id,
      v_cancelled_slot_ids[1],
      p_fecha,
      p_hora,
      'admin_cancelacion_bloque'
    );
  elsif coalesce(array_length(v_cancelled_slot_ids, 1), 0) > 1 then
    perform public.whatsapp_enqueue_cancelacion_multiple(
      p_paciente_id,
      v_cancelled_slot_ids,
      format('%s:%s:%s:%s', p_fecha, p_hora, p_camara_id, p_paciente_id),
      'admin_cancelacion_bloque'
    );
  end if;
end;
$$;


ALTER FUNCTION "public"."admin_cancelar_bloque_completo"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_paciente_id" "uuid", "p_motivo" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_cancelar_consulta"("p_slot_id" "uuid", "p_motivo" "text" DEFAULT NULL::"text") RETURNS "public"."consultas_slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor_perfil_id uuid := public.auth_current_profile_id();
  v_slot public.consultas_slots%rowtype;
  v_result public.consultas_slots%rowtype;
  v_motivo text := nullif(trim(coalesce(p_motivo, '')), '');
begin
  if v_actor_perfil_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.can_manage_consultas() then
    raise exception 'Prohibido';
  end if;

  select *
  into v_slot
  from public.consultas_slots
  where id = p_slot_id
  for update;

  if v_slot.id is null then
    raise exception 'Consulta no encontrada';
  end if;
  if v_slot.estado = 'libre' then
    raise exception 'La consulta ya esta libre';
  end if;

  update public.consultas_slots
  set estado = 'cancelada',
      motivo_cancelacion = v_motivo,
      paciente_id = null,
      medico_id = null,
      observaciones_admin = null
  where id = p_slot_id
  returning * into v_result;

  perform public.admin_insert_historial_consulta(
    v_slot.id,
    v_slot.fecha,
    v_slot.hora,
    'cancelada',
    v_slot.paciente_id,
    v_slot.medico_id,
    v_actor_perfil_id,
    v_motivo,
    jsonb_build_object('estado_previo', v_slot.estado)
  );

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_cancelar_consulta"("p_slot_id" "uuid", "p_motivo" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_cancelar_slot"("p_slot_id" "uuid", "p_motivo" "text" DEFAULT NULL::"text") RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_actor_profile_id uuid := public.auth_current_profile_id();
  v_result public.slots%rowtype;
  v_previous public.slots%rowtype;
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.can_turnos_cancelar() then
    raise exception 'Prohibido';
  end if;

  if v_actor_profile_id is null then
    raise exception 'Perfil no encontrado';
  end if;

  select * into v_previous from public.slots where id = p_slot_id;

  update public.slots
  set paciente_id = null,
      estado = 'cancelado',
      es_tanda = false,
      es_bloque_completo = false,
      apartado_por = null,
      apartado_ts = null,
      referido_tercero = false,
      modalidad_cobro = 'particular',
      obra_social_id = null,
      numero_autorizacion = null,
      medico_id = null,
      es_nuevo_ingreso = false,
      obra_social_validada_por = null,
      obra_social_validada_at = null
  where id = p_slot_id
  returning * into v_result;

  if v_result.id is null then
    raise exception 'Slot no encontrado';
  end if;

  perform public.admin_insert_historial_bloque(
    v_result.fecha, v_result.hora, v_result.camara_id, v_result.id, v_result.lugar, 'cancelado', v_previous.paciente_id, v_actor_profile_id,
    p_motivo, coalesce(v_previous.referido_tercero, false), coalesce(v_previous.modalidad_cobro, 'particular'),
    v_previous.obra_social_id, v_previous.numero_autorizacion, v_previous.medico_id, v_previous.es_nuevo_ingreso,
    v_previous.obra_social_validada_por, v_previous.obra_social_validada_at
  );

  perform public.whatsapp_enqueue_cancelacion_turno(
    v_previous.paciente_id,
    v_result.id,
    v_result.fecha,
    v_result.hora,
    'admin_cancelacion'
  );

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_cancelar_slot"("p_slot_id" "uuid", "p_motivo" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_cancelar_tanda"("p_tanda_id" "uuid", "p_motivo" "text" DEFAULT NULL::"text") RETURNS SETOF "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_logged boolean := false;
  v_row public.slots%ROWTYPE;
  v_cancelled_slot_ids uuid[] := ARRAY[]::uuid[];
  v_patient_id uuid;
  v_referido_tercero boolean := false;
  v_referente_id integer;
  v_modalidad_cobro public.modalidad_cobro_turno := 'particular';
  v_obra_social_id integer;
  v_numero_autorizacion text;
  v_sesiones_autorizadas integer;
  v_ciclo_obra_social_id uuid;
  v_medico_id integer;
  v_es_nuevo_ingreso boolean := false;
  v_obra_social_validada_por uuid;
  v_obra_social_validada_at timestamptz;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT (
    public.is_admin_authenticated()
    OR public.can_turnos_cancelar()
    OR public.can_turnos_reprogramar()
    OR public.can_turnos_tanda()
    OR EXISTS (
      SELECT 1
      FROM public.perfiles p
      WHERE p.id = v_user_id
        AND p.rol = 'admin'
    )
  ) THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF p_tanda_id IS NULL THEN
    RAISE EXCEPTION 'Tanda invalida';
  END IF;

  SELECT
    s.paciente_id,
    coalesce(s.referido_tercero, false),
    s.referente_id,
    coalesce(s.modalidad_cobro, 'particular'),
    s.obra_social_id,
    s.numero_autorizacion,
    s.sesiones_autorizadas,
    s.ciclo_obra_social_id,
    s.medico_id,
    coalesce(s.es_nuevo_ingreso, false),
    s.obra_social_validada_por,
    s.obra_social_validada_at
  INTO
    v_patient_id,
    v_referido_tercero,
    v_referente_id,
    v_modalidad_cobro,
    v_obra_social_id,
    v_numero_autorizacion,
    v_sesiones_autorizadas,
    v_ciclo_obra_social_id,
    v_medico_id,
    v_es_nuevo_ingreso,
    v_obra_social_validada_por,
    v_obra_social_validada_at
  FROM public.slots s
  WHERE s.tanda_id = p_tanda_id
    AND s.estado = 'ocupado'
  ORDER BY s.fecha, s.hora, s.camara_id, s.lugar
  LIMIT 1;

  IF v_patient_id IS NULL THEN
    RAISE EXCEPTION 'No hay turnos ocupados para esta tanda';
  END IF;

  FOR v_row IN
    UPDATE public.slots
    SET paciente_id = null,
        estado = 'cancelado',
        es_tanda = false,
        es_bloque_completo = false,
        apartado_por = null,
        apartado_ts = null,
        referido_tercero = false,
        referente_id = null,
        modalidad_cobro = 'particular',
        obra_social_id = null,
        numero_autorizacion = null,
        sesiones_autorizadas = null,
        ciclo_obra_social_id = null,
        medico_id = null,
        es_nuevo_ingreso = false,
        obra_social_validada_por = null,
        obra_social_validada_at = null
    WHERE tanda_id = p_tanda_id
      AND estado = 'ocupado'
    RETURNING *
  LOOP
    IF NOT v_logged THEN
      PERFORM public.admin_insert_historial_bloque(
        v_row.fecha,
        v_row.hora,
        v_row.camara_id,
        null,
        null,
        'tanda_cancelada',
        v_patient_id,
        v_user_id,
        p_motivo,
        v_referido_tercero,
        v_referente_id,
        v_modalidad_cobro,
        v_obra_social_id,
        v_numero_autorizacion,
        v_sesiones_autorizadas,
        v_ciclo_obra_social_id,
        v_medico_id,
        v_es_nuevo_ingreso,
        v_obra_social_validada_por,
        v_obra_social_validada_at,
        p_tanda_id
      );
      v_logged := true;
    END IF;
    v_cancelled_slot_ids := array_append(v_cancelled_slot_ids, v_row.id);
    RETURN NEXT v_row;
  END LOOP;

  IF NOT v_logged THEN
    RAISE EXCEPTION 'No hay turnos ocupados para esta tanda';
  END IF;

  IF coalesce(array_length(v_cancelled_slot_ids, 1), 0) = 1 THEN
    PERFORM public.whatsapp_enqueue_cancelacion_turno(
      v_patient_id,
      v_cancelled_slot_ids[1],
      (SELECT s.fecha FROM public.slots s WHERE s.id = v_cancelled_slot_ids[1]),
      (SELECT s.hora FROM public.slots s WHERE s.id = v_cancelled_slot_ids[1]),
      'admin_cancelacion_tanda'
    );
  ELSIF coalesce(array_length(v_cancelled_slot_ids, 1), 0) > 1 THEN
    PERFORM public.whatsapp_enqueue_cancelacion_multiple(
      v_patient_id,
      v_cancelled_slot_ids,
      format(
        'tanda:%s:%s',
        p_tanda_id,
        to_char(now() AT TIME ZONE 'UTC', 'YYYYMMDDHH24MISSUS')
      ),
      'admin_cancelacion_tanda'
    );
  END IF;
END;
$$;


ALTER FUNCTION "public"."admin_cancelar_tanda"("p_tanda_id" "uuid", "p_motivo" "text") OWNER TO "postgres";


