CREATE OR REPLACE FUNCTION "public"."admin_cancelar_turno_fuera_horario"("p_turno_id" "uuid") RETURNS "public"."turnos_fuera_horario"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_result public.turnos_fuera_horario%rowtype;
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.can_turnos_fuera_horario() then
    raise exception 'Prohibido';
  end if;

  delete from public.turnos_fuera_horario
  where id = p_turno_id
  returning * into v_result;

