CREATE OR REPLACE FUNCTION "public"."admin_cerrar_consulta"("p_slot_id" "uuid", "p_estado" "text", "p_titulo" "text" DEFAULT NULL::"text", "p_nota" "text" DEFAULT NULL::"text", "p_diagnostico_impresion" "text" DEFAULT NULL::"text", "p_indicaciones" "text" DEFAULT NULL::"text") RETURNS "public"."consultas_slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor_perfil_id uuid := public.auth_current_profile_id();
  v_slot public.consultas_slots%rowtype;
  v_result public.consultas_slots%rowtype;
  v_estado text := lower(trim(coalesce(p_estado, '')));
  v_nota text := nullif(trim(coalesce(p_nota, '')), '');
begin
  if v_actor_perfil_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.can_consultas_cerrar() then
    raise exception 'Prohibido';
  end if;

  if v_estado not in ('completada', 'ausente') then
    raise exception 'Estado de cierre invalido';
  end if;

  select *
  into v_slot
  from public.consultas_slots
  where id = p_slot_id
  for update;

  if v_slot.id is null then
    raise exception 'Consulta no encontrada';
  end if;
  if v_slot.estado <> 'confirmada' then
    raise exception 'Solo se pueden cerrar consultas confirmadas';
  end if;

  update public.consultas_slots
  set estado = v_estado,
      cerrado_at = now(),
      cerrado_por = v_actor_perfil_id
  where id = p_slot_id
  returning * into v_result;

  if v_estado = 'completada' and v_nota is not null then
    insert into public.historia_clinica_evoluciones (
      paciente_id,
      consulta_slot_id,
      medico_id,
      autor_perfil_id,
      fecha_clinica,
      titulo,
      nota,
      diagnostico_impresion,
      indicaciones
    )
    values (
      v_result.paciente_id,
      v_result.id,
      v_result.medico_id,
      v_actor_perfil_id,
      v_result.fecha,
      nullif(trim(coalesce(p_titulo, '')), ''),
      v_nota,
      nullif(trim(coalesce(p_diagnostico_impresion, '')), ''),
      nullif(trim(coalesce(p_indicaciones, '')), '')
    );
  end if;

  perform public.admin_insert_historial_consulta(
    v_result.id,
    v_result.fecha,
    v_result.hora,
    'cerrada_' || v_estado,
    v_result.paciente_id,
    v_result.medico_id,
    v_actor_perfil_id,
    null,
    jsonb_build_object('estado', v_estado)
  );

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_cerrar_consulta"("p_slot_id" "uuid", "p_estado" "text", "p_titulo" "text", "p_nota" "text", "p_diagnostico_impresion" "text", "p_indicaciones" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_configurar_portal_paciente"("p_paciente_id" "uuid", "p_portal_habilitado" boolean) RETURNS "public"."perfiles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_result public.perfiles%ROWTYPE;
  v_documento_normalizado text;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.can_pacientes_portal_manage() THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  SELECT documento_identidad_normalizado
  INTO v_documento_normalizado
  FROM public.perfiles
  WHERE id = p_paciente_id
    AND rol = 'paciente';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Paciente no encontrado';
  END IF;

  IF p_portal_habilitado AND v_documento_normalizado IS NULL THEN
    RAISE EXCEPTION 'Documento de identidad requerido';
  END IF;

  IF p_portal_habilitado AND EXISTS (
    SELECT 1
    FROM public.perfiles
    WHERE id <> p_paciente_id
      AND rol = 'paciente'
      AND portal_habilitado = true
      AND documento_identidad_normalizado = v_documento_normalizado
  ) THEN
    RAISE EXCEPTION 'Documento de identidad ya en uso para acceso al portal';
  END IF;

  UPDATE public.perfiles
  SET
    portal_habilitado = coalesce(p_portal_habilitado, false),
    requiere_reset_portal = CASE
      WHEN coalesce(p_portal_habilitado, false) AND coalesce(portal_habilitado, false) = false THEN true
      WHEN coalesce(p_portal_habilitado, false) THEN coalesce(requiere_reset_portal, false)
      ELSE false
    END,
    portal_login_email = CASE
      WHEN coalesce(p_portal_habilitado, false) THEN coalesce(portal_login_email, 'paciente+' || id::text || '@portal.local')
      ELSE portal_login_email
    END,
    portal_habilitado_at = CASE
      WHEN coalesce(p_portal_habilitado, false) THEN coalesce(portal_habilitado_at, now())
      ELSE portal_habilitado_at
    END
  WHERE id = p_paciente_id
  RETURNING * INTO v_result;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_configurar_portal_paciente"("p_paciente_id" "uuid", "p_portal_habilitado" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_confirmar_apartado"("p_slot_id" "uuid", "p_paciente_id" "uuid" DEFAULT NULL::"uuid", "p_referido_tercero" boolean DEFAULT false, "p_referente_id" integer DEFAULT NULL::integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno" DEFAULT 'particular'::"public"."modalidad_cobro_turno", "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_autorizacion" "text" DEFAULT NULL::"text", "p_sesiones_autorizadas" integer DEFAULT NULL::integer, "p_ciclo_obra_social_id" "uuid" DEFAULT NULL::"uuid", "p_iniciar_nuevo_ciclo_obra_social" boolean DEFAULT false, "p_convenio_corroborado" boolean DEFAULT false, "p_medico_id" integer DEFAULT NULL::integer, "p_es_nuevo_ingreso" boolean DEFAULT false, "p_es_monoxido" boolean DEFAULT false, "p_monoxido_orden_medica" boolean DEFAULT false, "p_monoxido_resumen_clinico" boolean DEFAULT false) RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_profile_id uuid := public.auth_current_profile_id();
  v_result public.slots%ROWTYPE;
  v_current_slot public.slots%ROWTYPE;
  v_target_paciente_id uuid;
  v_operativo_obra_social_id integer;
  v_operativo_numero_autorizacion text;
  v_operativo_sesiones_autorizadas integer;
  v_operativo_ciclo_obra_social_id uuid;
  v_operativo_sin_convenio boolean;
  v_obra_social_validada_por uuid;
  v_obra_social_validada_at timestamptz;
  v_medico_id integer;
  v_referente_id integer;
BEGIN
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'No autorizado'; END IF;
  IF v_profile_id IS NULL THEN RAISE EXCEPTION 'Perfil no encontrado'; END IF;
  IF NOT public.can_turnos_confirmar_apartado() THEN RAISE EXCEPTION 'Prohibido'; END IF;

  SELECT *
  INTO v_current_slot
  FROM public.slots
  WHERE id = p_slot_id;

  IF v_current_slot.id IS NULL THEN
    RAISE EXCEPTION 'Slot no encontrado';
  END IF;
  IF v_current_slot.estado <> 'apartado' THEN
    RAISE EXCEPTION 'Solo se pueden confirmar slots apartados';
  END IF;
  IF p_paciente_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM public.perfiles WHERE id = p_paciente_id AND rol = 'paciente') THEN
    RAISE EXCEPTION 'Paciente no valido';
  END IF;

  v_target_paciente_id := coalesce(p_paciente_id, v_current_slot.paciente_id);
  IF v_target_paciente_id IS NULL THEN
    RAISE EXCEPTION 'Paciente requerido para confirmar el apartado';
  END IF;

  IF coalesce(p_es_monoxido, false) AND (NOT coalesce(p_monoxido_orden_medica, false) OR NOT coalesce(p_monoxido_resumen_clinico, false)) THEN
    RAISE EXCEPTION 'Monoxido requiere orden medica y resumen clinico';
  END IF;

  SELECT obra_social_id, numero_autorizacion, sesiones_autorizadas, ciclo_obra_social_id, sin_convenio
  INTO v_operativo_obra_social_id, v_operativo_numero_autorizacion, v_operativo_sesiones_autorizadas, v_operativo_ciclo_obra_social_id, v_operativo_sin_convenio
  FROM public.admin_resolver_operativo_obra_social(
    v_target_paciente_id, p_modalidad_cobro, p_obra_social_id, p_numero_autorizacion, p_sesiones_autorizadas,
    p_ciclo_obra_social_id, p_iniciar_nuevo_ciclo_obra_social, p_convenio_corroborado
  );

  PERFORM public.admin_validar_tope_obra_social_serie(
    v_target_paciente_id, p_modalidad_cobro, v_operativo_numero_autorizacion, v_operativo_sesiones_autorizadas, v_operativo_ciclo_obra_social_id
  );

  v_medico_id := public.admin_resolver_medico_operativo(p_medico_id, p_es_nuevo_ingreso, null);
  v_referente_id := public.admin_resolver_referente_operativo(p_referido_tercero, p_referente_id, v_current_slot.referente_id);
  v_obra_social_validada_por := CASE WHEN v_operativo_sin_convenio THEN v_profile_id ELSE null END;
  v_obra_social_validada_at := CASE WHEN v_operativo_sin_convenio THEN now() ELSE null END;

  UPDATE public.slots
  SET estado = 'ocupado',
      paciente_id = v_target_paciente_id,
      apartado_por = null,
      apartado_ts = null,
      referido_tercero = coalesce(p_referido_tercero, false),
      referente_id = v_referente_id,
      modalidad_cobro = coalesce(p_modalidad_cobro, 'particular'),
      obra_social_id = v_operativo_obra_social_id,
      numero_autorizacion = v_operativo_numero_autorizacion,
      sesiones_autorizadas = v_operativo_sesiones_autorizadas,
      ciclo_obra_social_id = v_operativo_ciclo_obra_social_id,
      medico_id = v_medico_id,
      es_nuevo_ingreso = coalesce(p_es_nuevo_ingreso, false),
      obra_social_validada_por = v_obra_social_validada_por,
      obra_social_validada_at = v_obra_social_validada_at,
      es_monoxido = coalesce(p_es_monoxido, false),
      monoxido_orden_medica = CASE WHEN coalesce(p_es_monoxido, false) THEN coalesce(p_monoxido_orden_medica, false) ELSE false END,
      monoxido_resumen_clinico = CASE WHEN coalesce(p_es_monoxido, false) THEN coalesce(p_monoxido_resumen_clinico, false) ELSE false END
  WHERE id = p_slot_id
  RETURNING * INTO v_result;

  IF v_result.id IS NULL THEN
    RAISE EXCEPTION 'Slot no encontrado';
  END IF;

  PERFORM public.admin_insert_historial_bloque(
    v_result.fecha, v_result.hora, v_result.camara_id, v_result.id, v_result.lugar, 'apartado_confirmado', v_result.paciente_id, v_user_id,
    null, v_result.referido_tercero, v_result.referente_id, v_result.modalidad_cobro, v_result.obra_social_id,
    v_result.numero_autorizacion, v_result.sesiones_autorizadas, v_result.ciclo_obra_social_id, v_result.medico_id,
    v_result.es_nuevo_ingreso, v_result.obra_social_validada_por, v_result.obra_social_validada_at, v_result.tanda_id
  );
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_confirmar_apartado"("p_slot_id" "uuid", "p_paciente_id" "uuid", "p_referido_tercero" boolean, "p_referente_id" integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer, "p_numero_autorizacion" "text", "p_sesiones_autorizadas" integer, "p_ciclo_obra_social_id" "uuid", "p_iniciar_nuevo_ciclo_obra_social" boolean, "p_convenio_corroborado" boolean, "p_medico_id" integer, "p_es_nuevo_ingreso" boolean, "p_es_monoxido" boolean, "p_monoxido_orden_medica" boolean, "p_monoxido_resumen_clinico" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_confirmar_cierre_diario"("p_fecha" "date", "p_detalles" "jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_actor_perfil_id uuid := public.auth_current_profile_id();
  v_cierre_id uuid;
  v_preview_count integer;
  v_submitted_count integer;
  v_matching_count integer;
begin
  if v_user_id is null or v_actor_perfil_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('turnos.cierre_diario') then
    raise exception 'Prohibido';
  end if;

  if p_fecha is null then
    raise exception 'Fecha requerida';
  end if;

  if exists (select 1 from public.cierres_diarios where fecha = p_fecha) then
    raise exception 'La fecha ya tiene un cierre diario confirmado';
  end if;

  select count(*) into v_preview_count
  from public.admin_build_cierre_diario_preview_rows(p_fecha);

  if coalesce(v_preview_count, 0) = 0 then
    raise exception 'No hay turnos para cerrar en esa fecha';
  end if;

  with parsed as (
    select
      nullif(trim(coalesce(value ->> 'slot_id', '')), '')::uuid as slot_id,
      nullif(trim(coalesce(value ->> 'turno_fuera_horario_id', '')), '')::uuid as turno_fuera_horario_id,
      coalesce((value ->> 'asistio')::boolean, true) as asistio
    from jsonb_array_elements(coalesce(p_detalles, '[]'::jsonb)) as value
  ),
  submitted as (
    select slot_id, null::uuid as turno_fuera_horario_id, asistio
    from (
      select distinct on (slot_id) slot_id, asistio
      from parsed
      where slot_id is not null
        and turno_fuera_horario_id is null
      order by slot_id
    ) a
    union all
    select null::uuid, turno_fuera_horario_id, asistio
    from (
      select distinct on (turno_fuera_horario_id) turno_fuera_horario_id, asistio
      from parsed
      where turno_fuera_horario_id is not null
        and slot_id is null
      order by turno_fuera_horario_id
    ) b
  )
  select count(*) into v_submitted_count
  from submitted;

  with parsed as (
    select
      nullif(trim(coalesce(value ->> 'slot_id', '')), '')::uuid as slot_id,
      nullif(trim(coalesce(value ->> 'turno_fuera_horario_id', '')), '')::uuid as turno_fuera_horario_id,
      coalesce((value ->> 'asistio')::boolean, true) as asistio
    from jsonb_array_elements(coalesce(p_detalles, '[]'::jsonb)) as value
  ),
  submitted as (
    select slot_id, null::uuid as turno_fuera_horario_id, asistio
    from (
      select distinct on (slot_id) slot_id, asistio
      from parsed
      where slot_id is not null
        and turno_fuera_horario_id is null
      order by slot_id
    ) a
    union all
    select null::uuid, turno_fuera_horario_id, asistio
    from (
      select distinct on (turno_fuera_horario_id) turno_fuera_horario_id, asistio
      from parsed
      where turno_fuera_horario_id is not null
        and slot_id is null
      order by turno_fuera_horario_id
    ) b
  )
  select count(*) into v_matching_count
  from public.admin_build_cierre_diario_preview_rows(p_fecha) preview
  join submitted s
    on preview.slot_id is not distinct from s.slot_id and preview.turno_fuera_horario_id is not distinct from s.turno_fuera_horario_id;

  if v_submitted_count <> v_preview_count or v_matching_count <> v_preview_count then
    raise exception 'Los turnos del cierre cambiaron. Recarga el cierre diario antes de confirmar';
  end if;

  insert into public.cierres_diarios (fecha, estado, cerrado_por, cerrado_at)
  values (p_fecha, 'cerrado', v_actor_perfil_id, now())
  returning id into v_cierre_id;

  with parsed as (
    select
      nullif(trim(coalesce(value ->> 'slot_id', '')), '')::uuid as slot_id,
      nullif(trim(coalesce(value ->> 'turno_fuera_horario_id', '')), '')::uuid as turno_fuera_horario_id,
      coalesce((value ->> 'asistio')::boolean, true) as asistio
    from jsonb_array_elements(coalesce(p_detalles, '[]'::jsonb)) as value
  ),
  submitted as (
    select slot_id, null::uuid as turno_fuera_horario_id, asistio
    from (
      select distinct on (slot_id) slot_id, asistio
      from parsed
      where slot_id is not null
        and turno_fuera_horario_id is null
      order by slot_id
    ) a
    union all
    select null::uuid, turno_fuera_horario_id, asistio
    from (
      select distinct on (turno_fuera_horario_id) turno_fuera_horario_id, asistio
      from parsed
      where turno_fuera_horario_id is not null
        and slot_id is null
      order by turno_fuera_horario_id
    ) b
  )
  insert into public.cierre_diario_detalles (
    cierre_id,
    slot_id,
    turno_fuera_horario_id,
    slot_ids,
    paciente_id,
    fecha,
    hora,
    camara_id,
    paciente_numero_dia,
    nombre_paciente,
    sesion_numero,
    sesion_numero_historico,
    modalidad_cobro,
    obra_social_id,
    obra_social_nombre,
    obra_social_abreviatura,
    importe,
    numero_autorizacion,
    sesiones_autorizadas,
    ciclo_obra_social_id,
    es_nuevo_ingreso,
    medico_id,
    medico_nombre,
    es_monoxido,
    es_oxibarica,
    asistio
  )
  select
    v_cierre_id,
    preview.slot_id,
    preview.turno_fuera_horario_id,
    preview.slot_ids,
    preview.paciente_id,
    preview.fecha,
    preview.hora,
    preview.camara_id,
    preview.paciente_numero_dia,
    preview.nombre_paciente,
    preview.sesion_numero,
    preview.sesion_numero_historico,
    preview.modalidad_cobro,
    preview.obra_social_id,
    preview.obra_social_nombre,
    preview.obra_social_abreviatura,
    0::numeric(12,2),
    preview.numero_autorizacion,
    preview.sesiones_autorizadas,
    preview.ciclo_obra_social_id,
    preview.es_nuevo_ingreso,
    preview.medico_id,
    preview.medico_nombre,
    preview.es_monoxido,
    preview.es_oxibarica,
    s.asistio
  from public.admin_build_cierre_diario_preview_rows(p_fecha) preview
  join submitted s
    on preview.slot_id is not distinct from s.slot_id
   and preview.turno_fuera_horario_id is not distinct from s.turno_fuera_horario_id;

  insert into public.sesiones (
    paciente_id,
    slot_id,
    fecha,
    hora,
    camara_id,
    modalidad_cobro,
    obra_social_id,
    numero_autorizacion,
    sesiones_autorizadas,
    ciclo_obra_social_id,
    cierre_id
  )
  select
    detalle.paciente_id,
    detalle.slot_id,
    detalle.fecha,
    detalle.hora,
    detalle.camara_id,
    detalle.modalidad_cobro,
    case when detalle.modalidad_cobro = 'obra_social' then detalle.obra_social_id else null end,
    case when detalle.modalidad_cobro = 'obra_social' then detalle.numero_autorizacion else null end,
    case when detalle.modalidad_cobro = 'obra_social' then detalle.sesiones_autorizadas else null end,
    case when detalle.modalidad_cobro = 'obra_social' then detalle.ciclo_obra_social_id else null end,
    v_cierre_id
  from public.cierre_diario_detalles detalle
  where detalle.cierre_id = v_cierre_id
    and detalle.asistio = true;

  update public.perfiles p
  set primera_sesion_efectivizada = true
  where p.id in (
    select distinct detalle.paciente_id
    from public.cierre_diario_detalles detalle
    where detalle.cierre_id = v_cierre_id
      and detalle.asistio = true
      and detalle.paciente_id is not null
  );

  return v_cierre_id;
end;
$$;


ALTER FUNCTION "public"."admin_confirmar_cierre_diario"("p_fecha" "date", "p_detalles" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_contar_sesiones_historicas_serie"("p_paciente_id" "uuid", "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_numero_autorizacion" "text", "p_ciclo_obra_social_id" "uuid") RETURNS integer
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT count(*)::integer
  FROM public.sesiones s
  WHERE s.paciente_id = p_paciente_id
    AND coalesce(s.modalidad_cobro, 'particular'::public.modalidad_cobro_turno) = coalesce(p_modalidad_cobro, 'particular'::public.modalidad_cobro_turno)
    AND (
      coalesce(p_modalidad_cobro, 'particular'::public.modalidad_cobro_turno) = 'particular'
      OR (
        public.admin_es_serie_obra_social_sn(p_numero_autorizacion) = false
        AND public.admin_normalizar_numero_autorizacion_obra_social(s.numero_autorizacion) = public.admin_normalizar_numero_autorizacion_obra_social(p_numero_autorizacion)
      )
      OR (
        public.admin_es_serie_obra_social_sn(p_numero_autorizacion) = true
        AND s.ciclo_obra_social_id = p_ciclo_obra_social_id
      )
    );
$$;


ALTER FUNCTION "public"."admin_contar_sesiones_historicas_serie"("p_paciente_id" "uuid", "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_numero_autorizacion" "text", "p_ciclo_obra_social_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_contar_unidades_programadas_serie"("p_paciente_id" "uuid", "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_numero_autorizacion" "text", "p_ciclo_obra_social_id" "uuid", "p_exclude_slot_ids" "uuid"[] DEFAULT ARRAY[]::"uuid"[]) RETURNS integer
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH units AS (
    SELECT s.fecha, s.hora, s.camara_id
    FROM public.slots s
    WHERE s.paciente_id = p_paciente_id
      AND s.estado = 'ocupado'
      AND coalesce(s.modalidad_cobro, 'particular'::public.modalidad_cobro_turno) = coalesce(p_modalidad_cobro, 'particular'::public.modalidad_cobro_turno)
      AND (
        coalesce(p_modalidad_cobro, 'particular'::public.modalidad_cobro_turno) = 'particular'
        OR (
          public.admin_es_serie_obra_social_sn(p_numero_autorizacion) = false
          AND public.admin_normalizar_numero_autorizacion_obra_social(s.numero_autorizacion) = public.admin_normalizar_numero_autorizacion_obra_social(p_numero_autorizacion)
        )
        OR (
          public.admin_es_serie_obra_social_sn(p_numero_autorizacion) = true
          AND s.ciclo_obra_social_id = p_ciclo_obra_social_id
        )
      )
      AND NOT (s.id = ANY(coalesce(p_exclude_slot_ids, ARRAY[]::uuid[])))
    GROUP BY s.fecha, s.hora, s.camara_id
  )
  SELECT count(*)::integer FROM units;
$$;


ALTER FUNCTION "public"."admin_contar_unidades_programadas_serie"("p_paciente_id" "uuid", "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_numero_autorizacion" "text", "p_ciclo_obra_social_id" "uuid", "p_exclude_slot_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_crear_camara"("p_nombre" "text", "p_capacidad" integer) RETURNS "public"."camaras"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_result public.camaras%ROWTYPE;
  v_nombre text := nullif(trim(coalesce(p_nombre, '')), '');
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_permission('config.camaras.manage') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF v_nombre IS NULL THEN
    RAISE EXCEPTION 'Nombre requerido';
  END IF;

  IF p_capacidad IS NULL OR p_capacidad < 1 THEN
    RAISE EXCEPTION 'Capacidad invalida';
  END IF;

  INSERT INTO public.camaras (nombre, capacidad, activa)
  VALUES (v_nombre, p_capacidad, true)
  RETURNING * INTO v_result;

  PERFORM public.generar_slots_camara_rango(
    v_result.id,
    v_result.capacidad,
    current_date,
    public.slots_horizonte_hasta()
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_crear_camara"("p_nombre" "text", "p_capacidad" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_crear_campo_config"("p_nombre" "text", "p_tipo" "text") RETURNS "public"."campos_config"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := public.auth_current_profile_id();
  v_result public.campos_config%rowtype;
  v_nombre text := nullif(trim(coalesce(p_nombre, '')), '');
  v_tipo text := trim(coalesce(p_tipo, ''));
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('config.catalogos.manage') then
    raise exception 'Prohibido';
  end if;

  if v_nombre is null then
    raise exception 'Nombre requerido';
  end if;

  if v_tipo not in ('texto', 'checkbox', 'numero') then
    raise exception 'Tipo invalido';
  end if;

  if exists (
    select 1
    from public.campos_config
    where lower(trim(nombre)) = lower(v_nombre)
  ) then
    raise exception 'Ya existe un campo con ese nombre';
  end if;

  insert into public.campos_config (nombre, tipo)
  values (v_nombre, v_tipo)
  returning * into v_result;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_crear_campo_config"("p_nombre" "text", "p_tipo" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_crear_consulta_horario_config"("p_hora" "text", "p_orden" integer) RETURNS "public"."consultas_horarios_config"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_result public.consultas_horarios_config%rowtype;
  v_hora text := nullif(trim(coalesce(p_hora, '')), '');
begin
  if not public.can_manage_consultas() then
    raise exception 'Prohibido';
  end if;
  if v_hora is null or p_orden is null then
    raise exception 'Datos incompletos';
  end if;

  insert into public.consultas_horarios_config (hora, orden)
  values (v_hora, p_orden)
  returning * into v_result;

  perform public.reparar_consultas_slots_rango(current_date, public.slots_horizonte_hasta());
  return v_result;
end;
$$;


