    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "public"."historia_clinica_evoluciones" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_crear_historia_clinica_evolucion"("p_paciente_id" "uuid", "p_medico_id" integer, "p_fecha_clinica" "date", "p_titulo" "text" DEFAULT NULL::"text", "p_nota" "text" DEFAULT NULL::"text", "p_diagnostico_impresion" "text" DEFAULT NULL::"text", "p_indicaciones" "text" DEFAULT NULL::"text", "p_consulta_slot_id" "uuid" DEFAULT NULL::"uuid") RETURNS "public"."historia_clinica_evoluciones"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_result public.historia_clinica_evoluciones%rowtype;
begin
  if not public.can_manage_historia_clinica() then
    raise exception 'Prohibido';
  end if;
  if p_paciente_id is null or p_medico_id is null or p_fecha_clinica is null then
    raise exception 'Datos incompletos';
  end if;
  if nullif(trim(coalesce(p_nota, '')), '') is null then
    raise exception 'Nota requerida';
  end if;

  perform public.ensure_historia_clinica_for_patient(p_paciente_id);
  perform public.admin_resolver_medico_operativo(p_medico_id, false, null);

  insert into public.historia_clinica_evoluciones (
    paciente_id,
    consulta_slot_id,
    medico_id,
    autor_perfil_id,
    fecha_clinica,
    titulo,
    nota,
    diagnostico_impresion,
    indicaciones
  )
  values (
    p_paciente_id,
    p_consulta_slot_id,
    p_medico_id,
    v_user_id,
    p_fecha_clinica,
    nullif(trim(coalesce(p_titulo, '')), ''),
    nullif(trim(coalesce(p_nota, '')), ''),
    nullif(trim(coalesce(p_diagnostico_impresion, '')), ''),
    nullif(trim(coalesce(p_indicaciones, '')), '')
  )
  returning * into v_result;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_crear_historia_clinica_evolucion"("p_paciente_id" "uuid", "p_medico_id" integer, "p_fecha_clinica" "date", "p_titulo" "text", "p_nota" "text", "p_diagnostico_impresion" "text", "p_indicaciones" "text", "p_consulta_slot_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_crear_horario_config"("p_hora" "text", "p_orden" integer) RETURNS "public"."horarios_config"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_user_id uuid := auth.uid();
  v_result public.horarios_config%rowtype;
  v_hora text := nullif(trim(coalesce(p_hora, '')), '');
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('config.horarios.manage') then
    raise exception 'Prohibido';
  end if;

  if v_hora is null or v_hora !~ '^[0-2][0-9]:[0-5][0-9]$' then
    raise exception 'Hora invalida';
  end if;

  if p_orden is null or p_orden < 1 then
    raise exception 'Orden invalido';
  end if;

  if exists (
    select 1
    from public.horarios_config
    where hora = v_hora
  ) then
    raise exception 'Ya existe un horario con esa hora';
  end if;

  insert into public.horarios_config (hora, activo, orden)
  values (v_hora, true, p_orden)
  returning * into v_result;

  perform public.generar_slots_hora(v_hora);

  return v_result;
end;
$_$;


ALTER FUNCTION "public"."admin_crear_horario_config"("p_hora" "text", "p_orden" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_crear_medico"("p_nombre" "text") RETURNS "public"."medicos"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_result public.medicos%ROWTYPE;
  v_nombre text := nullif(trim(coalesce(p_nombre, '')), '');
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_permission('config.catalogos.manage') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF v_nombre IS NULL THEN
    RAISE EXCEPTION 'Nombre requerido';
  END IF;

  IF EXISTS (SELECT 1 FROM public.medicos WHERE lower(nombre) = lower(v_nombre)) THEN
    RAISE EXCEPTION 'Nombre duplicado';
  END IF;

  INSERT INTO public.medicos (nombre, orden)
  VALUES (v_nombre, coalesce((SELECT max(orden) + 1 FROM public.medicos), 1))
  RETURNING * INTO v_result;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_crear_medico"("p_nombre" "text") OWNER TO "postgres";


