CREATE OR REPLACE FUNCTION "public"."admin_crear_referente"("p_nombre" "text", "p_tipo" "text") RETURNS "public"."referentes"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_nombre text := nullif(trim(coalesce(p_nombre, '')), '');
  v_tipo text;
  v_orden integer;
  v_result public.referentes%ROWTYPE;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_permission('config.catalogos.manage') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF v_nombre IS NULL THEN
    RAISE EXCEPTION 'Nombre requerido';
  END IF;

  v_tipo := public.admin_normalizar_tipo_referente(p_tipo);

  IF EXISTS (
    SELECT 1 FROM public.referentes
    WHERE lower(btrim(nombre)) = lower(btrim(v_nombre)) AND tipo = v_tipo
  ) THEN
    RAISE EXCEPTION 'Ya existe un referente con ese nombre y tipo';
  END IF;

  SELECT coalesce(max(orden), 0) + 1 INTO v_orden FROM public.referentes;
  INSERT INTO public.referentes (nombre, tipo, orden)
  VALUES (v_nombre, v_tipo, v_orden)
  RETURNING * INTO v_result;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_crear_referente"("p_nombre" "text", "p_tipo" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_crear_turno_fuera_horario"("p_fecha" "date", "p_hora" "text", "p_paciente_id" "uuid", "p_operador_camara_id" "uuid", "p_notas" "text" DEFAULT NULL::"text", "p_es_monoxido" boolean DEFAULT false, "p_monoxido_orden_medica" boolean DEFAULT false, "p_monoxido_resumen_clinico" boolean DEFAULT false, "p_monoxido_medico_id" integer DEFAULT NULL::integer) RETURNS "public"."turnos_fuera_horario"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_actor_profile_id uuid := public.auth_current_profile_id();
  v_result public.turnos_fuera_horario%rowtype;
  v_hora text := trim(coalesce(p_hora, ''));
  v_notas text := nullif(trim(coalesce(p_notas, '')), '');
  v_es boolean := coalesce(p_es_monoxido, false);
  v_ord boolean := coalesce(p_monoxido_orden_medica, false);
  v_res boolean := coalesce(p_monoxido_resumen_clinico, false);
  v_med integer := p_monoxido_medico_id;
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.can_turnos_fuera_horario() then
    raise exception 'Prohibido';
  end if;

  if v_actor_profile_id is null then
    raise exception 'Perfil no encontrado';
  end if;

  if p_fecha is null or p_fecha < current_date then
    raise exception 'La fecha del turno debe ser hoy o futura';
  end if;

  if v_hora = '' then
    raise exception 'La hora es obligatoria';
  end if;

  if p_paciente_id is null or not exists (
    select 1
    from public.perfiles
    where id = p_paciente_id and rol = 'paciente'
  ) then
    raise exception 'Paciente no valido';
  end if;

  if p_operador_camara_id is null then
    raise exception 'Debe indicarse el operador de cámara';
  end if;

  if not exists (
    select 1
    from public.perfiles
    where id = p_operador_camara_id
      and rol = 'admin'
  ) then
    raise exception 'Operador de cámara no válido';
  end if;

  if v_es and (not v_ord or not v_res) then
    raise exception 'Para turno de monóxido se requiere orden médica y resumen clínico';
  end if;

  if v_es then
    if v_med is null then
      raise exception 'Para turno de monóxido debe indicarse el médico de la consulta';
    end if;
    if not exists (select 1 from public.medicos m where m.id = v_med) then
      raise exception 'Médico no válido';
    end if;
  else
    v_med := null;
  end if;

  insert into public.turnos_fuera_horario (
    fecha,
    hora,
    paciente_id,
    notas,
    creado_por,
    operador_camara_id,
    es_monoxido,
    monoxido_orden_medica,
    monoxido_resumen_clinico,
    monoxido_medico_id
  )
  values (
    p_fecha,
    v_hora,
    p_paciente_id,
    v_notas,
    v_actor_profile_id,
    p_operador_camara_id,
    v_es,
    case when v_es then v_ord else false end,
    case when v_es then v_res else false end,
    case when v_es then v_med else null end
  )
  returning * into v_result;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_crear_turno_fuera_horario"("p_fecha" "date", "p_hora" "text", "p_paciente_id" "uuid", "p_operador_camara_id" "uuid", "p_notas" "text", "p_es_monoxido" boolean, "p_monoxido_orden_medica" boolean, "p_monoxido_resumen_clinico" boolean, "p_monoxido_medico_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_create_staff_user"("p_auth_user_id" "uuid", "p_nombre" "text", "p_login_identifier" "text" DEFAULT NULL::"text", "p_email" "text" DEFAULT NULL::"text", "p_documento_identidad" "text" DEFAULT NULL::"text", "p_role_slug" "text" DEFAULT 'secretaria'::"text", "p_primary" boolean DEFAULT true) RETURNS "public"."perfiles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_actor_id uuid := public.auth_current_profile_id();
  v_perfil public.perfiles%rowtype;
  v_role_slug text := lower(trim(coalesce(p_role_slug, 'secretaria')));
  v_login_identifier text := nullif(lower(trim(coalesce(p_login_identifier, p_email, ''))), '');
  v_documento text := upper(regexp_replace(coalesce(trim(p_documento_identidad), ''), '[^A-Z0-9]', '', 'g'));
begin
  if not public.auth_has_permission('staff.manage') then
    raise exception 'Prohibido';
  end if;

  if p_auth_user_id is null then
    raise exception 'Auth user requerido';
  end if;

  if v_role_slug = 'paciente' then
    raise exception 'Para staff no se permite rol paciente';
  end if;

  if coalesce(trim(p_nombre), '') = '' then
    raise exception 'Nombre requerido';
  end if;

  if coalesce(trim(coalesce(v_login_identifier, '')), '') = '' then
    raise exception 'Identificador de acceso requerido';
  end if;

  select *
  into v_perfil
  from public.perfiles
  where auth_user_id = p_auth_user_id
  limit 1;

  if v_perfil.id is null then
    insert into public.perfiles(
      id,
      auth_user_id,
      nombre,
      email,
      portal_login_email,
      documento_identidad,
      telefono,
      rol,
      portal_habilitado,
      requiere_reset_portal
    )
    values (
      gen_random_uuid(),
      p_auth_user_id,
      trim(coalesce(p_nombre, 'Usuario interno')),
      case
        when coalesce(trim(coalesce(p_email, '')), '') <> '' then nullif(lower(trim(coalesce(p_email, ''))), '')
        when v_login_identifier ~ '^[^[:space:]@]+@[^[:space:]@]+\\.[^[:space:]@]+$' then v_login_identifier
        else null
      end,
      v_login_identifier,
      nullif(v_documento, ''),
      null,
      'admin',
      false,
      false
    )
    returning *
    into v_perfil;
  else
    update public.perfiles
    set
      nombre = trim(coalesce(p_nombre, v_perfil.nombre)),
      email = coalesce(nullif(lower(trim(coalesce(p_email, ''))), ''), v_perfil.email),
      portal_login_email = coalesce(v_perfil.portal_login_email, v_login_identifier),
      documento_identidad = coalesce(nullif(v_documento, ''), v_perfil.documento_identidad),
      rol = 'admin',
      updated_at = now()
    where id = v_perfil.id
    returning *
    into v_perfil;
  end if;

  perform public.admin_assign_user_roles(
    v_perfil.id,
    array[v_role_slug],
    case when p_primary then v_role_slug else null end
  );

  perform public.admin_append_event(
    p_occurred_at := now(),
    p_action_code := 'staff.creado',
    p_action_family := 'altas',
    p_entity_type := 'staff',
    p_entity_id := v_perfil.id::text,
    p_title := 'Usuario interno creado',
    p_summary := v_perfil.nombre,
    p_actor_user_id := v_actor_id,
    p_actor_label := null,
    p_source_system := 'perfiles',
    p_source_record_key := v_perfil.id::text || ':staff',
    p_metadata := jsonb_build_object(
      'role_slug', v_role_slug,
      'email', v_perfil.email,
      'portal_login_email', v_perfil.portal_login_email,
      'documento_identidad', v_perfil.documento_identidad
    )
  );

  return v_perfil;
end;
$_$;


ALTER FUNCTION "public"."admin_create_staff_user"("p_auth_user_id" "uuid", "p_nombre" "text", "p_login_identifier" "text", "p_email" "text", "p_documento_identidad" "text", "p_role_slug" "text", "p_primary" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_dashboard_agenda_hoy"("p_fecha" "date") RETURNS TABLE("slot_id" "uuid", "fecha" "date", "hora" "text", "camara_id" integer, "camara_nombre" "text", "lugar" integer, "paciente_id" "uuid", "nombre_paciente" "text", "modalidad_cobro" "public"."modalidad_cobro_turno", "es_nuevo_ingreso" boolean, "es_bloque_completo" boolean, "estado" "public"."estado_slot")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_fecha date := coalesce(p_fecha, current_date);
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_permission('dashboard.read') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  RETURN QUERY
  SELECT
    s.id AS slot_id,
    s.fecha,
    s.hora,
    s.camara_id,
    c.nombre AS camara_nombre,
    s.lugar,
    s.paciente_id,
    p.nombre AS nombre_paciente,
    coalesce(s.modalidad_cobro, 'particular'::public.modalidad_cobro_turno) AS modalidad_cobro,
    coalesce(s.es_nuevo_ingreso, false) AS es_nuevo_ingreso,
    coalesce(s.es_bloque_completo, false) AS es_bloque_completo,
    s.estado
  FROM public.slots s
  JOIN public.camaras c ON c.id = s.camara_id
  LEFT JOIN public.perfiles p ON p.id = s.paciente_id
  WHERE s.fecha = v_fecha
    AND s.estado IN ('ocupado', 'apartado')
  ORDER BY s.hora, s.camara_id, s.lugar, lower(coalesce(p.nombre, '')), s.id;
END;
$$;


ALTER FUNCTION "public"."admin_dashboard_agenda_hoy"("p_fecha" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_dashboard_alertas"("p_fecha" "date" DEFAULT NULL::"date") RETURNS TABLE("tipo" "text", "titulo" "text", "descripcion" "text", "severidad" "text", "target_tab" "text", "target_meta" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_fecha date := coalesce(p_fecha, current_date);
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('dashboard.read') then
    raise exception 'Prohibido';
  end if;

  return query
  with agenda as (
    select
      s.id,
      s.paciente_id,
      coalesce(s.es_nuevo_ingreso, false) as es_nuevo_ingreso,
      s.estado
    from public.slots s
    where s.fecha = v_fecha
      and s.estado in ('ocupado', 'apartado')
  ),
  alertas as (
    select
      'condiciones_clinicas'::text as tipo,
      'Condiciones clinicas hoy'::text as titulo,
      format('%s paciente(s) con alerta clinica en agenda regular.', count(*)::integer)::text as descripcion,
      'alta'::text as severidad,
      'turnos'::text as target_tab,
      jsonb_build_object('fecha', v_fecha)::jsonb as target_meta,
      1 as orden
    from agenda a
    join public.perfiles p on p.id = a.paciente_id
    where coalesce(p.claustrofobico, false) = true
    having count(*) > 0

    union all

    select
      'nuevos_ingresos'::text,
      'Nuevos ingresos hoy'::text,
      format('%s turno(s) marcados como nuevo ingreso.', count(*)::integer)::text,
      'media'::text,
      'turnos'::text,
      jsonb_build_object('fecha', v_fecha)::jsonb,
      2 as orden
    from agenda
    where es_nuevo_ingreso = true
    having count(*) > 0

    union all

    select
      'apartados_pendientes'::text,
      'Apartados pendientes'::text,
      format('%s lugar(es) continúan apartados y ocupan capacidad del día.', count(*)::integer)::text,
      'media'::text,
      'turnos'::text,
      jsonb_build_object('fecha', v_fecha, 'estado', 'apartado')::jsonb,
      3 as orden
    from public.slots s
    where s.fecha = v_fecha
      and s.estado = 'apartado'
    having count(*) > 0

    union all

    select
      'turnos_fuera_horario'::text,
      'Turnos fuera de horario'::text,
      format('%s turno(s) fuera de horario cargados para hoy.', count(*)::integer)::text,
      'info'::text,
      'turnos'::text,
      jsonb_build_object('fecha', v_fecha, 'fuera_horario', true)::jsonb,
      4 as orden
    from public.turnos_fuera_horario t
    where t.fecha = v_fecha
    having count(*) > 0

    union all

    select
      'cierre_diario_pendiente'::text,
      'Cierre diario pendiente'::text,
      'El día de hoy todavía no fue cerrado.'::text,
      'alta'::text,
      'cierres-diario'::text,
      jsonb_build_object('fecha', v_fecha)::jsonb,
      5 as orden
    where not exists (
      select 1
      from public.cierres_diarios c
      where c.fecha = v_fecha
        and c.estado = 'cerrado'
    )
      and (
        exists (select 1 from public.slots s where s.fecha = v_fecha and s.estado = 'ocupado')
        or exists (select 1 from public.turnos_fuera_horario t where t.fecha = v_fecha)
      )

    union all

    select
      'obra_social_limite'::text,
      'Obras sociales al limite'::text,
      format('%s turno(s) de obra social quedaron en la ultima sesion autorizada.', count(*)::integer)::text,
      'media'::text,
      'turnos'::text,
      jsonb_build_object('fecha', v_fecha, 'modalidad', 'obra_social')::jsonb,
      6 as orden
    from public.admin_build_cierre_diario_preview_rows(v_fecha) preview
    where preview.modalidad_cobro = 'obra_social'
      and preview.sesiones_autorizadas is not null
      and preview.sesion_numero_historico >= preview.sesiones_autorizadas
    having count(*) > 0
  )
  select
    alertas.tipo,
    alertas.titulo,
    alertas.descripcion,
    alertas.severidad,
    alertas.target_tab,
    alertas.target_meta
  from alertas
  order by alertas.orden, alertas.tipo;
end;
$$;


ALTER FUNCTION "public"."admin_dashboard_alertas"("p_fecha" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_dashboard_ocupacion_camaras"("p_fecha" "date") RETURNS TABLE("camara_id" integer, "camara_nombre" "text", "capacidad_total" integer, "ocupados" integer, "libres" integer, "porcentaje_ocupacion" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_fecha date := coalesce(p_fecha, current_date);
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_permission('dashboard.read') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  RETURN QUERY
  SELECT
    c.id AS camara_id,
    c.nombre AS camara_nombre,
    count(s.id)::integer AS capacidad_total,
    count(*) FILTER (WHERE s.estado IN ('ocupado', 'apartado'))::integer AS ocupados,
    count(*) FILTER (WHERE s.estado IN ('libre', 'cancelado'))::integer AS libres,
    CASE
      WHEN count(s.id) = 0 THEN 0::numeric(5,2)
      ELSE round((count(*) FILTER (WHERE s.estado IN ('ocupado', 'apartado'))::numeric / count(s.id)::numeric) * 100, 2)
    END::numeric(5,2) AS porcentaje_ocupacion
  FROM public.camaras c
  LEFT JOIN public.slots s
    ON s.camara_id = c.id
   AND s.fecha = v_fecha
  WHERE c.activa = true
  GROUP BY c.id, c.nombre
  ORDER BY c.id;
END;
$$;


ALTER FUNCTION "public"."admin_dashboard_ocupacion_camaras"("p_fecha" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_dashboard_resumen"("p_fecha" "date") RETURNS TABLE("turnos_hoy" integer, "pacientes_hoy" integer, "asistidos_hoy" integer, "apartados_activos" integer, "fuera_horario_hoy" integer, "cierre_diario_estado" "text", "ultimo_cierre_fecha" "date", "dias_cerrados_mes" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_fecha date := coalesce(p_fecha, current_date);
  v_inicio_mes date := date_trunc('month', coalesce(p_fecha, current_date))::date;
  v_fin_mes date := (date_trunc('month', coalesce(p_fecha, current_date)) + interval '1 month - 1 day')::date;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_permission('dashboard.read') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  RETURN QUERY
  WITH preview AS (
    SELECT * FROM public.admin_build_cierre_diario_preview_rows(v_fecha)
  ),
  cierre_hoy AS (
    SELECT c.estado
    FROM public.cierres_diarios c
    WHERE c.fecha = v_fecha
    LIMIT 1
  ),
  asistidos AS (
    SELECT count(*)::integer AS total
    FROM public.cierre_diario_detalles detalle
    JOIN public.cierres_diarios cierre ON cierre.id = detalle.cierre_id
    WHERE cierre.fecha = v_fecha
      AND cierre.estado = 'cerrado'
      AND detalle.asistio = true
  )
  SELECT
    coalesce((SELECT count(*)::integer FROM public.slots s WHERE s.fecha = v_fecha AND s.estado = 'ocupado'), 0) AS turnos_hoy,
    coalesce((SELECT count(*)::integer FROM preview), 0) AS pacientes_hoy,
    CASE
      WHEN EXISTS (SELECT 1 FROM cierre_hoy WHERE estado = 'cerrado') THEN coalesce((SELECT total FROM asistidos), 0)
      ELSE NULL
    END AS asistidos_hoy,
    coalesce((SELECT count(*)::integer FROM public.slots s WHERE s.fecha = v_fecha AND s.estado = 'apartado'), 0) AS apartados_activos,
    coalesce((SELECT count(*)::integer FROM public.turnos_fuera_horario t WHERE t.fecha = v_fecha), 0) AS fuera_horario_hoy,
    coalesce((SELECT estado FROM cierre_hoy), 'abierto') AS cierre_diario_estado,
    (SELECT max(fecha) FROM public.cierres_diarios WHERE estado = 'cerrado') AS ultimo_cierre_fecha,
    coalesce((
      SELECT count(*)::integer
      FROM public.cierres_diarios c
      WHERE c.estado = 'cerrado'
        AND c.fecha >= v_inicio_mes
        AND c.fecha <= v_fin_mes
    ), 0) AS dias_cerrados_mes;
END;
$$;


ALTER FUNCTION "public"."admin_dashboard_resumen"("p_fecha" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_eliminar_campo_config"("p_campo_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := public.auth_current_profile_id();
  v_deleted_id uuid;
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('config.catalogos.manage') then
    raise exception 'Prohibido';
  end if;

  delete from public.campos_config
  where id = p_campo_id
  returning id into v_deleted_id;

  if v_deleted_id is null then
    raise exception 'Campo no encontrado';
  end if;

  return v_deleted_id;
end;
$$;


ALTER FUNCTION "public"."admin_eliminar_campo_config"("p_campo_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_eliminar_consulta_horario_config"("p_horario_id" integer, "p_resoluciones" "jsonb" DEFAULT '[]'::"jsonb", "p_motivo" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_actor_profile_id uuid := public.auth_current_profile_id();
  v_horario public.consultas_horarios_config%rowtype;
  v_auditoria_id uuid;
  v_current_source_slot_ids uuid[] := array[]::uuid[];
  v_payload_source_slot_ids uuid[] := array[]::uuid[];
  v_resolution jsonb;
  v_child jsonb;
  v_source_slot_id uuid;
  v_target_slot_id uuid;
  v_source_slot public.consultas_slots%rowtype;
  v_deleted_slot public.consultas_slots%rowtype;
  v_reasignados integer := 0;
  v_cancelados integer := 0;
  v_slots_eliminados integer := 0;
  v_action text;
  v_unit_id text;
  v_unit_type text;
begin
  if not public.can_manage_consultas() then
    raise exception 'Prohibido';
  end if;

  if v_actor_profile_id is null then
    raise exception 'Perfil no encontrado';
  end if;

  select *
  into v_horario
  from public.consultas_horarios_config
  where id = p_horario_id
  for update;

  if v_horario.id is null then
    return null;
  end if;

  select coalesce(array_agg(c.id order by c.id), array[]::uuid[])
  into v_current_source_slot_ids
  from public.consultas_slots c
  where c.fecha >= current_date
    and c.hora = v_horario.hora
    and c.estado in ('confirmada', 'completada');

  select coalesce(array_agg(distinct nullif(child->>'source_slot_id', '')::uuid), array[]::uuid[])
  into v_payload_source_slot_ids
  from jsonb_array_elements(coalesce(p_resoluciones, '[]'::jsonb)) as resolution_item,
       jsonb_array_elements(coalesce(resolution_item.value->'children', '[]'::jsonb)) as child
  where nullif(child->>'source_slot_id', '') is not null;

  if coalesce(array_length(v_current_source_slot_ids, 1), 0) <> coalesce(array_length(v_payload_source_slot_ids, 1), 0)
    or exists (
      select 1
      from unnest(v_current_source_slot_ids) as current_id
      where not (current_id = any(v_payload_source_slot_ids))
    )
    or exists (
      select 1
      from unnest(v_payload_source_slot_ids) as payload_id
      where not (payload_id = any(v_current_source_slot_ids))
    ) then
    raise exception 'La resolución quedó desactualizada. Volvé a cargar la previsualización.';
  end if;

  insert into public.horarios_eliminacion_auditoria (
    agenda_tipo, horario_id, hora, motivo, realizado_por, afectados_count, resumen
  )
  values (
    'consultas',
    v_horario.id,
    v_horario.hora,
    nullif(trim(coalesce(p_motivo, '')), ''),
    v_actor_profile_id,
    coalesce(array_length(v_current_source_slot_ids, 1), 0),
    jsonb_build_object('horario', row_to_json(v_horario))
  )
  returning id into v_auditoria_id;

  for v_resolution in
    select value
    from jsonb_array_elements(coalesce(p_resoluciones, '[]'::jsonb))
  loop
    v_action := lower(trim(coalesce(v_resolution->>'action', '')));
    v_unit_id := coalesce(v_resolution->>'unit_id', '');
    v_unit_type := coalesce(v_resolution->>'unit_type', '');

    if v_action not in ('cancel', 'reassign') then
      raise exception 'Acción inválida para eliminar horario';
    end if;

    for v_child in
      select value
      from jsonb_array_elements(coalesce(v_resolution->'children', '[]'::jsonb))
    loop
      v_source_slot_id := nullif(v_child->>'source_slot_id', '')::uuid;
      v_target_slot_id := nullif(v_child->>'target_slot_id', '')::uuid;

      select * into v_source_slot from public.consultas_slots where id = v_source_slot_id for update;
      if v_source_slot.id is null then
        raise exception 'Consulta origen inválida';
      end if;

      if v_action = 'reassign' then
        if v_target_slot_id is null then
          raise exception 'Falta destino para la consulta';
        end if;
        perform public.admin_reprogramar_consulta(v_source_slot_id, v_target_slot_id, v_source_slot.medico_id);
        v_reasignados := v_reasignados + 1;
      else
        perform public.admin_cancelar_consulta(v_source_slot_id, coalesce(p_motivo, 'Eliminacion de horario'));
        v_cancelados := v_cancelados + 1;
      end if;

      insert into public.horarios_eliminacion_auditoria_items (
        auditoria_id, agenda_tipo, unit_id, unit_type, accion, paciente_id, medico_id,
        source_slot_id, source_slot_ids, source_fecha, source_hora, target_slot_id, snapshot
      )
      values (
        v_auditoria_id,
        'consultas',
        v_unit_id,
        v_unit_type,
        v_action,
        v_source_slot.paciente_id,
        v_source_slot.medico_id,
        v_source_slot_id,
        array[v_source_slot_id]::uuid[],
        v_source_slot.fecha,
        v_source_slot.hora,
        v_target_slot_id,
        jsonb_build_object('source_estado', v_source_slot.estado)
      );
    end loop;
  end loop;

  for v_deleted_slot in
    delete from public.consultas_slots
    where fecha >= current_date
      and hora = v_horario.hora
    returning *
  loop
    v_slots_eliminados := v_slots_eliminados + 1;
    perform public.admin_insert_historial_consulta(
      null,
      v_deleted_slot.fecha,
      v_deleted_slot.hora,
      'eliminacion_horario_slot_eliminado',
      null,
      null,
      v_actor_profile_id,
      coalesce(p_motivo, 'Eliminacion de horario'),
      jsonb_build_object('slot_id', v_deleted_slot.id)
    );
  end loop;

  delete from public.consultas_horarios_config
  where id = v_horario.id;

  update public.horarios_eliminacion_auditoria
  set reasignados_count = v_reasignados,
      cancelados_count = v_cancelados,
      liberados_count = 0,
      slots_eliminados_count = v_slots_eliminados,
      resumen = jsonb_build_object(
        'horario', row_to_json(v_horario),
        'reasignados', v_reasignados,
        'cancelados', v_cancelados,
        'slots_eliminados', v_slots_eliminados
      )
  where id = v_auditoria_id;

  return jsonb_build_object(
    'auditoria_id', v_auditoria_id,
    'reasignados', v_reasignados,
    'cancelados', v_cancelados,
    'slots_eliminados', v_slots_eliminados
  );
end;
$$;


ALTER FUNCTION "public"."admin_eliminar_consulta_horario_config"("p_horario_id" integer, "p_resoluciones" "jsonb", "p_motivo" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_eliminar_horario_config"("p_horario_id" integer, "p_resoluciones" "jsonb" DEFAULT '[]'::"jsonb", "p_motivo" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_actor_profile_id uuid := public.auth_current_profile_id();
  v_horario public.horarios_config%rowtype;
  v_auditoria_id uuid;
  v_current_source_slot_ids uuid[] := array[]::uuid[];
  v_payload_source_slot_ids uuid[] := array[]::uuid[];
  v_resolution jsonb;
  v_child jsonb;
  v_source_slot_ids uuid[];
  v_source_slot_id uuid;
  v_target_slot_id uuid;
  v_source_slot public.slots%rowtype;
  v_deleted_slot public.slots%rowtype;
  v_reasignados integer := 0;
  v_cancelados integer := 0;
  v_liberados integer := 0;
  v_slots_eliminados integer := 0;
  v_child_count integer := 0;
  v_action text;
  v_unit_id text;
  v_unit_type text;
begin
  if not public.can_manage_horarios_auditoria() then
    raise exception 'Prohibido';
  end if;

  if v_actor_profile_id is null then
    raise exception 'Perfil no encontrado';
  end if;

  select *
  into v_horario
  from public.horarios_config
  where id = p_horario_id
  for update;

  if v_horario.id is null then
    raise exception 'Horario no encontrado';
  end if;

  select coalesce(array_agg(s.id order by s.id), array[]::uuid[])
  into v_current_source_slot_ids
  from public.slots s
  where s.fecha >= current_date
    and s.hora = v_horario.hora
    and s.estado in ('ocupado', 'apartado');

  select coalesce(array_agg(distinct source_id), array[]::uuid[])
  into v_payload_source_slot_ids
  from (
    select nullif(child_item->>'source_slot_id', '')::uuid as source_id
    from jsonb_array_elements(coalesce(p_resoluciones, '[]'::jsonb)) as resolution_item,
         jsonb_array_elements(coalesce(resolution_item.value->'children', '[]'::jsonb)) as child_item
    union all
    select nullif(source_slot_id_text.value, '')::uuid as source_id
    from jsonb_array_elements(coalesce(p_resoluciones, '[]'::jsonb)) as resolution_item,
         jsonb_array_elements(coalesce(resolution_item.value->'children', '[]'::jsonb)) as child_item,
         jsonb_array_elements_text(coalesce(child_item.value->'source_slot_ids', '[]'::jsonb)) as source_slot_id_text(value)
  ) ids
  where source_id is not null;

  if coalesce(array_length(v_current_source_slot_ids, 1), 0) <> coalesce(array_length(v_payload_source_slot_ids, 1), 0)
    or exists (
      select 1
      from unnest(v_current_source_slot_ids) as current_id
      where not (current_id = any(v_payload_source_slot_ids))
    )
    or exists (
      select 1
      from unnest(v_payload_source_slot_ids) as payload_id
      where not (payload_id = any(v_current_source_slot_ids))
    ) then
    raise exception 'La resolución quedó desactualizada. Volvé a cargar la previsualización.';
  end if;

  insert into public.horarios_eliminacion_auditoria (
    agenda_tipo, horario_id, hora, motivo, realizado_por, afectados_count, resumen
  )
  values (
    'camaras',
    v_horario.id,
    v_horario.hora,
    nullif(trim(coalesce(p_motivo, '')), ''),
    v_actor_profile_id,
    coalesce(array_length(v_current_source_slot_ids, 1), 0),
    jsonb_build_object('horario', row_to_json(v_horario))
  )
  returning id into v_auditoria_id;

  for v_resolution in
    select value
    from jsonb_array_elements(coalesce(p_resoluciones, '[]'::jsonb))
  loop
    v_action := lower(trim(coalesce(v_resolution->>'action', '')));
    v_unit_id := coalesce(v_resolution->>'unit_id', '');
    v_unit_type := coalesce(v_resolution->>'unit_type', '');

    if v_action not in ('cancel', 'reassign') then
      raise exception 'Acción inválida para eliminar horario';
    end if;

    for v_child in
      select value
      from jsonb_array_elements(coalesce(v_resolution->'children', '[]'::jsonb))
    loop
      v_source_slot_id := nullif(v_child->>'source_slot_id', '')::uuid;
      v_target_slot_id := nullif(v_child->>'target_slot_id', '')::uuid;

      select coalesce(array_agg(nullif(source_slot_id_text.value, '')::uuid), array[]::uuid[])
      into v_source_slot_ids
      from jsonb_array_elements_text(coalesce(v_child->'source_slot_ids', '[]'::jsonb)) as source_slot_id_text(value);

      if coalesce(array_length(v_source_slot_ids, 1), 0) > 1 then
        select * into v_source_slot from public.slots where id = v_source_slot_id for update;
        if v_source_slot.id is null then
          raise exception 'Bloque origen inválido';
        end if;

        if v_action = 'reassign' then
          if v_target_slot_id is null then
            raise exception 'Falta destino para bloque';
          end if;
          v_child_count := public.admin_mover_bloque_por_eliminacion_horario(v_source_slot_id, v_target_slot_id, p_motivo);
          v_reasignados := v_reasignados + v_child_count;
        elsif v_source_slot.estado = 'apartado' then
          foreach v_source_slot_id in array v_source_slot_ids loop
            perform public.admin_liberar_apartado(v_source_slot_id);
          end loop;
          v_liberados := v_liberados + coalesce(array_length(v_source_slot_ids, 1), 0);
        else
          perform public.admin_cancelar_bloque_completo(
            v_source_slot.fecha,
            v_source_slot.hora,
            v_source_slot.camara_id,
            v_source_slot.paciente_id,
            coalesce(p_motivo, 'Eliminacion de horario')
          );
          v_cancelados := v_cancelados + coalesce(array_length(v_source_slot_ids, 1), 0);
        end if;

        insert into public.horarios_eliminacion_auditoria_items (
          auditoria_id, agenda_tipo, unit_id, unit_type, accion, paciente_id, medico_id, tanda_id,
          source_slot_id, source_slot_ids, source_fecha, source_hora, source_camara_id, target_slot_id,
          snapshot
        )
        values (
          v_auditoria_id,
          'camaras',
          v_unit_id,
          v_unit_type,
          v_action,
          v_source_slot.paciente_id,
          v_source_slot.medico_id,
          v_source_slot.tanda_id,
          v_source_slot_id,
          coalesce(v_source_slot_ids, array[]::uuid[]),
          v_source_slot.fecha,
          v_source_slot.hora,
          v_source_slot.camara_id,
          v_target_slot_id,
          jsonb_build_object(
            'source_estado', v_source_slot.estado,
            'source_slot_ids', to_jsonb(v_source_slot_ids)
          )
        );
      else
        select * into v_source_slot from public.slots where id = v_source_slot_id for update;
        if v_source_slot.id is null then
          raise exception 'Turno origen inválido';
        end if;

        if v_action = 'reassign' then
          if v_target_slot_id is null then
            raise exception 'Falta destino para turno';
          end if;
          perform public.admin_mover_slot_por_eliminacion_horario(v_source_slot_id, v_target_slot_id, p_motivo);
          v_reasignados := v_reasignados + 1;
        elsif v_source_slot.estado = 'apartado' then
          perform public.admin_liberar_apartado(v_source_slot_id);
          v_liberados := v_liberados + 1;
        else
          perform public.admin_cancelar_slot(v_source_slot_id, coalesce(p_motivo, 'Eliminacion de horario'));
          v_cancelados := v_cancelados + 1;
        end if;

        insert into public.horarios_eliminacion_auditoria_items (
          auditoria_id, agenda_tipo, unit_id, unit_type, accion, paciente_id, medico_id, tanda_id,
          source_slot_id, source_slot_ids, source_fecha, source_hora, source_camara_id, source_lugar,
          target_slot_id, snapshot
        )
        values (
          v_auditoria_id,
          'camaras',
          v_unit_id,
          v_unit_type,
          v_action,
          v_source_slot.paciente_id,
          v_source_slot.medico_id,
          v_source_slot.tanda_id,
          v_source_slot_id,
          coalesce(v_source_slot_ids, array[v_source_slot_id]::uuid[]),
          v_source_slot.fecha,
          v_source_slot.hora,
          v_source_slot.camara_id,
          v_source_slot.lugar,
          v_target_slot_id,
          jsonb_build_object('source_estado', v_source_slot.estado)
        );
      end if;
    end loop;
  end loop;

  for v_deleted_slot in
    delete from public.slots
    where fecha >= current_date
      and hora = v_horario.hora
    returning *
  loop
    v_slots_eliminados := v_slots_eliminados + 1;
    perform public.admin_insert_historial_bloque(
      v_deleted_slot.fecha, v_deleted_slot.hora, v_deleted_slot.camara_id, null, v_deleted_slot.lugar,
      'eliminacion_horario_slot_eliminado', null, v_actor_profile_id, coalesce(p_motivo, 'Eliminacion de horario'),
      false, null, 'particular', null, null, null, null, null, false, null, null, null
    );
  end loop;

  delete from public.horarios_config
  where id = v_horario.id;

  update public.horarios_eliminacion_auditoria
  set reasignados_count = v_reasignados,
      cancelados_count = v_cancelados,
      liberados_count = v_liberados,
      slots_eliminados_count = v_slots_eliminados,
      resumen = jsonb_build_object(
        'horario', row_to_json(v_horario),
        'reasignados', v_reasignados,
        'cancelados', v_cancelados,
        'liberados', v_liberados,
        'slots_eliminados', v_slots_eliminados
      )
  where id = v_auditoria_id;

  return jsonb_build_object(
    'auditoria_id', v_auditoria_id,
    'reasignados', v_reasignados,
    'cancelados', v_cancelados,
    'liberados', v_liberados,
    'slots_eliminados', v_slots_eliminados
  );
end;
$$;


ALTER FUNCTION "public"."admin_eliminar_horario_config"("p_horario_id" integer, "p_resoluciones" "jsonb", "p_motivo" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_eliminar_nota_paciente"("p_nota_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_deleted_id uuid;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.can_pacientes_editar() THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  DELETE FROM public.notas_paciente
  WHERE id = p_nota_id
  RETURNING id INTO v_deleted_id;

  IF v_deleted_id IS NULL THEN
    RAISE EXCEPTION 'Nota no encontrada';
  END IF;

  RETURN v_deleted_id;
END;
$$;


