CREATE OR REPLACE FUNCTION "public"."admin_event_feed_filter_options"() RETURNS "jsonb"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select jsonb_build_object(
    'actors',
    coalesce((
      select jsonb_agg(
        jsonb_build_object(
          'id', actor_user_id,
          'label', actor_label
        )
        order by actor_label
      )
      from (
        select distinct on (e.actor_user_id)
          e.actor_user_id,
          coalesce(
            nullif(trim(p.nombre), ''),
            nullif(trim(e.actor_label), ''),
            'Sistema'
          ) as actor_label
        from public.admin_event_feed e
        left join public.perfiles p on p.id = e.actor_user_id
        where e.actor_user_id is not null
        order by
          e.actor_user_id,
          case
            when coalesce(
              nullif(trim(p.nombre), ''),
              nullif(trim(e.actor_label), ''),
              'Sistema'
            ) is distinct from 'Sistema'::text
            then 0
            else 1
          end,
          e.occurred_at desc,
          e.id desc
      ) actors
    ), '[]'::jsonb),
    'actions',
    coalesce((
      select jsonb_agg(
        jsonb_build_object(
          'code', action_code,
          'family', action_family,
          'label', label
        )
        order by label
      )
      from (
        select
          action_code,
          action_family,
          min(title) as label
        from public.admin_event_feed
        group by action_code, action_family
      ) action_options
    ), '[]'::jsonb)
  )
  where public.can_manage_admin_event_feed();
$$;


ALTER FUNCTION "public"."admin_event_feed_filter_options"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_event_from_catalog_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor_user_id uuid := public.auth_current_profile_id();
  v_actor_label text;
  v_row jsonb := case when tg_op = 'DELETE' then to_jsonb(old) else to_jsonb(new) end;
  v_entity_id text := coalesce(v_row->>'id', 'sin-id');
  v_name text := coalesce(v_row->>'nombre', v_row->>'hora', 'Registro');
  v_action_code text;
  v_title text;
  v_summary text;
  v_source_record_key text := format(
    '%s:%s:%s:%s',
    tg_table_name,
    lower(tg_op),
    v_entity_id,
    to_char(clock_timestamp() at time zone 'UTC', 'YYYYMMDDHH24MISSUS')
  );
begin
  if v_actor_user_id is not null then
    select nombre into v_actor_label
    from public.perfiles
    where id = v_actor_user_id;
  end if;

  if tg_table_name = 'medicos' then
    if tg_op = 'INSERT' then
      v_action_code := 'medico.creado';
      v_title := 'Médico creado';
      v_summary := coalesce(new.nombre, 'Médico sin nombre');
    elsif tg_op = 'UPDATE' and coalesce(old.activo, true) is distinct from coalesce(new.activo, true) then
      v_action_code := 'medico.estado_actualizado';
      v_title := 'Estado de médico actualizado';
      v_summary := coalesce(new.nombre, old.nombre, 'Médico') || case when new.activo then ' activado' else ' desactivado' end;
    else
      v_action_code := 'medico.actualizado';
      v_title := 'Médico actualizado';
      v_summary := coalesce(new.nombre, old.nombre, 'Médico');
    end if;
  elsif tg_table_name = 'camaras' then
    if tg_op = 'INSERT' then
      v_action_code := 'config.camara_creada';
      v_title := 'Cámara creada';
    else
      v_action_code := 'config.camara_actualizada';
      v_title := 'Cámara actualizada';
    end if;
    v_summary := trim(both ' ' from concat(
      v_name,
      case when v_row ? 'capacidad' then ' Â· capacidad ' || coalesce(v_row->>'capacidad', '') else '' end,
      case when v_row ? 'activa' then ' Â· ' || case when coalesce((v_row->>'activa')::boolean, true) then 'activa' else 'inactiva' end else '' end
    ));
  elsif tg_table_name = 'obras_sociales' then
    v_action_code := case when tg_op = 'INSERT' then 'config.obra_social_creada' else 'config.obra_social_actualizada' end;
    v_title := case when tg_op = 'INSERT' then 'Obra social creada' else 'Obra social actualizada' end;
    v_summary := v_name;
  elsif tg_table_name = 'referentes' then
    v_action_code := case when tg_op = 'INSERT' then 'config.referente_creado' else 'config.referente_actualizado' end;
    v_title := case when tg_op = 'INSERT' then 'Referente creado' else 'Referente actualizado' end;
    v_summary := v_name;
  elsif tg_table_name = 'campos_config' then
    v_action_code := case
      when tg_op = 'INSERT' then 'config.campo_creado'
      when tg_op = 'DELETE' then 'config.campo_eliminado'
      else 'config.campo_actualizado'
    end;
    v_title := case
      when tg_op = 'INSERT' then 'Campo configurable creado'
      when tg_op = 'DELETE' then 'Campo configurable eliminado'
      else 'Campo configurable actualizado'
    end;
    v_summary := v_name;
  elsif tg_table_name = 'horarios_config' then
    v_action_code := case when tg_op = 'INSERT' then 'config.horario_creado' else 'config.horario_actualizado' end;
    v_title := case when tg_op = 'INSERT' then 'Horario creado' else 'Horario actualizado' end;
    v_summary := coalesce(v_row->>'hora', 'Horario');
  elsif tg_table_name = 'consultas_horarios_config' then
    v_action_code := case when tg_op = 'INSERT' then 'config.consulta_horario_creado' else 'config.consulta_horario_actualizado' end;
    v_title := case when tg_op = 'INSERT' then 'Horario de consulta creado' else 'Horario de consulta actualizado' end;
    v_summary := coalesce(v_row->>'hora', 'Horario de consulta');
  else
    if tg_op = 'DELETE' then
      return old;
    end if;
    return new;
  end if;

  perform public.admin_append_event(
    now(),
    v_actor_user_id,
    v_actor_label,
    v_action_code,
    case when v_action_code like 'medico.%' then 'altas' else 'configuracion' end,
    tg_table_name,
    v_entity_id,
    null,
    null,
    null,
    case when tg_table_name = 'medicos' then v_entity_id::integer else null end,
    case when tg_table_name = 'medicos' then v_name else null end,
    v_title,
    v_summary,
    tg_table_name,
    v_source_record_key,
    jsonb_strip_nulls(jsonb_build_object(
      'operation', lower(tg_op),
      'before', case when tg_op in ('UPDATE', 'DELETE') then to_jsonb(old) else null end,
      'after', case when tg_op in ('INSERT', 'UPDATE') then to_jsonb(new) else null end
    ))
  );

  if tg_op = 'DELETE' then
    return old;
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."admin_event_from_catalog_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_event_from_historial_bloques"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor_label text;
  v_paciente_nombre text;
  v_medico_nombre text;
  v_camara_nombre text;
  v_action_code text;
  v_action_family text;
  v_title text;
  v_summary text;
begin
  if tg_op <> 'INSERT' then
    return new;
  end if;

  select nombre into v_actor_label from public.perfiles where id = new.realizado_por;
  select nombre into v_paciente_nombre from public.perfiles where id = new.paciente_id;
  select nombre into v_medico_nombre from public.medicos where id = new.medico_id;
  select nombre into v_camara_nombre from public.camaras where id = new.camara_id;

  v_action_code := case
    when new.accion in ('asignado', 'bloque_asignado') then 'turno.asignado'
    when new.accion = 'reasignado' then 'turno.reasignado'
    when new.accion in ('cancelado', 'bloque_cancelado', 'cancelado_por_whatsapp') then 'turno.cancelado'
    when new.accion = 'apartado' then 'turno.apartado'
    when new.accion = 'confirmado' then 'turno.confirmado'
    when new.accion = 'liberado' then 'turno.liberado'
    else 'turno.actualizado'
  end;

  v_action_family := case
    when v_action_code in ('turno.asignado', 'turno.reasignado', 'turno.confirmado') then 'turnos'
    when v_action_code = 'turno.cancelado' then 'cancelaciones'
    when v_action_code in ('turno.apartado', 'turno.liberado') then 'turnos'
    else 'turnos'
  end;

  v_title := case
    when v_action_code = 'turno.asignado' and new.accion = 'bloque_asignado' then 'Bloque asignado'
    when v_action_code = 'turno.asignado' then 'Turno asignado'
    when v_action_code = 'turno.reasignado' then 'Turno reasignado'
    when v_action_code = 'turno.cancelado' then 'Turno cancelado'
    when v_action_code = 'turno.apartado' then 'Turno apartado'
    when v_action_code = 'turno.confirmado' then 'Turno confirmado'
    when v_action_code = 'turno.liberado' then 'Turno liberado'
    else 'Turno actualizado'
  end;

  v_summary := trim(both ' ' from concat(
    coalesce(v_paciente_nombre, 'Paciente sin nombre'),
    ' - ',
    to_char(new.fecha, 'DD/MM/YYYY'),
    ' ',
    coalesce(new.hora, ''),
    ' hs',
    case when v_camara_nombre is not null then ' - ' || v_camara_nombre else '' end,
    case when new.motivo is not null then ' - ' || new.motivo else '' end
  ));

  perform public.admin_append_event(
    new.created_at,
    new.realizado_por,
    v_actor_label,
    v_action_code,
    v_action_family,
    case when new.tanda_id is not null then 'tanda' else 'slot' end,
    coalesce(new.tanda_id::text, new.slot_id::text, new.id::text),
    'camaras',
    new.paciente_id,
    v_paciente_nombre,
    new.medico_id,
    v_medico_nombre,
    v_title,
    v_summary,
    'historial_bloques',
    new.id::text,
    jsonb_strip_nulls(jsonb_build_object(
      'accion_original', new.accion,
      'fecha', new.fecha,
      'hora', new.hora,
      'camara_id', new.camara_id,
      'camara_nombre', v_camara_nombre,
      'slot_id', new.slot_id,
      'lugar', new.lugar,
      'motivo', new.motivo,
      'tanda_id', new.tanda_id,
      'medico_id', new.medico_id,
      'medico_nombre', v_medico_nombre
    ))
  );

  return new;
end;
$$;


ALTER FUNCTION "public"."admin_event_from_historial_bloques"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_event_from_historial_consultas"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
