    AS $$
declare
  v_actor_label text;
  v_paciente_nombre text;
  v_medico_nombre text;
  v_action_code text;
  v_action_family text;
  v_title text;
  v_summary text;
begin
  if tg_op <> 'INSERT' then
    return new;
  end if;

  if new.accion = 'reprogramada_origen' then
    return new;
  end if;

  select nombre into v_actor_label from public.perfiles where id = new.realizado_por;
  select nombre into v_paciente_nombre from public.perfiles where id = new.paciente_id;
  select nombre into v_medico_nombre from public.medicos where id = new.medico_id;

  v_action_code := case
    when new.accion = 'confirmada' then 'consulta.asignada'
    when new.accion = 'cancelada' then 'consulta.cancelada'
    when new.accion = 'reprogramada_destino' then 'consulta.reprogramada'
    when new.accion = 'cerrada_completada' then 'consulta.cerrada'
    when new.accion = 'cerrada_ausente' then 'consulta.cerrada'
    else 'consulta.actualizada'
  end;

  v_action_family := case
    when v_action_code in ('consulta.asignada', 'consulta.reprogramada', 'consulta.cerrada') then 'consultas'
    when v_action_code = 'consulta.cancelada' then 'cancelaciones'
    else 'consultas'
  end;

  v_title := case
    when new.accion = 'confirmada' then 'Consulta asignada'
    when new.accion = 'cancelada' then 'Consulta cancelada'
    when new.accion = 'reprogramada_destino' then 'Consulta reprogramada'
    when new.accion = 'cerrada_completada' then 'Consulta completada'
    when new.accion = 'cerrada_ausente' then 'Consulta marcada como ausente'
    else 'Consulta actualizada'
  end;

  v_summary := trim(both ' ' from concat(
    coalesce(v_paciente_nombre, 'Paciente sin nombre'),
    ' - ',
    to_char(new.fecha, 'DD/MM/YYYY'),
    ' ',
    coalesce(new.hora, ''),
    ' hs',
    case when v_medico_nombre is not null then ' - ' || v_medico_nombre else '' end,
    case when new.motivo is not null then ' - ' || new.motivo else '' end
  ));

  perform public.admin_append_event(
    new.created_at,
    new.realizado_por,
    v_actor_label,
    v_action_code,
    v_action_family,
    'consulta',
    coalesce(new.consulta_slot_id::text, new.id::text),
    'consultas',
    new.paciente_id,
    v_paciente_nombre,
    new.medico_id,
    v_medico_nombre,
    v_title,
    v_summary,
    'historial_consultas',
    new.id::text,
    jsonb_strip_nulls(coalesce(new.detalle, '{}'::jsonb) || jsonb_build_object(
      'accion_original', new.accion,
      'fecha', new.fecha,
      'hora', new.hora,
      'motivo', new.motivo,
      'medico_nombre', v_medico_nombre
    ))
  );

  return new;
end;
$$;


