CREATE OR REPLACE FUNCTION "public"."admin_generar_consultas_slots_dia"("p_fecha" "date") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if not public.can_manage_consultas() then
    raise exception 'Prohibido';
  end if;
  perform public.generar_consultas_slots_dia(p_fecha);
  return 1;
end;
$$;


ALTER FUNCTION "public"."admin_generar_consultas_slots_dia"("p_fecha" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_generar_slots_dia"("p_fecha" "date") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_inserted integer := 0;
  v_rows integer;
  h record;
  cam record;
  lugar_idx integer;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_any_permission(array['turnos.read', 'turnos.asignar', 'turnos.tanda']::text[]) THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF p_fecha IS NULL THEN
    RAISE EXCEPTION 'Fecha invalida';
  END IF;

  FOR h IN
    SELECT hora
    FROM public.horarios_config
    WHERE activo = true
    ORDER BY orden
  LOOP
    FOR cam IN
      SELECT id, capacidad
      FROM public.camaras
      WHERE activa = true
      ORDER BY id
    LOOP
      FOR lugar_idx IN 0..(cam.capacidad - 1) LOOP
        INSERT INTO public.slots (fecha, hora, camara_id, lugar, estado)
        VALUES (p_fecha, h.hora, cam.id, lugar_idx, 'libre')
        ON CONFLICT (fecha, hora, camara_id, lugar) DO NOTHING;

        GET DIAGNOSTICS v_rows = ROW_COUNT;
        v_inserted := v_inserted + v_rows;
      END LOOP;
    END LOOP;
  END LOOP;

  RETURN v_inserted;
END;
$$;


ALTER FUNCTION "public"."admin_generar_slots_dia"("p_fecha" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_generar_slots_hasta_fin_junio"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_fecha date := current_date;
  v_limite date := make_date(EXTRACT(YEAR FROM current_date)::integer, 6, 30);
  v_total integer := 0;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_any_permission(array['turnos.read', 'turnos.asignar', 'turnos.tanda']::text[]) THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF v_fecha > v_limite THEN
    RETURN 0;
  END IF;

  WHILE v_fecha <= v_limite LOOP
    v_total := v_total + public.admin_generar_slots_dia(v_fecha);
    v_fecha := v_fecha + 1;
  END LOOP;

  RETURN v_total;
END;
$$;


ALTER FUNCTION "public"."admin_generar_slots_hasta_fin_junio"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_get_cierre_diario_detalle"("p_fecha" "date" DEFAULT NULL::"date", "p_cierre_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("cierre_id" "uuid", "slot_id" "uuid", "turno_fuera_horario_id" "uuid", "slot_ids" "uuid"[], "paciente_id" "uuid", "fecha" "date", "hora" "text", "camara_id" integer, "paciente_numero_dia" integer, "nombre_paciente" "text", "sesion_numero" integer, "modalidad_cobro" "public"."modalidad_cobro_turno", "obra_social_id" integer, "obra_social_nombre" "text", "obra_social_abreviatura" "text", "importe" numeric, "numero_autorizacion" "text", "es_nuevo_ingreso" boolean, "medico_id" integer, "medico_nombre" "text", "es_monoxido" boolean, "es_oxibarica" boolean, "asistio" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_effective_cierre_id uuid;
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('turnos.cierre_diario') then
    raise exception 'Prohibido';
  end if;

  if p_cierre_id is not null then
    v_effective_cierre_id := p_cierre_id;
  else
    select id into v_effective_cierre_id
    from public.cierres_diarios cierre
    where cierre.fecha = p_fecha;
  end if;

  if v_effective_cierre_id is null then
    return;
  end if;

  return query
  select
    detalle.cierre_id,
    detalle.slot_id,
    detalle.turno_fuera_horario_id,
    detalle.slot_ids,
    detalle.paciente_id,
    detalle.fecha,
    detalle.hora,
    detalle.camara_id,
    detalle.paciente_numero_dia,
    detalle.nombre_paciente,
    detalle.sesion_numero,
    detalle.modalidad_cobro,
    detalle.obra_social_id,
    detalle.obra_social_nombre,
    detalle.obra_social_abreviatura,
    detalle.importe,
    detalle.numero_autorizacion,
    detalle.es_nuevo_ingreso,
    detalle.medico_id,
    detalle.medico_nombre,
    detalle.es_monoxido,
    detalle.es_oxibarica,
    detalle.asistio
  from public.cierre_diario_detalles detalle
  where detalle.cierre_id = v_effective_cierre_id
  order by
    detalle.paciente_numero_dia,
    detalle.hora,
    detalle.camara_id nulls last,
    detalle.nombre_paciente,
    detalle.slot_id,
    detalle.turno_fuera_horario_id;
end;
$$;


