  FROM public.cierres_diarios c
  LEFT JOIN public.cierre_diario_detalles d ON d.cierre_id = c.id
  WHERE c.fecha = p_fecha
  GROUP BY c.id, c.fecha, c.estado, c.cerrado_por, c.cerrado_at;
