CREATE OR REPLACE FUNCTION "public"."admin_get_cierre_mensual_export"("p_anio" integer, "p_mes" integer) RETURNS TABLE("cierre_id" "uuid", "slot_id" "uuid", "turno_fuera_horario_id" "uuid", "paciente_id" "uuid", "fecha" "date", "hora" "text", "camara_id" integer, "paciente_numero_dia" integer, "nombre_paciente" "text", "sesion_numero_mes" integer, "modalidad_cobro" "public"."modalidad_cobro_turno", "obra_social_id" integer, "obra_social_nombre" "text", "obra_social_abreviatura" "text", "importe" numeric, "numero_autorizacion" "text", "es_nuevo_ingreso" boolean, "medico_id" integer, "medico_nombre" "text", "es_monoxido" boolean, "es_oxibarica" boolean, "factura_numero" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_fecha_inicio date;
  v_fecha_fin date;
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('turnos.cierre_diario') then
    raise exception 'Prohibido';
  end if;

  if p_mes is null or p_mes < 1 or p_mes > 12 then
    raise exception 'Mes invalido';
  end if;
  if p_anio is null or p_anio < 2000 or p_anio > 2100 then
    raise exception 'Anio invalido';
  end if;

  v_fecha_inicio := make_date(p_anio, p_mes, 1);
  v_fecha_fin := (v_fecha_inicio + interval '1 month - 1 day')::date;

  return query
  select
    detalle.cierre_id,
    detalle.slot_id,
    detalle.turno_fuera_horario_id,
    detalle.paciente_id,
    detalle.fecha,
    detalle.hora,
    detalle.camara_id,
    detalle.paciente_numero_dia,
    detalle.nombre_paciente,
    coalesce(detalle.sesion_numero_historico, detalle.sesion_numero) as sesion_numero_mes,
    detalle.modalidad_cobro,
    detalle.obra_social_id,
    detalle.obra_social_nombre,
    detalle.obra_social_abreviatura,
    detalle.importe,
    detalle.numero_autorizacion,
    detalle.es_nuevo_ingreso,
    detalle.medico_id,
    detalle.medico_nombre,
    detalle.es_monoxido,
    detalle.es_oxibarica,
    ''::text as factura_numero
  from public.cierre_diario_detalles detalle
  join public.cierres_diarios cierre on cierre.id = detalle.cierre_id
  where cierre.estado = 'cerrado'
    and detalle.asistio = true
    and detalle.fecha >= v_fecha_inicio
    and detalle.fecha <= v_fecha_fin
  order by
    detalle.fecha,
    detalle.paciente_numero_dia,
    detalle.hora,
    detalle.camara_id nulls last,
    detalle.slot_id,
    detalle.turno_fuera_horario_id;
end;
$$;


ALTER FUNCTION "public"."admin_get_cierre_mensual_export"("p_anio" integer, "p_mes" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_get_disponibilidad_tanda_detalle_mes"("p_fecha_inicio" "date", "p_fecha_fin" "date", "p_paciente_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("fecha" "date", "hora" "text", "camara_id" integer, "camara_nombre" "text", "capacidad" integer, "libres_count" integer, "tiene_disponibilidad" boolean, "tiene_bloque_completo_posible" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_fecha date;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT (
    public.is_admin_authenticated()
    OR public.can_turnos_cancelar()
    OR public.can_turnos_reprogramar()
    OR public.can_turnos_tanda()
    OR EXISTS (
      SELECT 1
      FROM public.perfiles p
      WHERE p.id = v_user_id
        AND p.rol = 'admin'
    )
  ) THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF p_fecha_inicio IS NULL OR p_fecha_fin IS NULL OR p_fecha_inicio > p_fecha_fin THEN
    RAISE EXCEPTION 'Rango de fechas invalido';
  END IF;

  v_fecha := p_fecha_inicio;
  WHILE v_fecha <= p_fecha_fin LOOP
    PERFORM public.admin_generar_slots_dia(v_fecha);
    v_fecha := v_fecha + 1;
  END LOOP;

  RETURN QUERY
  WITH dias AS (
    SELECT generate_series(p_fecha_inicio, p_fecha_fin, interval '1 day')::date AS fecha
  ),
  horarios_activos AS (
    SELECT h.hora
    FROM public.horarios_config h
    WHERE h.activo = true
  ),
  camaras_activas AS (
    SELECT c.id, c.nombre, c.capacidad
    FROM public.camaras c
    WHERE c.activa = true
  ),
  paciente_ocupados AS (
    SELECT
      s.fecha,
      s.hora
    FROM public.slots s
    WHERE p_paciente_id IS NOT NULL
      AND s.fecha BETWEEN p_fecha_inicio AND p_fecha_fin
      AND s.paciente_id = p_paciente_id
      AND s.estado IN ('ocupado', 'apartado')
  ),
  horas_bloqueadas_paciente AS (
    SELECT po.fecha, po.hora
    FROM paciente_ocupados po
    UNION
    SELECT po.fecha, to_char((po.hora::time - interval '1 hour'), 'HH24:MI')
    FROM paciente_ocupados po
    UNION
    SELECT po.fecha, to_char((po.hora::time + interval '1 hour'), 'HH24:MI')
    FROM paciente_ocupados po
  ),
  combinaciones AS (
    SELECT
      d.fecha,
      h.hora,
      c.id AS camara_id,
      c.nombre AS camara_nombre,
      c.capacidad
    FROM dias d
    CROSS JOIN horarios_activos h
    CROSS JOIN camaras_activas c
  ),
  slots_activos AS (
    SELECT
      s.fecha,
      s.hora,
      s.camara_id,
      s.estado
    FROM public.slots s
    JOIN public.camaras c
      ON c.id = s.camara_id
     AND c.activa = true
    JOIN public.horarios_config h
      ON h.hora = s.hora
     AND h.activo = true
    WHERE s.fecha BETWEEN p_fecha_inicio AND p_fecha_fin
  )
  SELECT
    c.fecha,
    c.hora,
    c.camara_id,
    c.camara_nombre,
    c.capacidad,
    COUNT(*) FILTER (
      WHERE sa.estado IN ('libre', 'cancelado')
        AND hbp.hora IS NULL
    )::integer AS libres_count,
    COUNT(*) FILTER (
      WHERE sa.estado IN ('libre', 'cancelado')
        AND hbp.hora IS NULL
    ) > 0 AS tiene_disponibilidad,
    COUNT(*) FILTER (
      WHERE sa.estado IN ('libre', 'cancelado')
        AND hbp.hora IS NULL
    ) = c.capacidad AND c.capacidad > 0 AS tiene_bloque_completo_posible
  FROM combinaciones c
  LEFT JOIN slots_activos sa
    ON sa.fecha = c.fecha
   AND sa.hora = c.hora
   AND sa.camara_id = c.camara_id
  LEFT JOIN horas_bloqueadas_paciente hbp
    ON hbp.fecha = c.fecha
   AND hbp.hora = c.hora
  GROUP BY c.fecha, c.hora, c.camara_id, c.camara_nombre, c.capacidad
  ORDER BY c.fecha, c.hora, c.camara_id;
END;
$$;


ALTER FUNCTION "public"."admin_get_disponibilidad_tanda_detalle_mes"("p_fecha_inicio" "date", "p_fecha_fin" "date", "p_paciente_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_get_disponibilidad_tanda_mes"("p_fecha_inicio" "date", "p_fecha_fin" "date", "p_paciente_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("fecha" "date", "tiene_disponibilidad" boolean, "horas_disponibles_count" integer, "tiene_bloque_completo_posible" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_fecha date;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT (
    public.is_admin_authenticated()
    OR public.can_turnos_cancelar()
    OR public.can_turnos_tanda()
    OR EXISTS (
      SELECT 1
      FROM public.perfiles p
      WHERE p.id = v_user_id
        AND p.rol = 'admin'
    )
  ) THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF p_fecha_inicio IS NULL OR p_fecha_fin IS NULL OR p_fecha_inicio > p_fecha_fin THEN
    RAISE EXCEPTION 'Rango de fechas invalido';
  END IF;

  v_fecha := p_fecha_inicio;
  WHILE v_fecha <= p_fecha_fin LOOP
    PERFORM public.admin_generar_slots_dia(v_fecha);
    v_fecha := v_fecha + 1;
  END LOOP;

  RETURN QUERY
  WITH dias AS (
    SELECT generate_series(p_fecha_inicio, p_fecha_fin, interval '1 day')::date AS fecha
  ),
  paciente_ocupados AS (
    SELECT
      s.fecha,
      s.hora
    FROM public.slots s
    WHERE p_paciente_id IS NOT NULL
      AND s.fecha BETWEEN p_fecha_inicio AND p_fecha_fin
      AND s.paciente_id = p_paciente_id
      AND s.estado IN ('ocupado', 'apartado')
  ),
  horas_bloqueadas_paciente AS (
    SELECT po.fecha, po.hora
    FROM paciente_ocupados po
    UNION
    SELECT po.fecha, to_char((po.hora::time - interval '1 hour'), 'HH24:MI')
    FROM paciente_ocupados po
    UNION
    SELECT po.fecha, to_char((po.hora::time + interval '1 hour'), 'HH24:MI')
    FROM paciente_ocupados po
  ),
  slots_activos AS (
    SELECT
      s.fecha,
      s.hora,
      s.camara_id,
      s.estado,
      c.capacidad
    FROM public.slots s
    JOIN public.camaras c
      ON c.id = s.camara_id
     AND c.activa = true
    JOIN public.horarios_config h
      ON h.hora = s.hora
     AND h.activo = true
    WHERE s.fecha BETWEEN p_fecha_inicio AND p_fecha_fin
  ),
  horas_disponibles AS (
    SELECT sa.fecha, sa.hora
    FROM slots_activos sa
    LEFT JOIN horas_bloqueadas_paciente hbp
      ON hbp.fecha = sa.fecha
     AND hbp.hora = sa.hora
    WHERE sa.estado IN ('libre', 'cancelado')
      AND hbp.hora IS NULL
    GROUP BY sa.fecha, sa.hora
  ),
  bloques_posibles AS (
    SELECT sa.fecha, sa.hora, sa.camara_id
    FROM slots_activos sa
    LEFT JOIN horas_bloqueadas_paciente hbp
      ON hbp.fecha = sa.fecha
     AND hbp.hora = sa.hora
    WHERE hbp.hora IS NULL
    GROUP BY sa.fecha, sa.hora, sa.camara_id, sa.capacidad
    HAVING COUNT(*) FILTER (WHERE sa.estado IN ('libre', 'cancelado')) = MAX(sa.capacidad)
  )
  SELECT
    d.fecha,
    COALESCE(COUNT(DISTINCT hd.hora) > 0, false) AS tiene_disponibilidad,
    COUNT(DISTINCT hd.hora)::integer AS horas_disponibles_count,
    COALESCE(COUNT(DISTINCT ROW(bp.hora, bp.camara_id)) > 0, false) AS tiene_bloque_completo_posible
  FROM dias d
  LEFT JOIN horas_disponibles hd
    ON hd.fecha = d.fecha
  LEFT JOIN bloques_posibles bp
    ON bp.fecha = d.fecha
  GROUP BY d.fecha
  ORDER BY d.fecha;
END;
$$;


ALTER FUNCTION "public"."admin_get_disponibilidad_tanda_mes"("p_fecha_inicio" "date", "p_fecha_fin" "date", "p_paciente_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_insert_historial_bloque"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_slot_id" "uuid", "p_lugar" integer, "p_accion" "text", "p_paciente_id" "uuid", "p_realizado_por" "uuid", "p_motivo" "text" DEFAULT NULL::"text", "p_referido_tercero" boolean DEFAULT false, "p_modalidad_cobro" "public"."modalidad_cobro_turno" DEFAULT 'particular'::"public"."modalidad_cobro_turno") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO public.historial_bloques (
    fecha,
    hora,
    camara_id,
    slot_id,
    lugar,
    accion,
    paciente_id,
    realizado_por,
    motivo,
    referido_tercero,
    modalidad_cobro
  )
  VALUES (
    p_fecha,
    p_hora,
    p_camara_id,
    p_slot_id,
    p_lugar,
    p_accion,
    p_paciente_id,
    p_realizado_por,
    nullif(trim(coalesce(p_motivo, '')), ''),
    coalesce(p_referido_tercero, false),
    coalesce(p_modalidad_cobro, 'particular')
  );
END;
$$;


