    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO public.historial_bloques (
    fecha,
    hora,
    camara_id,
    slot_id,
    lugar,
    accion,
    paciente_id,
    realizado_por,
    motivo,
    referido_tercero,
    modalidad_cobro,
    obra_social_id,
