    obra_social_validada_at
  )
  VALUES (
    p_fecha,
    p_hora,
    p_camara_id,
    p_slot_id,
    p_lugar,
    p_accion,
    p_paciente_id,
    p_realizado_por,
    nullif(trim(coalesce(p_motivo, '')), ''),
    coalesce(p_referido_tercero, false),
    coalesce(p_modalidad_cobro, 'particular'),
    p_obra_social_id,
    nullif(trim(coalesce(p_numero_autorizacion, '')), ''),
    p_medico_id,
    coalesce(p_es_nuevo_ingreso, false),
    p_obra_social_validada_por,
    p_obra_social_validada_at
  );
END;
$$;


ALTER FUNCTION "public"."admin_insert_historial_bloque"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_slot_id" "uuid", "p_lugar" integer, "p_accion" "text", "p_paciente_id" "uuid", "p_realizado_por" "uuid", "p_motivo" "text", "p_referido_tercero" boolean, "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer, "p_numero_autorizacion" "text", "p_medico_id" integer, "p_es_nuevo_ingreso" boolean, "p_obra_social_validada_por" "uuid", "p_obra_social_validada_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_insert_historial_bloque"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_slot_id" "uuid", "p_lugar" integer, "p_accion" "text", "p_paciente_id" "uuid", "p_realizado_por" "uuid", "p_motivo" "text" DEFAULT NULL::"text", "p_referido_tercero" boolean DEFAULT false, "p_referente_id" integer DEFAULT NULL::integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno" DEFAULT 'particular'::"public"."modalidad_cobro_turno", "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_autorizacion" "text" DEFAULT NULL::"text", "p_sesiones_autorizadas" integer DEFAULT NULL::integer, "p_ciclo_obra_social_id" "uuid" DEFAULT NULL::"uuid", "p_medico_id" integer DEFAULT NULL::integer, "p_es_nuevo_ingreso" boolean DEFAULT false, "p_obra_social_validada_por" "uuid" DEFAULT NULL::"uuid", "p_obra_social_validada_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_tanda_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_tanda_id uuid := p_tanda_id;
  v_realizado_por uuid := p_realizado_por;
  v_profile_id uuid := public.auth_current_profile_id();
begin
  if v_tanda_id is null and p_slot_id is not null then
    select s.tanda_id
    into v_tanda_id
    from public.slots as s
    where s.id = p_slot_id;
  end if;

  if v_realizado_por is null or not exists (
    select 1 from public.perfiles p where p.id = v_realizado_por
  ) then
    v_realizado_por := v_profile_id;
  end if;

  if v_realizado_por is null then
    raise exception 'Perfil no encontrado';
  end if;

  insert into public.historial_bloques (
    id,
    fecha, hora, camara_id, slot_id, lugar, accion, paciente_id, realizado_por, motivo,
    referido_tercero, referente_id, modalidad_cobro, obra_social_id, numero_autorizacion,
    sesiones_autorizadas, ciclo_obra_social_id, medico_id, es_nuevo_ingreso,
    obra_social_validada_por, obra_social_validada_at, tanda_id
  )
  values (
    gen_random_uuid(),
    p_fecha, p_hora, p_camara_id, p_slot_id, p_lugar, p_accion, p_paciente_id, v_realizado_por,
    nullif(trim(coalesce(p_motivo, '')), ''), coalesce(p_referido_tercero, false), p_referente_id,
    coalesce(p_modalidad_cobro, 'particular'), p_obra_social_id,
    nullif(trim(coalesce(p_numero_autorizacion, '')), ''), p_sesiones_autorizadas,
    p_ciclo_obra_social_id, p_medico_id, coalesce(p_es_nuevo_ingreso, false),
    p_obra_social_validada_por, p_obra_social_validada_at, v_tanda_id
  );
end;
$$;


ALTER FUNCTION "public"."admin_insert_historial_bloque"("p_fecha" "date", "p_hora" "text", "p_camara_id" integer, "p_slot_id" "uuid", "p_lugar" integer, "p_accion" "text", "p_paciente_id" "uuid", "p_realizado_por" "uuid", "p_motivo" "text", "p_referido_tercero" boolean, "p_referente_id" integer, "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer, "p_numero_autorizacion" "text", "p_sesiones_autorizadas" integer, "p_ciclo_obra_social_id" "uuid", "p_medico_id" integer, "p_es_nuevo_ingreso" boolean, "p_obra_social_validada_por" "uuid", "p_obra_social_validada_at" timestamp with time zone, "p_tanda_id" "uuid") OWNER TO "postgres";


