    "detalle" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "public"."historial_consultas" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_insert_historial_consulta"("p_consulta_slot_id" "uuid", "p_fecha" "date", "p_hora" "text", "p_accion" "text", "p_paciente_id" "uuid", "p_medico_id" integer, "p_realizado_por" "uuid", "p_motivo" "text" DEFAULT NULL::"text", "p_detalle" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "public"."historial_consultas"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_result public.historial_consultas%rowtype;
begin
  insert into public.historial_consultas (
    consulta_slot_id,
    fecha,
    hora,
    accion,
    paciente_id,
    medico_id,
    realizado_por,
    motivo,
    detalle
  )
  values (
    p_consulta_slot_id,
    p_fecha,
    p_hora,
    p_accion,
    p_paciente_id,
    p_medico_id,
    p_realizado_por,
    p_motivo,
    coalesce(p_detalle, '{}'::jsonb)
  )
  returning * into v_result;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_insert_historial_consulta"("p_consulta_slot_id" "uuid", "p_fecha" "date", "p_hora" "text", "p_accion" "text", "p_paciente_id" "uuid", "p_medico_id" integer, "p_realizado_por" "uuid", "p_motivo" "text", "p_detalle" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_liberar_apartado"("p_slot_id" "uuid") RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_result public.slots%ROWTYPE;
  v_current_slot public.slots%ROWTYPE;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;
  IF NOT public.auth_has_any_permission(array['turnos.tanda', 'turnos.reprogramar']::text[]) THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  SELECT * INTO v_current_slot FROM public.slots WHERE id = p_slot_id;
  IF v_current_slot.id IS NULL THEN
    RAISE EXCEPTION 'Slot no encontrado';
  END IF;
  IF v_current_slot.estado <> 'apartado' THEN
    RAISE EXCEPTION 'Solo se pueden liberar slots apartados';
  END IF;

  UPDATE public.slots
  SET estado = 'libre',
      paciente_id = null,
      apartado_por = null,
      apartado_ts = null,
      referido_tercero = false,
      modalidad_cobro = 'particular',
      obra_social_id = null,
      numero_autorizacion = null,
      medico_id = null,
      es_nuevo_ingreso = false,
      obra_social_validada_por = null,
      obra_social_validada_at = null,
      es_monoxido = false,
      monoxido_orden_medica = false,
      monoxido_resumen_clinico = false
  WHERE id = p_slot_id
  RETURNING * INTO v_result;

  IF v_result.id IS NULL THEN
    RAISE EXCEPTION 'Slot no encontrado';
  END IF;

  PERFORM public.admin_insert_historial_bloque(
    v_result.fecha, v_result.hora, v_result.camara_id, v_result.id, v_result.lugar, 'liberado', null, v_user_id,
    null, false, 'particular', null, null, null, false, null, null
  );
  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_liberar_apartado"("p_slot_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_list_event_feed"("p_limit" integer DEFAULT 50, "p_before_occurred_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_before_id" bigint DEFAULT NULL::bigint, "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_action_codes" "text"[] DEFAULT NULL::"text"[], "p_date_from" "date" DEFAULT NULL::"date", "p_date_to" "date" DEFAULT NULL::"date") RETURNS TABLE("id" bigint, "occurred_at" timestamp with time zone, "actor_user_id" "uuid", "actor_label" "text", "action_code" "text", "action_family" "text", "entity_type" "text", "entity_id" "text", "agenda_type" "text", "paciente_id" "uuid", "paciente_nombre" "text", "medico_id" integer, "medico_nombre" "text", "title" "text", "summary" "text", "metadata" "jsonb")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    e.id,
    e.occurred_at,
    e.actor_user_id,
    e.actor_label,
    e.action_code,
    e.action_family,
    e.entity_type,
    e.entity_id,
    e.agenda_type,
    e.paciente_id,
    e.paciente_nombre,
    e.medico_id,
    e.medico_nombre,
    e.title,
    e.summary,
    e.metadata
  from public.admin_event_feed e
  where public.can_manage_admin_event_feed()
    and (p_actor_user_id is null or e.actor_user_id = p_actor_user_id)
    and (
      p_action_codes is null
      or cardinality(p_action_codes) = 0
      or e.action_code = any(p_action_codes)
    )
    and (p_date_from is null or e.occurred_at >= p_date_from::timestamptz)
    and (p_date_to is null or e.occurred_at < (p_date_to + 1)::timestamptz)
    and (
      p_before_occurred_at is null
      or p_before_id is null
      or (e.occurred_at, e.id) < (p_before_occurred_at, p_before_id)
    )
  order by e.occurred_at desc, e.id desc
  limit greatest(1, least(coalesce(p_limit, 50), 100));
$$;


ALTER FUNCTION "public"."admin_list_event_feed"("p_limit" integer, "p_before_occurred_at" timestamp with time zone, "p_before_id" bigint, "p_actor_user_id" "uuid", "p_action_codes" "text"[], "p_date_from" "date", "p_date_to" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_list_roles"() RETURNS TABLE("id" bigint, "slug" "text", "nombre" "text", "descripcion" "text", "activo" boolean, "is_system" boolean, "is_staff" boolean, "default_home" "text", "permissions" "text"[])
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    r.id,
    r.slug,
    r.nombre,
    r.descripcion,
    r.activo,
    r.is_system,
    r.is_staff,
    r.default_home,
    coalesce(
      array_agg(p.key order by p.key) filter (where p.key is not null),
      array[]::text[]
    ) as permissions
  from public.rbac_roles r
  left join public.rbac_role_permissions rp
    on rp.role_id = r.id
    and rp.granted = true
  left join public.rbac_permissions p
    on p.id = rp.permission_id
  where public.auth_has_any_permission(array['rbac.read', 'rbac.manage']::text[])
  group by r.id, r.slug, r.nombre, r.descripcion, r.activo, r.is_system, r.is_staff, r.default_home
  order by r.is_system desc, r.slug asc;
$$;


ALTER FUNCTION "public"."admin_list_roles"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_list_staff_users"() RETURNS TABLE("id" "uuid", "nombre" "text", "email" "text", "auth_user_id" "uuid", "legacy_rol" "public"."rol_usuario", "is_active" boolean, "roles" "text"[], "primary_role" "text")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    p.id,
    p.nombre,
    p.email,
    p.auth_user_id,
    p.rol as legacy_rol,
    exists (
      select 1
      from public.rbac_user_roles ur_active
      join public.rbac_roles r_active on r_active.id = ur_active.role_id
      where ur_active.user_id = p.id
        and ur_active.expires_at is null
        and r_active.slug <> 'staff_inactivo'
    ) as is_active,
    coalesce(
      array_agg(distinct r.slug order by r.slug) filter (where r.slug is not null),
      array[]::text[]
    ) as roles,
    max(case when ur.is_primary then r.slug else null end) as primary_role
  from public.perfiles p
  join public.rbac_user_roles ur on ur.user_id = p.id and ur.expires_at is null
  join public.rbac_roles r on r.id = ur.role_id and r.is_staff = true
  where
    public.auth_has_permission('staff.read')
    or public.auth_has_permission('staff.manage')
    or public.auth_has_permission('rbac.read')
    or public.auth_has_permission('rbac.manage')
  group by p.id, p.nombre, p.email, p.auth_user_id, p.rol
  order by p.nombre asc nulls last, p.email asc nulls last;
$$;


ALTER FUNCTION "public"."admin_list_staff_users"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_listar_whatsapp_message_settings"() RETURNS SETOF "public"."whatsapp_message_settings"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.can_config_read() THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  RETURN QUERY
  SELECT *
  FROM public.whatsapp_message_settings
  ORDER BY key;
END;
$$;


ALTER FUNCTION "public"."admin_listar_whatsapp_message_settings"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_mover_bloque_por_eliminacion_horario"("p_source_slot_id" "uuid", "p_target_slot_id" "uuid", "p_motivo" "text" DEFAULT NULL::"text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_source public.slots%rowtype;
  v_target public.slots%rowtype;
  v_target_hour_order integer;
  v_source_slot_ids uuid[];
  v_target_slot_ids uuid[];
  v_source_count integer := 0;
  v_target_count integer := 0;
  v_index integer := 1;
  v_source_member public.slots%rowtype;
  v_target_member public.slots%rowtype;
begin
  if not public.can_manage_horarios_auditoria() then
    raise exception 'Prohibido';
  end if;

  select * into v_source from public.slots where id = p_source_slot_id for update;
  select * into v_target from public.slots where id = p_target_slot_id for update;

  if v_source.id is null or v_target.id is null then
    raise exception 'Bloque invalido';
  end if;

  if v_source.estado not in ('ocupado', 'apartado') or not coalesce(v_source.es_bloque_completo, false) then
    raise exception 'Bloque origen invalido';
  end if;

  if v_target.estado not in ('libre', 'cancelado') then
    raise exception 'Bloque destino invalido';
  end if;

  if not exists (
    select 1
    from public.camaras c
    where c.id = v_target.camara_id
      and c.activa = true
  ) then
    raise exception 'Camara inactiva';
  end if;

  select orden
  into v_target_hour_order
  from public.horarios_config
  where hora = v_target.hora
    and activo = true;

  if v_target_hour_order is null then
    raise exception 'Horario inactivo';
  end if;

  select array_agg(s.id order by s.lugar), count(*)
  into v_source_slot_ids, v_source_count
  from public.slots s
  where s.fecha = v_source.fecha
    and s.hora = v_source.hora
    and s.camara_id = v_source.camara_id
    and s.paciente_id = v_source.paciente_id
    and s.estado = v_source.estado
    and s.es_bloque_completo = true
    and s.tanda_id is not distinct from v_source.tanda_id;

  if coalesce(v_source_count, 0) = 0 then
    raise exception 'Bloque origen invalido';
  end if;

  if v_source.estado = 'ocupado' and exists (
    select 1
    from public.slots s
    join public.horarios_config hs on hs.hora = s.hora
    where s.fecha = v_target.fecha
      and s.paciente_id = v_source.paciente_id
      and s.estado = 'ocupado'
      and not (s.id = any(v_source_slot_ids))
      and abs(hs.orden - v_target_hour_order) <= 1
  ) then
    raise exception 'No se pueden asignar turnos en bloques seguidos';
  end if;

  select array_agg(s.id order by s.lugar), count(*)
  into v_target_slot_ids, v_target_count
  from public.slots s
  where s.fecha = v_target.fecha
    and s.hora = v_target.hora
    and s.camara_id = v_target.camara_id
    and s.estado in ('libre', 'cancelado')
    and not coalesce(s.es_bloque_completo, false);

  if coalesce(v_target_count, 0) < v_source_count then
    raise exception 'No hay capacidad suficiente en el bloque destino';
  end if;

  while v_index <= v_source_count loop
    select * into v_source_member from public.slots where id = v_source_slot_ids[v_index] for update;
    select * into v_target_member from public.slots where id = v_target_slot_ids[v_index] for update;

    update public.slots
    set paciente_id = v_source_member.paciente_id,
        estado = v_source_member.estado,
        es_tanda = v_source_member.es_tanda,
        tanda_id = v_source_member.tanda_id,
        es_bloque_completo = true,
        referido_tercero = coalesce(v_source_member.referido_tercero, false),
        referente_id = v_source_member.referente_id,
        modalidad_cobro = coalesce(v_source_member.modalidad_cobro, 'particular'),
        obra_social_id = v_source_member.obra_social_id,
        numero_autorizacion = v_source_member.numero_autorizacion,
        sesiones_autorizadas = v_source_member.sesiones_autorizadas,
        ciclo_obra_social_id = v_source_member.ciclo_obra_social_id,
        medico_id = v_source_member.medico_id,
        es_nuevo_ingreso = coalesce(v_source_member.es_nuevo_ingreso, false),
        obra_social_validada_por = v_source_member.obra_social_validada_por,
        obra_social_validada_at = v_source_member.obra_social_validada_at,
        apartado_por = case when v_source_member.estado = 'apartado' then v_source_member.apartado_por else null end,
        apartado_ts = case when v_source_member.estado = 'apartado' then v_source_member.apartado_ts else null end
    where id = v_target_member.id
    returning * into v_target_member;

    update public.slots
    set paciente_id = null,
        estado = case when v_source_member.estado = 'ocupado' then 'cancelado' else 'libre' end,
        es_tanda = false,
        tanda_id = null,
        es_bloque_completo = false,
        apartado_por = null,
        apartado_ts = null,
        referido_tercero = false,
        referente_id = null,
        modalidad_cobro = 'particular',
        obra_social_id = null,
        numero_autorizacion = null,
        sesiones_autorizadas = null,
        ciclo_obra_social_id = null,
        medico_id = null,
        es_nuevo_ingreso = false,
        obra_social_validada_por = null,
        obra_social_validada_at = null
    where id = v_source_member.id;

    perform public.admin_insert_historial_bloque(
      v_source_member.fecha, v_source_member.hora, v_source_member.camara_id, v_source_member.id, v_source_member.lugar,
      'eliminacion_horario_reasignado_origen', v_source_member.paciente_id, v_user_id,
      p_motivo, v_source_member.referido_tercero, v_source_member.referente_id, v_source_member.modalidad_cobro,
      v_source_member.obra_social_id, v_source_member.numero_autorizacion, v_source_member.sesiones_autorizadas,
      v_source_member.ciclo_obra_social_id, v_source_member.medico_id, v_source_member.es_nuevo_ingreso,
      v_source_member.obra_social_validada_por, v_source_member.obra_social_validada_at, v_source_member.tanda_id
    );

    perform public.admin_insert_historial_bloque(
      v_target_member.fecha, v_target_member.hora, v_target_member.camara_id, v_target_member.id, v_target_member.lugar,
      'eliminacion_horario_reasignado_destino', v_target_member.paciente_id, v_user_id,
      p_motivo, v_target_member.referido_tercero, v_target_member.referente_id, v_target_member.modalidad_cobro,
      v_target_member.obra_social_id, v_target_member.numero_autorizacion, v_target_member.sesiones_autorizadas,
      v_target_member.ciclo_obra_social_id, v_target_member.medico_id, v_target_member.es_nuevo_ingreso,
      v_target_member.obra_social_validada_por, v_target_member.obra_social_validada_at, v_target_member.tanda_id
    );

    v_index := v_index + 1;
  end loop;

  return v_source_count;
end;
$$;


ALTER FUNCTION "public"."admin_mover_bloque_por_eliminacion_horario"("p_source_slot_id" "uuid", "p_target_slot_id" "uuid", "p_motivo" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_mover_slot_por_eliminacion_horario"("p_source_slot_id" "uuid", "p_target_slot_id" "uuid", "p_motivo" "text" DEFAULT NULL::"text") RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_source public.slots%rowtype;
  v_target public.slots%rowtype;
  v_target_hour_order integer;
  v_result public.slots%rowtype;
begin
  if not public.can_manage_horarios_auditoria() then
    raise exception 'Prohibido';
  end if;

  select * into v_source from public.slots where id = p_source_slot_id for update;
  select * into v_target from public.slots where id = p_target_slot_id for update;

  if v_source.id is null or v_target.id is null or v_source.id = v_target.id then
    raise exception 'Slot invalido';
  end if;

  if v_source.fecha < current_date or v_target.fecha < current_date then
    raise exception 'Solo se pueden mover turnos futuros';
  end if;

  if v_source.estado not in ('ocupado', 'apartado') then
    raise exception 'Turno origen invalido';
  end if;

  if v_target.estado not in ('libre', 'cancelado') then
    raise exception 'Slot destino invalido';
  end if;

  if not exists (
    select 1
    from public.camaras c
    where c.id = v_target.camara_id
      and c.activa = true
  ) then
    raise exception 'Camara inactiva';
  end if;

  select orden
  into v_target_hour_order
  from public.horarios_config
  where hora = v_target.hora
    and activo = true;

  if v_target_hour_order is null then
    raise exception 'Horario inactivo';
  end if;

  if v_source.estado = 'ocupado' and exists (
    select 1
    from public.slots s
    join public.horarios_config hs on hs.hora = s.hora
    where s.fecha = v_target.fecha
      and s.paciente_id = v_source.paciente_id
      and s.estado = 'ocupado'
      and s.id <> v_source.id
      and abs(hs.orden - v_target_hour_order) <= 1
  ) then
    raise exception 'No se pueden asignar turnos en bloques seguidos';
  end if;

  update public.slots
  set paciente_id = v_source.paciente_id,
      estado = v_source.estado,
      es_tanda = v_source.es_tanda,
      tanda_id = v_source.tanda_id,
      es_bloque_completo = false,
      referido_tercero = coalesce(v_source.referido_tercero, false),
      referente_id = v_source.referente_id,
      modalidad_cobro = coalesce(v_source.modalidad_cobro, 'particular'),
      obra_social_id = v_source.obra_social_id,
      numero_autorizacion = v_source.numero_autorizacion,
      sesiones_autorizadas = v_source.sesiones_autorizadas,
      ciclo_obra_social_id = v_source.ciclo_obra_social_id,
      medico_id = v_source.medico_id,
      es_nuevo_ingreso = coalesce(v_source.es_nuevo_ingreso, false),
      obra_social_validada_por = v_source.obra_social_validada_por,
      obra_social_validada_at = v_source.obra_social_validada_at,
      apartado_por = case when v_source.estado = 'apartado' then v_source.apartado_por else null end,
      apartado_ts = case when v_source.estado = 'apartado' then v_source.apartado_ts else null end
  where id = v_target.id
  returning * into v_result;

  update public.slots
  set paciente_id = null,
      estado = case when v_source.estado = 'ocupado' then 'cancelado' else 'libre' end,
      es_tanda = false,
      tanda_id = null,
      es_bloque_completo = false,
      apartado_por = null,
      apartado_ts = null,
      referido_tercero = false,
      referente_id = null,
      modalidad_cobro = 'particular',
      obra_social_id = null,
      numero_autorizacion = null,
      sesiones_autorizadas = null,
      ciclo_obra_social_id = null,
      medico_id = null,
      es_nuevo_ingreso = false,
      obra_social_validada_por = null,
      obra_social_validada_at = null
  where id = v_source.id;

  perform public.admin_insert_historial_bloque(
    v_source.fecha, v_source.hora, v_source.camara_id, v_source.id, v_source.lugar,
    'eliminacion_horario_reasignado_origen', v_source.paciente_id, v_user_id,
    p_motivo, v_source.referido_tercero, v_source.referente_id, v_source.modalidad_cobro,
    v_source.obra_social_id, v_source.numero_autorizacion, v_source.sesiones_autorizadas,
    v_source.ciclo_obra_social_id, v_source.medico_id, v_source.es_nuevo_ingreso,
    v_source.obra_social_validada_por, v_source.obra_social_validada_at, v_source.tanda_id
  );

  perform public.admin_insert_historial_bloque(
    v_result.fecha, v_result.hora, v_result.camara_id, v_result.id, v_result.lugar,
    'eliminacion_horario_reasignado_destino', v_result.paciente_id, v_user_id,
    p_motivo, v_result.referido_tercero, v_result.referente_id, v_result.modalidad_cobro,
    v_result.obra_social_id, v_result.numero_autorizacion, v_result.sesiones_autorizadas,
    v_result.ciclo_obra_social_id, v_result.medico_id, v_result.es_nuevo_ingreso,
    v_result.obra_social_validada_por, v_result.obra_social_validada_at, v_result.tanda_id
  );

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_mover_slot_por_eliminacion_horario"("p_source_slot_id" "uuid", "p_target_slot_id" "uuid", "p_motivo" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_normalizar_numero_autorizacion_obra_social"("p_numero_autorizacion" "text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_numero text := upper(trim(coalesce(p_numero_autorizacion, '')));
BEGIN
  IF v_numero = '' THEN
    RETURN null;
  END IF;
  IF replace(v_numero, '.', '') = 'S/N' OR replace(v_numero, '/', '') = 'SN' THEN
    RETURN 'S/N';
  END IF;
  RETURN v_numero;
END;
$$;


ALTER FUNCTION "public"."admin_normalizar_numero_autorizacion_obra_social"("p_numero_autorizacion" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_normalizar_tipo_referente"("p_tipo" "text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_tipo text := lower(trim(coalesce(p_tipo, '')));
BEGIN
  IF v_tipo NOT IN ('doctor', 'agencia', 'otro') THEN
    RAISE EXCEPTION 'Tipo de referente invalido';
  END IF;
  RETURN v_tipo;
END;
$$;


ALTER FUNCTION "public"."admin_normalizar_tipo_referente"("p_tipo" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_paciente_tiene_historial_turnos"("p_paciente_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.can_pacientes_read() THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF p_paciente_id IS NULL OR NOT EXISTS (
    SELECT 1 FROM public.perfiles WHERE id = p_paciente_id AND rol = 'paciente'
  ) THEN
    RAISE EXCEPTION 'Paciente no valido';
  END IF;

  RETURN EXISTS (
    SELECT 1
    FROM public.sesiones s
    WHERE s.paciente_id = p_paciente_id
  ) OR EXISTS (
    SELECT 1
    FROM public.slots sl
    WHERE sl.paciente_id = p_paciente_id
      AND sl.estado = 'ocupado'
  );
END;
$$;


ALTER FUNCTION "public"."admin_paciente_tiene_historial_turnos"("p_paciente_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_permitir_reset_portal_paciente"("p_paciente_id" "uuid") RETURNS "public"."perfiles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_result public.perfiles%ROWTYPE;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.can_pacientes_portal_manage() THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  UPDATE public.perfiles
  SET requiere_reset_portal = true
  WHERE id = p_paciente_id
    AND rol = 'paciente'
    AND portal_habilitado = true
  RETURNING * INTO v_result;

  IF v_result.id IS NULL THEN
    RAISE EXCEPTION 'Paciente no encontrado';
  END IF;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_permitir_reset_portal_paciente"("p_paciente_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_preview_cierre_diario"("p_fecha" "date") RETURNS TABLE("slot_id" "uuid", "turno_fuera_horario_id" "uuid", "slot_ids" "uuid"[], "paciente_id" "uuid", "fecha" "date", "hora" "text", "camara_id" integer, "paciente_numero_dia" integer, "nombre_paciente" "text", "sesion_numero" integer, "modalidad_cobro" "public"."modalidad_cobro_turno", "obra_social_id" integer, "obra_social_nombre" "text", "obra_social_abreviatura" "text", "importe" numeric, "numero_autorizacion" "text", "sesiones_autorizadas" integer, "ciclo_obra_social_id" "uuid", "es_nuevo_ingreso" boolean, "medico_id" integer, "medico_nombre" "text", "es_monoxido" boolean, "es_oxibarica" boolean, "asistio" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('turnos.cierre_diario') then
    raise exception 'Prohibido';
  end if;

  return query
  select
    row_data.slot_id,
    row_data.turno_fuera_horario_id,
    row_data.slot_ids,
    row_data.paciente_id,
    row_data.fecha,
    row_data.hora,
    row_data.camara_id,
    row_data.paciente_numero_dia,
    row_data.nombre_paciente,
    row_data.sesion_numero,
    row_data.modalidad_cobro,
    row_data.obra_social_id,
    row_data.obra_social_nombre,
    row_data.obra_social_abreviatura,
    0::numeric(12,2) as importe,
    row_data.numero_autorizacion,
    row_data.sesiones_autorizadas,
    row_data.ciclo_obra_social_id,
    row_data.es_nuevo_ingreso,
    row_data.medico_id,
    row_data.medico_nombre,
    row_data.es_monoxido,
    row_data.es_oxibarica,
    true as asistio
  from public.admin_build_cierre_diario_preview_rows(p_fecha) row_data;
end;
$$;


ALTER FUNCTION "public"."admin_preview_cierre_diario"("p_fecha" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_preview_eliminar_consulta_horario_config"("p_horario_id" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_horario public.consultas_horarios_config%rowtype;
  v_items jsonb := '[]'::jsonb;
  v_free_count integer := 0;
  v_cancelled_count integer := 0;
  v_informational_count integer := 0;
  v_row record;
begin
  if not public.can_manage_consultas() then
    raise exception 'Prohibido';
  end if;

  select *
  into v_horario
  from public.consultas_horarios_config
  where id = p_horario_id;

  if v_horario.id is null then
    raise exception 'Horario no encontrado';
  end if;

  select count(*) into v_free_count
  from public.consultas_slots
  where fecha >= current_date
    and hora = v_horario.hora
    and estado = 'libre';

  select count(*) into v_cancelled_count
  from public.consultas_slots
  where fecha >= current_date
    and hora = v_horario.hora
    and estado = 'cancelada';

  select count(*) into v_informational_count
  from public.consultas_slots
  where fecha >= current_date
    and hora = v_horario.hora
    and paciente_id is not null
    and estado not in ('confirmada', 'completada', 'libre', 'cancelada');

  for v_row in
    select
      format('consulta:%s', c.id) as unit_id,
      c.id as source_slot_id,
      c.fecha,
      c.hora,
      c.estado,
      c.paciente_id,
      p.nombre as patient_name,
      c.medico_id,
      m.nombre as medico_nombre
    from public.consultas_slots c
    join public.perfiles p on p.id = c.paciente_id
    left join public.medicos m on m.id = c.medico_id
    where c.fecha >= current_date
      and c.hora = v_horario.hora
      and c.estado in ('confirmada', 'completada')
    order by c.fecha, c.hora
  loop
    v_items := v_items || jsonb_build_array(
      jsonb_build_object(
        'unit_id', v_row.unit_id,
        'unit_type', 'consulta',
        'patient_name', v_row.patient_name,
        'paciente_id', v_row.paciente_id,
        'medico_id', v_row.medico_id,
        'child_count', 1,
        'children', jsonb_build_array(
          jsonb_build_object(
            'source_slot_id', v_row.source_slot_id,
            'fecha', v_row.fecha,
            'hora', v_row.hora,
            'estado', v_row.estado,
            'paciente_id', v_row.paciente_id,
            'medico_id', v_row.medico_id,
            'medico_nombre', v_row.medico_nombre
          )
        )
      )
    );
  end loop;

  return jsonb_build_object(
    'horario', jsonb_build_object('id', v_horario.id, 'hora', v_horario.hora, 'orden', v_horario.orden, 'activo', v_horario.activo),
    'agenda_tipo', 'consultas',
    'stats', jsonb_build_object(
      'free_count', v_free_count,
      'cancelled_count', v_cancelled_count,
      'informational_count', v_informational_count,
      'affected_count', coalesce((
        select count(*)
        from public.consultas_slots c
        where c.fecha >= current_date
          and c.hora = v_horario.hora
          and c.estado in ('confirmada', 'completada')
      ), 0),
      'unit_count', jsonb_array_length(v_items)
    ),
    'items', v_items
  );
end;
$$;


ALTER FUNCTION "public"."admin_preview_eliminar_consulta_horario_config"("p_horario_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_preview_eliminar_horario_config"("p_horario_id" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_horario public.horarios_config%rowtype;
  v_free_count integer := 0;
  v_cancelled_count integer := 0;
  v_informational_count integer := 0;
  v_items jsonb := '[]'::jsonb;
  v_row record;
begin
  if not public.can_manage_horarios_auditoria() then
    raise exception 'Prohibido';
  end if;

  select *
  into v_horario
  from public.horarios_config
  where id = p_horario_id;

  if v_horario.id is null then
    raise exception 'Horario no encontrado';
  end if;

  select count(*) into v_free_count
  from public.slots
  where fecha >= current_date
    and hora = v_horario.hora
    and estado = 'libre';

  select count(*) into v_cancelled_count
  from public.slots
  where fecha >= current_date
    and hora = v_horario.hora
    and estado = 'cancelado';

  select count(*) into v_informational_count
  from public.slots
  where fecha >= current_date
    and hora = v_horario.hora
    and paciente_id is not null
    and estado not in ('ocupado', 'apartado', 'libre', 'cancelado');

  for v_row in
    with grouped as (
      select
        format('tanda:%s', s.tanda_id) as unit_id,
        s.tanda_id,
        (array_agg(s.paciente_id order by s.fecha, s.camara_id, s.lugar))[1] as paciente_id,
        max(p.nombre) as patient_name,
        jsonb_agg(
          jsonb_build_object(
            'source_slot_id', s.id,
            'fecha', s.fecha,
            'hora', s.hora,
            'camara_id', s.camara_id,
            'camara_nombre', c.nombre,
            'lugar', s.lugar,
            'estado', s.estado,
            'paciente_id', s.paciente_id
          )
          order by s.fecha, s.camara_id, s.lugar
        ) as children,
        count(*) as child_count
      from public.slots s
      join public.perfiles p on p.id = s.paciente_id
      join public.camaras c on c.id = s.camara_id
      where s.fecha >= current_date
        and s.hora = v_horario.hora
        and s.estado = 'ocupado'
        and s.es_tanda = true
        and s.es_bloque_completo = false
        and s.tanda_id is not null
      group by s.tanda_id
    )
    select * from grouped
  loop
    v_items := v_items || jsonb_build_array(
      jsonb_build_object(
        'unit_id', v_row.unit_id,
        'unit_type', 'tanda',
        'patient_name', v_row.patient_name,
        'paciente_id', v_row.paciente_id,
        'tanda_id', v_row.tanda_id,
        'child_count', v_row.child_count,
        'children', v_row.children
      )
    );
  end loop;

  for v_row in
    with bloque_ocurrencias as (
      select
        s.tanda_id,
        s.paciente_id,
        max(p.nombre) as patient_name,
        s.fecha,
        s.hora,
        s.camara_id,
        max(c.nombre) as camara_nombre,
        (array_agg(s.id order by s.lugar))[1] as source_slot_id,
        array_agg(s.id order by s.lugar) as source_slot_ids,
        count(*) as block_size
      from public.slots s
      join public.perfiles p on p.id = s.paciente_id
      join public.camaras c on c.id = s.camara_id
      where s.fecha >= current_date
        and s.hora = v_horario.hora
        and s.estado = 'ocupado'
        and s.es_bloque_completo = true
        and s.tanda_id is not null
      group by s.tanda_id, s.paciente_id, s.fecha, s.hora, s.camara_id
    ),
    grouped as (
      select
        format('bloque_tanda:%s', tanda_id) as unit_id,
        tanda_id,
        paciente_id,
        max(patient_name) as patient_name,
        jsonb_agg(
          jsonb_build_object(
            'source_slot_id', source_slot_id,
            'source_slot_ids', to_jsonb(source_slot_ids),
            'fecha', fecha,
            'hora', hora,
            'camara_id', camara_id,
            'camara_nombre', camara_nombre,
            'estado', 'ocupado',
            'paciente_id', paciente_id,
            'block_size', block_size
          )
          order by fecha, camara_id
        ) as children,
        count(*) as child_count
      from bloque_ocurrencias
      group by tanda_id, paciente_id
    )
    select * from grouped
  loop
    v_items := v_items || jsonb_build_array(
      jsonb_build_object(
        'unit_id', v_row.unit_id,
        'unit_type', 'bloque',
        'patient_name', v_row.patient_name,
        'paciente_id', v_row.paciente_id,
        'tanda_id', v_row.tanda_id,
        'child_count', v_row.child_count,
        'children', v_row.children
      )
    );
  end loop;

  for v_row in
    with grouped as (
      select
        format('bloque:%s:%s:%s:%s', s.paciente_id, s.fecha, s.camara_id, s.hora) as unit_id,
        s.paciente_id,
        max(p.nombre) as patient_name,
        s.fecha,
        s.hora,
        s.camara_id,
        max(c.nombre) as camara_nombre,
        (array_agg(s.id order by s.lugar))[1] as source_slot_id,
        array_agg(s.id order by s.lugar) as source_slot_ids,
        count(*) as block_size
      from public.slots s
      join public.perfiles p on p.id = s.paciente_id
      join public.camaras c on c.id = s.camara_id
      where s.fecha >= current_date
        and s.hora = v_horario.hora
        and s.estado = 'ocupado'
        and s.es_bloque_completo = true
        and s.tanda_id is null
      group by s.paciente_id, s.fecha, s.hora, s.camara_id
    )
    select * from grouped
  loop
    v_items := v_items || jsonb_build_array(
      jsonb_build_object(
        'unit_id', v_row.unit_id,
        'unit_type', 'bloque',
        'patient_name', v_row.patient_name,
        'paciente_id', v_row.paciente_id,
        'child_count', 1,
        'children', jsonb_build_array(
          jsonb_build_object(
            'source_slot_id', v_row.source_slot_id,
            'source_slot_ids', to_jsonb(v_row.source_slot_ids),
            'fecha', v_row.fecha,
            'hora', v_row.hora,
            'camara_id', v_row.camara_id,
            'camara_nombre', v_row.camara_nombre,
            'estado', 'ocupado',
            'paciente_id', v_row.paciente_id,
            'block_size', v_row.block_size
          )
        )
      )
    );
  end loop;

  for v_row in
    select
      format('slot:%s', s.id) as unit_id,
      s.id as source_slot_id,
      s.paciente_id,
      p.nombre as patient_name,
      s.fecha,
      s.hora,
      s.camara_id,
      c.nombre as camara_nombre,
      s.lugar,
      s.estado
    from public.slots s
    join public.perfiles p on p.id = s.paciente_id
    join public.camaras c on c.id = s.camara_id
    where s.fecha >= current_date
      and s.hora = v_horario.hora
      and s.estado = 'ocupado'
      and coalesce(s.es_tanda, false) = false
      and coalesce(s.es_bloque_completo, false) = false
    order by s.fecha, s.camara_id, s.lugar
  loop
    v_items := v_items || jsonb_build_array(
      jsonb_build_object(
        'unit_id', v_row.unit_id,
        'unit_type', 'individual',
        'patient_name', v_row.patient_name,
        'paciente_id', v_row.paciente_id,
        'child_count', 1,
        'children', jsonb_build_array(
          jsonb_build_object(
            'source_slot_id', v_row.source_slot_id,
            'fecha', v_row.fecha,
            'hora', v_row.hora,
            'camara_id', v_row.camara_id,
            'camara_nombre', v_row.camara_nombre,
            'lugar', v_row.lugar,
            'estado', v_row.estado,
            'paciente_id', v_row.paciente_id
          )
        )
      )
    );
  end loop;

  for v_row in
    select
      format('apartado:%s', s.id) as unit_id,
      s.id as source_slot_id,
      s.paciente_id,
      p.nombre as patient_name,
      s.fecha,
      s.hora,
      s.camara_id,
      c.nombre as camara_nombre,
      s.lugar,
      s.estado
    from public.slots s
    join public.perfiles p on p.id = s.paciente_id
    join public.camaras c on c.id = s.camara_id
    where s.fecha >= current_date
      and s.hora = v_horario.hora
      and s.estado = 'apartado'
    order by s.fecha, s.camara_id, s.lugar
  loop
    v_items := v_items || jsonb_build_array(
      jsonb_build_object(
        'unit_id', v_row.unit_id,
        'unit_type', 'apartado',
        'patient_name', v_row.patient_name,
        'paciente_id', v_row.paciente_id,
        'child_count', 1,
        'children', jsonb_build_array(
          jsonb_build_object(
            'source_slot_id', v_row.source_slot_id,
            'fecha', v_row.fecha,
            'hora', v_row.hora,
            'camara_id', v_row.camara_id,
            'camara_nombre', v_row.camara_nombre,
            'lugar', v_row.lugar,
            'estado', v_row.estado,
            'paciente_id', v_row.paciente_id
          )
        )
      )
    );
  end loop;

  return jsonb_build_object(
    'horario', jsonb_build_object('id', v_horario.id, 'hora', v_horario.hora, 'orden', v_horario.orden, 'activo', v_horario.activo),
    'agenda_tipo', 'camaras',
    'stats', jsonb_build_object(
      'free_count', v_free_count,
      'cancelled_count', v_cancelled_count,
      'informational_count', v_informational_count,
      'affected_count', coalesce((
        select count(*)
        from public.slots s
        where s.fecha >= current_date
          and s.hora = v_horario.hora
          and s.estado in ('ocupado', 'apartado')
      ), 0),
      'unit_count', jsonb_array_length(v_items)
    ),
    'items', v_items
  );
end;
$$;


ALTER FUNCTION "public"."admin_preview_eliminar_horario_config"("p_horario_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_reabrir_cierre_diario"("p_fecha" "date" DEFAULT NULL::"date", "p_cierre_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_effective_cierre_id uuid;
  v_affected_patients uuid[];
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('turnos.cierre_diario') then
    raise exception 'Prohibido';
  end if;

  if p_cierre_id is not null then
    v_effective_cierre_id := p_cierre_id;
  else
    select id into v_effective_cierre_id
    from public.cierres_diarios cierre
    where cierre.fecha = p_fecha;
  end if;

  if v_effective_cierre_id is null then
    raise exception 'Cierre diario no encontrado';
  end if;

  select array_agg(distinct detalle.paciente_id)
  into v_affected_patients
  from public.cierre_diario_detalles detalle
  where detalle.cierre_id = v_effective_cierre_id
    and detalle.asistio = true
    and detalle.paciente_id is not null;

  delete from public.sesiones
  where cierre_id = v_effective_cierre_id;

  delete from public.cierres_diarios
  where id = v_effective_cierre_id;

  if v_affected_patients is not null then
    update public.perfiles p
    set primera_sesion_efectivizada = exists (
      select 1 from public.sesiones s where s.paciente_id = p.id
    )
    where p.id = any(v_affected_patients);
  end if;

  return v_effective_cierre_id;
end;
$$;


ALTER FUNCTION "public"."admin_reabrir_cierre_diario"("p_fecha" "date", "p_cierre_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_reconciliar_capacidad_camara"("p_camara_id" integer, "p_capacidad_nueva" integer, "p_realizado_por" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_slot_origen public.slots%ROWTYPE;
  v_slot_destino public.slots%ROWTYPE;
  v_slot_eliminado public.slots%ROWTYPE;
  v_movidos integer := 0;
  v_cancelados integer := 0;
  v_apartados_liberados integer := 0;
  v_eliminados integer := 0;
BEGIN
  IF p_camara_id IS NULL OR p_capacidad_nueva IS NULL OR p_capacidad_nueva < 1 THEN
    RETURN jsonb_build_object('movidos', 0, 'cancelados', 0, 'apartados_liberados', 0, 'eliminados', 0);
  END IF;

  FOR v_slot_origen IN
    SELECT *
    FROM public.slots
    WHERE camara_id = p_camara_id
      AND fecha >= current_date
      AND lugar >= p_capacidad_nueva
      AND estado = 'ocupado'
    ORDER BY fecha, hora, lugar
  LOOP
    SELECT *
    INTO v_slot_destino
    FROM public.slots
    WHERE camara_id = p_camara_id
      AND fecha = v_slot_origen.fecha
      AND hora = v_slot_origen.hora
      AND lugar < p_capacidad_nueva
      AND estado IN ('libre', 'cancelado')
    ORDER BY lugar
    LIMIT 1;

    IF v_slot_destino.id IS NOT NULL THEN
      UPDATE public.slots
      SET paciente_id = v_slot_origen.paciente_id,
          estado = 'ocupado',
          es_tanda = v_slot_origen.es_tanda,
          tanda_id = v_slot_origen.tanda_id,
          es_bloque_completo = v_slot_origen.es_bloque_completo,
          apartado_por = null,
          apartado_ts = null,
          referido_tercero = v_slot_origen.referido_tercero,
          referente_id = v_slot_origen.referente_id,
          modalidad_cobro = v_slot_origen.modalidad_cobro,
          obra_social_id = v_slot_origen.obra_social_id,
          numero_autorizacion = v_slot_origen.numero_autorizacion,
          medico_id = v_slot_origen.medico_id,
          es_nuevo_ingreso = v_slot_origen.es_nuevo_ingreso,
          obra_social_validada_por = v_slot_origen.obra_social_validada_por,
          obra_social_validada_at = v_slot_origen.obra_social_validada_at
      WHERE id = v_slot_destino.id
      RETURNING * INTO v_slot_destino;

      PERFORM public.admin_insert_historial_bloque(
        v_slot_destino.fecha, v_slot_destino.hora, v_slot_destino.camara_id, v_slot_destino.id, v_slot_destino.lugar,
        'capacidad_reducida_reubicado', v_slot_destino.paciente_id, p_realizado_por,
        format('Reduccion de capacidad de camara. Reubicado desde lugar %s', v_slot_origen.lugar + 1),
        v_slot_destino.referido_tercero, v_slot_destino.referente_id, v_slot_destino.modalidad_cobro, v_slot_destino.obra_social_id,
        v_slot_destino.numero_autorizacion, v_slot_destino.medico_id, v_slot_destino.es_nuevo_ingreso,
        v_slot_destino.obra_social_validada_por, v_slot_destino.obra_social_validada_at, v_slot_destino.tanda_id
      );

      DELETE FROM public.slots WHERE id = v_slot_origen.id;
      v_movidos := v_movidos + 1;
    ELSE
      PERFORM public.admin_insert_historial_bloque(
        v_slot_origen.fecha, v_slot_origen.hora, v_slot_origen.camara_id, v_slot_origen.id, v_slot_origen.lugar,
        'capacidad_reducida_cancelado', v_slot_origen.paciente_id, p_realizado_por,
        'Reduccion de capacidad de camara',
        v_slot_origen.referido_tercero, v_slot_origen.referente_id, v_slot_origen.modalidad_cobro, v_slot_origen.obra_social_id,
        v_slot_origen.numero_autorizacion, v_slot_origen.medico_id, v_slot_origen.es_nuevo_ingreso,
        v_slot_origen.obra_social_validada_por, v_slot_origen.obra_social_validada_at, v_slot_origen.tanda_id
      );

      DELETE FROM public.slots WHERE id = v_slot_origen.id;
      v_cancelados := v_cancelados + 1;
    END IF;
  END LOOP;

  FOR v_slot_origen IN
    SELECT *
    FROM public.slots
    WHERE camara_id = p_camara_id
      AND fecha >= current_date
      AND lugar >= p_capacidad_nueva
      AND estado = 'apartado'
    ORDER BY fecha, hora, lugar
  LOOP
    PERFORM public.admin_insert_historial_bloque(
      v_slot_origen.fecha, v_slot_origen.hora, v_slot_origen.camara_id, v_slot_origen.id, v_slot_origen.lugar,
      'capacidad_reducida_apartado_liberado', v_slot_origen.paciente_id, p_realizado_por,
      'Reduccion de capacidad de camara',
      v_slot_origen.referido_tercero, v_slot_origen.referente_id, v_slot_origen.modalidad_cobro, v_slot_origen.obra_social_id,
      v_slot_origen.numero_autorizacion, v_slot_origen.medico_id, v_slot_origen.es_nuevo_ingreso,
      v_slot_origen.obra_social_validada_por, v_slot_origen.obra_social_validada_at, v_slot_origen.tanda_id
    );

    DELETE FROM public.slots WHERE id = v_slot_origen.id;
    v_apartados_liberados := v_apartados_liberados + 1;
  END LOOP;

  FOR v_slot_eliminado IN
    DELETE FROM public.slots
    WHERE camara_id = p_camara_id
      AND fecha >= current_date
      AND lugar >= p_capacidad_nueva
      AND estado IN ('libre', 'cancelado')
    RETURNING *
  LOOP
    PERFORM public.admin_insert_historial_bloque(
      v_slot_eliminado.fecha, v_slot_eliminado.hora, v_slot_eliminado.camara_id, null, v_slot_eliminado.lugar,
      'capacidad_reducida_slot_eliminado', null, p_realizado_por,
      'Reduccion de capacidad de camara',
      false, null, 'particular', null, null, null, false, null, null, v_slot_eliminado.tanda_id
    );
    v_eliminados := v_eliminados + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'movidos', v_movidos,
    'cancelados', v_cancelados,
    'apartados_liberados', v_apartados_liberados,
    'eliminados', v_eliminados
  );
END;
$$;


ALTER FUNCTION "public"."admin_reconciliar_capacidad_camara"("p_camara_id" integer, "p_capacidad_nueva" integer, "p_realizado_por" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_registrar_historial_bloques"("p_entradas" "jsonb") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_realizado_por uuid := public.auth_current_profile_id();
  v_inserted_count integer := 0;
begin
  if v_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_any_permission(array[
    'turnos.asignar',
    'turnos.cancelar',
    'turnos.reprogramar',
    'turnos.apartar',
    'turnos.confirmar_apartado',
    'turnos.liberar_apartado',
    'turnos.bloque_completo',
    'turnos.tanda'
  ]::text[]) then
    raise exception 'Prohibido';
  end if;

  if v_realizado_por is null then
    raise exception 'Perfil no encontrado';
  end if;

  if p_entradas is null or jsonb_typeof(p_entradas) <> 'array' or jsonb_array_length(p_entradas) = 0 then
    return 0;
  end if;

  insert into public.historial_bloques (
    fecha,
    hora,
    camara_id,
    slot_id,
    lugar,
    accion,
    paciente_id,
    realizado_por,
    motivo
  )
  select
    (entry->>'fecha')::date,
    entry->>'hora',
    nullif(entry->>'camara_id', '')::integer,
    nullif(entry->>'slot_id', '')::uuid,
    nullif(entry->>'lugar', '')::integer,
    entry->>'accion',
    nullif(entry->>'paciente_id', '')::uuid,
    v_realizado_por,
    nullif(entry->>'motivo', '')
  from jsonb_array_elements(p_entradas) as entry;

  get diagnostics v_inserted_count = row_count;
  return v_inserted_count;
end;
$$;


ALTER FUNCTION "public"."admin_registrar_historial_bloques"("p_entradas" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_reparar_consultas_slots_rango"("p_fecha_inicio" "date", "p_fecha_fin" "date") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if not public.can_manage_consultas() then
    raise exception 'Prohibido';
  end if;
  return public.reparar_consultas_slots_rango(p_fecha_inicio, p_fecha_fin);
end;
$$;


ALTER FUNCTION "public"."admin_reparar_consultas_slots_rango"("p_fecha_inicio" "date", "p_fecha_fin" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_reparar_slots_rango"("p_fecha_inicio" "date", "p_fecha_fin" "date") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_fecha date;
  v_total integer := 0;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_any_permission(array['turnos.read', 'turnos.asignar', 'turnos.tanda']::text[]) THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  IF p_fecha_inicio IS NULL OR p_fecha_fin IS NULL OR p_fecha_inicio > p_fecha_fin THEN
    RAISE EXCEPTION 'Rango de fechas invalido';
  END IF;

  v_fecha := p_fecha_inicio;
  WHILE v_fecha <= p_fecha_fin LOOP
    v_total := v_total + public.admin_generar_slots_dia(v_fecha);
    v_fecha := v_fecha + 1;
  END LOOP;

  RETURN v_total;
END;
$$;


ALTER FUNCTION "public"."admin_reparar_slots_rango"("p_fecha_inicio" "date", "p_fecha_fin" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_reprogramar_bloque_tanda"("p_slot_id" "uuid", "p_target_slot_id" "uuid") RETURNS SETOF "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_source public.slots%ROWTYPE;
  v_target public.slots%ROWTYPE;
  v_source_count integer;
  v_target_count integer;
  v_target_available integer;
  v_target_hour_order integer;
  v_result public.slots%ROWTYPE;
  v_source_slot_ids uuid[];
  v_moved_count integer := 0;
  v_cancelled_count integer := 0;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_any_permission(array['turnos.tanda', 'turnos.reprogramar']::text[]) THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  SELECT * INTO v_source FROM public.slots WHERE id = p_slot_id FOR UPDATE;
  IF v_source.id IS NULL OR v_source.estado <> 'ocupado' OR v_source.paciente_id IS NULL THEN
    RAISE EXCEPTION 'Bloque origen invalido';
  END IF;
  IF v_source.tanda_id IS NULL THEN
    RAISE EXCEPTION 'El turno no pertenece a una tanda';
  END IF;
  IF NOT v_source.es_bloque_completo THEN
    RAISE EXCEPTION 'Este turno no pertenece a un bloque completo';
  END IF;

  SELECT * INTO v_target FROM public.slots WHERE id = p_target_slot_id FOR UPDATE;
  IF v_target.id IS NULL OR v_target.id = v_source.id THEN
    RAISE EXCEPTION 'Bloque destino invalido';
  END IF;
  IF v_target.fecha <> v_source.fecha THEN
    RAISE EXCEPTION 'Solo se puede mover un turno dentro de la misma fecha';
  END IF;
  IF NOT EXISTS (
    SELECT 1 FROM public.camaras c WHERE c.id = v_target.camara_id AND c.activa = true
  ) THEN
    RAISE EXCEPTION 'Camara inactiva';
  END IF;

  SELECT orden INTO v_target_hour_order
  FROM public.horarios_config
  WHERE hora = v_target.hora AND activo = true;

  IF v_target_hour_order IS NULL THEN
    RAISE EXCEPTION 'Horario inactivo';
  END IF;

  SELECT array_agg(s.id ORDER BY s.lugar)
  INTO v_source_slot_ids
  FROM public.slots s
  WHERE s.fecha = v_source.fecha
    AND s.hora = v_source.hora
    AND s.camara_id = v_source.camara_id
    AND s.paciente_id = v_source.paciente_id
    AND s.tanda_id = v_source.tanda_id
    AND s.estado = 'ocupado'
    AND s.es_bloque_completo = true;

  SELECT count(*) INTO v_source_count
  FROM unnest(coalesce(v_source_slot_ids, ARRAY[]::uuid[]));

  IF coalesce(v_source_count, 0) = 0 THEN
    RAISE EXCEPTION 'Bloque origen invalido';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.slots s
    JOIN public.horarios_config hs ON hs.hora = s.hora
    WHERE s.fecha = v_target.fecha
      AND s.paciente_id = v_source.paciente_id
      AND s.estado = 'ocupado'
      AND NOT (s.id = ANY(v_source_slot_ids))
      AND abs(hs.orden - v_target_hour_order) <= 1
  ) THEN
    RAISE EXCEPTION 'No se pueden asignar turnos en bloques seguidos';
  END IF;

  SELECT count(*), count(*) FILTER (WHERE estado IN ('libre', 'cancelado'))
  INTO v_target_count, v_target_available
  FROM public.slots s
  WHERE s.fecha = v_target.fecha
    AND s.hora = v_target.hora
    AND s.camara_id = v_target.camara_id;

  IF coalesce(v_target_count, 0) <> v_source_count THEN
    RAISE EXCEPTION 'Bloque destino incompatible';
  END IF;
  IF coalesce(v_target_available, 0) <> v_source_count THEN
    RAISE EXCEPTION 'No hay disponibilidad completa para mover este bloque';
  END IF;

  FOR v_result IN
    UPDATE public.slots
    SET paciente_id = v_source.paciente_id,
        estado = 'ocupado',
        es_tanda = true,
        tanda_id = v_source.tanda_id,
        es_bloque_completo = true,
        apartado_por = null,
        apartado_ts = null,
        referido_tercero = coalesce(v_source.referido_tercero, false),
        referente_id = v_source.referente_id,
        modalidad_cobro = coalesce(v_source.modalidad_cobro, 'particular'),
        obra_social_id = v_source.obra_social_id,
        numero_autorizacion = v_source.numero_autorizacion,
        sesiones_autorizadas = v_source.sesiones_autorizadas,
        ciclo_obra_social_id = v_source.ciclo_obra_social_id,
        medico_id = v_source.medico_id,
        es_nuevo_ingreso = coalesce(v_source.es_nuevo_ingreso, false),
        obra_social_validada_por = v_source.obra_social_validada_por,
        obra_social_validada_at = v_source.obra_social_validada_at
    WHERE fecha = v_target.fecha
      AND hora = v_target.hora
      AND camara_id = v_target.camara_id
      AND estado IN ('libre', 'cancelado')
    RETURNING *
  LOOP
    v_moved_count := v_moved_count + 1;
    RETURN NEXT v_result;
  END LOOP;

  IF v_moved_count <> v_source_count THEN
    RAISE EXCEPTION 'No hay disponibilidad completa para mover este bloque';
  END IF;

  UPDATE public.slots
  SET paciente_id = null,
      estado = 'cancelado',
      es_tanda = false,
      es_bloque_completo = false,
      apartado_por = null,
      apartado_ts = null,
      referido_tercero = false,
      referente_id = null,
      modalidad_cobro = 'particular',
      obra_social_id = null,
      numero_autorizacion = null,
      sesiones_autorizadas = null,
      ciclo_obra_social_id = null,
      medico_id = null,
      es_nuevo_ingreso = false,
      obra_social_validada_por = null,
      obra_social_validada_at = null
  WHERE fecha = v_source.fecha
    AND hora = v_source.hora
    AND camara_id = v_source.camara_id
    AND paciente_id = v_source.paciente_id
    AND tanda_id = v_source.tanda_id
    AND estado = 'ocupado'
    AND es_bloque_completo = true;

  GET DIAGNOSTICS v_cancelled_count = ROW_COUNT;
  IF v_cancelled_count <> v_source_count THEN
    RAISE EXCEPTION 'Bloque origen invalido';
  END IF;
END;
$$;


ALTER FUNCTION "public"."admin_reprogramar_bloque_tanda"("p_slot_id" "uuid", "p_target_slot_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_reprogramar_consulta"("p_slot_id" "uuid", "p_target_slot_id" "uuid", "p_medico_id" integer DEFAULT NULL::integer) RETURNS "public"."consultas_slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor_perfil_id uuid := public.auth_current_profile_id();
  v_source public.consultas_slots%rowtype;
  v_target public.consultas_slots%rowtype;
  v_result public.consultas_slots%rowtype;
  v_medico_id integer;
begin
  if v_actor_perfil_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.can_manage_consultas() then
    raise exception 'Prohibido';
  end if;

  select *
  into v_source
  from public.consultas_slots
  where id = p_slot_id
  for update;

  select *
  into v_target
  from public.consultas_slots
  where id = p_target_slot_id
  for update;

  if v_source.id is null or v_target.id is null then
    raise exception 'Consulta invalida';
  end if;
  if v_source.estado not in ('confirmada', 'completada') then
    raise exception 'Consulta origen invalida';
  end if;
  if v_target.estado not in ('libre', 'cancelada') then
    raise exception 'Consulta destino invalida';
  end if;

  v_medico_id := public.admin_resolver_medico_operativo(
    coalesce(p_medico_id, v_source.medico_id),
    false,
    v_source.medico_id
  );

  perform public.admin_validar_conflicto_consulta(v_source.paciente_id, v_target.fecha, v_target.hora, v_target.id);

  update public.consultas_slots
  set estado = 'libre',
      paciente_id = null,
      medico_id = null,
      motivo_cancelacion = null,
      observaciones_admin = null,
      confirmado_at = null,
      confirmado_por = null,
      cerrado_at = null,
      cerrado_por = null
  where id = v_source.id;

  update public.consultas_slots
  set estado = 'confirmada',
      paciente_id = v_source.paciente_id,
      medico_id = v_medico_id,
      motivo_cancelacion = null,
      observaciones_admin = v_source.observaciones_admin,
      confirmado_at = coalesce(v_source.confirmado_at, now()),
      confirmado_por = coalesce(v_source.confirmado_por, v_actor_perfil_id),
      cerrado_at = null,
      cerrado_por = null
  where id = v_target.id
  returning * into v_result;

  perform public.admin_insert_historial_consulta(
    v_source.id,
    v_source.fecha,
    v_source.hora,
    'reprogramada_origen',
    v_source.paciente_id,
    v_source.medico_id,
    v_actor_perfil_id,
    null,
    jsonb_build_object('destino_id', v_target.id, 'destino_fecha', v_target.fecha, 'destino_hora', v_target.hora)
  );

  perform public.admin_insert_historial_consulta(
    v_result.id,
    v_result.fecha,
    v_result.hora,
    'reprogramada_destino',
    v_result.paciente_id,
    v_result.medico_id,
    v_actor_perfil_id,
    null,
    jsonb_build_object('origen_id', v_source.id, 'origen_fecha', v_source.fecha, 'origen_hora', v_source.hora)
  );

  update public.historia_clinica_evoluciones
  set consulta_slot_id = v_result.id
  where consulta_slot_id = v_source.id;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_reprogramar_consulta"("p_slot_id" "uuid", "p_target_slot_id" "uuid", "p_medico_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_reprogramar_slot"("p_slot_id" "uuid", "p_target_slot_id" "uuid") RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_source public.slots%ROWTYPE;
  v_target public.slots%ROWTYPE;
  v_result public.slots%ROWTYPE;
  v_target_hour_order integer;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.can_turnos_reprogramar() THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  SELECT * INTO v_source FROM public.slots WHERE id = p_slot_id FOR UPDATE;
  IF v_source.id IS NULL OR v_source.estado <> 'ocupado' OR v_source.paciente_id IS NULL THEN
    RAISE EXCEPTION 'Turno origen invalido';
  END IF;
  IF v_source.es_bloque_completo THEN
    RAISE EXCEPTION 'Este turno forma parte de un bloque completo';
  END IF;

  SELECT * INTO v_target FROM public.slots WHERE id = p_target_slot_id FOR UPDATE;
  IF v_target.id IS NULL OR v_target.id = v_source.id THEN
    RAISE EXCEPTION 'Slot destino invalido';
  END IF;
  IF v_target.fecha <> v_source.fecha THEN
    RAISE EXCEPTION 'Solo se puede mover un turno dentro de la misma fecha';
  END IF;
  IF v_target.estado NOT IN ('libre', 'cancelado') THEN
    RAISE EXCEPTION 'Slot destino invalido';
  END IF;
  IF NOT EXISTS (
    SELECT 1 FROM public.camaras c WHERE c.id = v_target.camara_id AND c.activa = true
  ) THEN
    RAISE EXCEPTION 'Camara inactiva';
  END IF;

  SELECT orden INTO v_target_hour_order
  FROM public.horarios_config
  WHERE hora = v_target.hora AND activo = true;

  IF v_target_hour_order IS NULL THEN
    RAISE EXCEPTION 'Horario inactivo';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.slots s
    JOIN public.horarios_config hs ON hs.hora = s.hora
    WHERE s.fecha = v_target.fecha
      AND s.paciente_id = v_source.paciente_id
      AND s.estado = 'ocupado'
      AND s.id <> v_source.id
      AND abs(hs.orden - v_target_hour_order) <= 1
  ) THEN
    RAISE EXCEPTION 'No se pueden asignar turnos en bloques seguidos';
  END IF;

  UPDATE public.slots
  SET paciente_id = v_source.paciente_id,
      estado = 'ocupado',
      es_tanda = coalesce(v_source.es_tanda, false),
      tanda_id = v_source.tanda_id,
      es_bloque_completo = false,
      apartado_por = null,
      apartado_ts = null,
      referido_tercero = coalesce(v_source.referido_tercero, false),
      referente_id = v_source.referente_id,
      modalidad_cobro = coalesce(v_source.modalidad_cobro, 'particular'),
      obra_social_id = v_source.obra_social_id,
      numero_autorizacion = v_source.numero_autorizacion,
      sesiones_autorizadas = v_source.sesiones_autorizadas,
      ciclo_obra_social_id = v_source.ciclo_obra_social_id,
      medico_id = v_source.medico_id,
      es_nuevo_ingreso = coalesce(v_source.es_nuevo_ingreso, false),
      obra_social_validada_por = v_source.obra_social_validada_por,
      obra_social_validada_at = v_source.obra_social_validada_at
  WHERE id = v_target.id
    AND estado IN ('libre', 'cancelado')
  RETURNING * INTO v_result;

  IF v_result.id IS NULL THEN
    RAISE EXCEPTION 'Slot destino invalido';
  END IF;

  UPDATE public.slots
  SET paciente_id = null,
      estado = 'cancelado',
      es_tanda = false,
      es_bloque_completo = false,
      apartado_por = null,
      apartado_ts = null,
      referido_tercero = false,
      referente_id = null,
      modalidad_cobro = 'particular',
      obra_social_id = null,
      numero_autorizacion = null,
      sesiones_autorizadas = null,
      ciclo_obra_social_id = null,
      medico_id = null,
      es_nuevo_ingreso = false,
      obra_social_validada_por = null,
      obra_social_validada_at = null
  WHERE id = v_source.id
    AND estado = 'ocupado';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Turno origen invalido';
  END IF;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_reprogramar_slot"("p_slot_id" "uuid", "p_target_slot_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_reprogramar_slot_tanda"("p_slot_id" "uuid", "p_target_slot_id" "uuid") RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_source public.slots%ROWTYPE;
  v_target public.slots%ROWTYPE;
  v_result public.slots%ROWTYPE;
  v_target_hour_order integer;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_any_permission(array['turnos.tanda', 'turnos.reprogramar']::text[]) THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  SELECT * INTO v_source FROM public.slots WHERE id = p_slot_id FOR UPDATE;
  IF v_source.id IS NULL OR v_source.estado <> 'ocupado' OR v_source.paciente_id IS NULL THEN
    RAISE EXCEPTION 'Turno origen invalido';
  END IF;
  IF v_source.es_bloque_completo THEN
    RAISE EXCEPTION 'Este turno forma parte de un bloque completo';
  END IF;

  SELECT * INTO v_target FROM public.slots WHERE id = p_target_slot_id FOR UPDATE;
  IF v_target.id IS NULL OR v_target.id = v_source.id THEN
    RAISE EXCEPTION 'Slot destino invalido';
  END IF;
  IF v_target.fecha <> v_source.fecha THEN
    RAISE EXCEPTION 'Solo se puede mover un turno dentro de la misma fecha';
  END IF;
  IF v_target.estado NOT IN ('libre', 'cancelado') THEN
    RAISE EXCEPTION 'Slot destino invalido';
  END IF;
  IF NOT EXISTS (
    SELECT 1 FROM public.camaras c WHERE c.id = v_target.camara_id AND c.activa = true
  ) THEN
    RAISE EXCEPTION 'Camara inactiva';
  END IF;

  SELECT orden INTO v_target_hour_order
  FROM public.horarios_config
  WHERE hora = v_target.hora AND activo = true;

  IF v_target_hour_order IS NULL THEN
    RAISE EXCEPTION 'Horario inactivo';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.slots s
    JOIN public.horarios_config hs ON hs.hora = s.hora
    WHERE s.fecha = v_target.fecha
      AND s.paciente_id = v_source.paciente_id
      AND s.estado = 'ocupado'
      AND s.id <> v_source.id
      AND abs(hs.orden - v_target_hour_order) <= 1
  ) THEN
    RAISE EXCEPTION 'No se pueden asignar turnos en bloques seguidos';
  END IF;

  UPDATE public.slots
  SET paciente_id = v_source.paciente_id,
      estado = 'ocupado',
      es_tanda = coalesce(v_source.es_tanda, false),
      tanda_id = v_source.tanda_id,
      es_bloque_completo = false,
      apartado_por = null,
      apartado_ts = null,
      referido_tercero = coalesce(v_source.referido_tercero, false),
      referente_id = v_source.referente_id,
      modalidad_cobro = coalesce(v_source.modalidad_cobro, 'particular'),
      obra_social_id = v_source.obra_social_id,
      numero_autorizacion = v_source.numero_autorizacion,
      sesiones_autorizadas = v_source.sesiones_autorizadas,
      ciclo_obra_social_id = v_source.ciclo_obra_social_id,
      medico_id = v_source.medico_id,
      es_nuevo_ingreso = coalesce(v_source.es_nuevo_ingreso, false),
      obra_social_validada_por = v_source.obra_social_validada_por,
      obra_social_validada_at = v_source.obra_social_validada_at
  WHERE id = v_target.id
    AND estado IN ('libre', 'cancelado')
  RETURNING * INTO v_result;

  IF v_result.id IS NULL THEN
    RAISE EXCEPTION 'Slot destino invalido';
  END IF;

  UPDATE public.slots
  SET paciente_id = null,
      estado = 'libre',
      es_tanda = false,
      es_bloque_completo = false,
      apartado_por = null,
      apartado_ts = null,
      referido_tercero = false,
      referente_id = null,
      modalidad_cobro = 'particular',
      obra_social_id = null,
      numero_autorizacion = null,
      sesiones_autorizadas = null,
      ciclo_obra_social_id = null,
      medico_id = null,
      es_nuevo_ingreso = false,
      obra_social_validada_por = null,
      obra_social_validada_at = null
  WHERE id = v_source.id
    AND estado = 'ocupado';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Turno origen invalido';
  END IF;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_reprogramar_slot_tanda"("p_slot_id" "uuid", "p_target_slot_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_resolver_medico_operativo"("p_medico_id" integer DEFAULT NULL::integer, "p_es_nuevo_ingreso" boolean DEFAULT false, "p_medico_actual_id" integer DEFAULT NULL::integer) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_medico_id integer;
BEGIN
  IF coalesce(p_es_nuevo_ingreso, false) AND p_medico_id IS NULL THEN
    RAISE EXCEPTION 'Medico requerido para nuevo ingreso';
  END IF;

  IF p_medico_id IS NULL THEN
    RETURN null;
  END IF;

  SELECT id
  INTO v_medico_id
  FROM public.medicos
  WHERE id = p_medico_id
    AND (activo = true OR id = p_medico_actual_id);

  IF v_medico_id IS NULL THEN
    RAISE EXCEPTION 'Medico invalido';
  END IF;

  RETURN v_medico_id;
END;
$$;


ALTER FUNCTION "public"."admin_resolver_medico_operativo"("p_medico_id" integer, "p_es_nuevo_ingreso" boolean, "p_medico_actual_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_resolver_operativo_obra_social"("p_paciente_id" "uuid", "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_autorizacion" "text" DEFAULT NULL::"text", "p_convenio_corroborado" boolean DEFAULT false) RETURNS TABLE("obra_social_id" integer, "numero_autorizacion" "text", "sin_convenio" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_paciente_obra_social_id integer;
  v_numero_autorizacion text := nullif(trim(coalesce(p_numero_autorizacion, '')), '');
  v_tiene_convenio boolean := false;
BEGIN
  IF coalesce(p_modalidad_cobro, 'particular') <> 'obra_social' THEN
    RETURN QUERY SELECT null::integer, null::text, false;
    RETURN;
  END IF;

  SELECT p.obra_social_id
  INTO v_paciente_obra_social_id
  FROM public.perfiles AS p
  WHERE p.id = p_paciente_id
    AND p.rol = 'paciente';

  IF v_paciente_obra_social_id IS NULL THEN
    RAISE EXCEPTION 'Paciente sin obra social cargada';
  END IF;

  IF p_obra_social_id IS NULL OR p_obra_social_id <> v_paciente_obra_social_id THEN
    RAISE EXCEPTION 'Obra social invalida para el paciente';
  END IF;

  SELECT coalesce(os.tiene_convenio, false)
  INTO v_tiene_convenio
  FROM public.obras_sociales AS os
  WHERE os.id = p_obra_social_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Obra social invalida';
  END IF;

  IF v_numero_autorizacion IS NULL THEN
    RAISE EXCEPTION 'Numero de autorizacion requerido';
  END IF;

  IF NOT v_tiene_convenio AND NOT coalesce(p_convenio_corroborado, false) THEN
    RAISE EXCEPTION 'Debes corroborar el pago de la obra social';
  END IF;

  RETURN QUERY
  SELECT
    v_paciente_obra_social_id AS obra_social_id,
    v_numero_autorizacion AS numero_autorizacion,
    (NOT v_tiene_convenio) AS sin_convenio;
END;
$$;


ALTER FUNCTION "public"."admin_resolver_operativo_obra_social"("p_paciente_id" "uuid", "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer, "p_numero_autorizacion" "text", "p_convenio_corroborado" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_resolver_operativo_obra_social"("p_paciente_id" "uuid", "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer DEFAULT NULL::integer, "p_numero_autorizacion" "text" DEFAULT NULL::"text", "p_sesiones_autorizadas" integer DEFAULT NULL::integer, "p_ciclo_obra_social_id" "uuid" DEFAULT NULL::"uuid", "p_iniciar_nuevo_ciclo_obra_social" boolean DEFAULT false, "p_convenio_corroborado" boolean DEFAULT false) RETURNS TABLE("obra_social_id" integer, "numero_autorizacion" "text", "sesiones_autorizadas" integer, "ciclo_obra_social_id" "uuid", "sin_convenio" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_paciente_obra_social_id integer;
  v_numero_autorizacion text := public.admin_normalizar_numero_autorizacion_obra_social(p_numero_autorizacion);
  v_tiene_convenio boolean := false;
  v_ciclo_obra_social_id uuid := p_ciclo_obra_social_id;
begin
  if coalesce(p_modalidad_cobro, 'particular') <> 'obra_social' then
    return query select null::integer, null::text, null::integer, null::uuid, false;
    return;
  end if;

  select p.obra_social_id
  into v_paciente_obra_social_id
  from public.perfiles as p
  where p.id = p_paciente_id
    and p.rol = 'paciente';

  if v_paciente_obra_social_id is null then
    raise exception 'Paciente sin obra social cargada';
  end if;

  if p_obra_social_id is null or p_obra_social_id <> v_paciente_obra_social_id then
    raise exception 'Obra social invalida para el paciente';
  end if;

  select coalesce(os.tiene_convenio, false)
  into v_tiene_convenio
  from public.obras_sociales as os
  where os.id = p_obra_social_id;

  if not found then
    raise exception 'Obra social invalida';
  end if;

  if v_numero_autorizacion is null then
    raise exception 'Numero de autorizacion requerido';
  end if;

  if p_sesiones_autorizadas is null or p_sesiones_autorizadas <= 0 then
    raise exception 'Debes indicar una cantidad valida de sesiones autorizadas';
  end if;

  if public.admin_es_serie_obra_social_sn(v_numero_autorizacion) then
    if coalesce(p_iniciar_nuevo_ciclo_obra_social, false) then
      v_ciclo_obra_social_id := gen_random_uuid();  -- â† era uuid_generate_v4()
    elsif v_ciclo_obra_social_id is null then
      raise exception 'Para una autorizacion S/N debes indicar o iniciar un ciclo de obra social';
    end if;
  else
    v_ciclo_obra_social_id := null;
  end if;

  if not v_tiene_convenio and not coalesce(p_convenio_corroborado, false) then
    raise exception 'Debes corroborar el pago de la obra social';
  end if;

  return query
  select
    v_paciente_obra_social_id,
    v_numero_autorizacion,
    p_sesiones_autorizadas,
    v_ciclo_obra_social_id,
    (not v_tiene_convenio);
end;
$$;


ALTER FUNCTION "public"."admin_resolver_operativo_obra_social"("p_paciente_id" "uuid", "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_obra_social_id" integer, "p_numero_autorizacion" "text", "p_sesiones_autorizadas" integer, "p_ciclo_obra_social_id" "uuid", "p_iniciar_nuevo_ciclo_obra_social" boolean, "p_convenio_corroborado" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_resolver_referente_operativo"("p_referido_tercero" boolean DEFAULT false, "p_referente_id" integer DEFAULT NULL::integer, "p_referente_actual_id" integer DEFAULT NULL::integer) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_referente_id integer;
BEGIN
  IF coalesce(p_referido_tercero, false) IS FALSE THEN
    RETURN null;
  END IF;
  IF p_referente_id IS NULL THEN
    RAISE EXCEPTION 'Debes indicar quien refiere el turno';
  END IF;
  SELECT id INTO v_referente_id
  FROM public.referentes
  WHERE id = p_referente_id
    AND (activo = true OR id = p_referente_actual_id);
  IF v_referente_id IS NULL THEN
    RAISE EXCEPTION 'Referente invalido';
  END IF;
  RETURN v_referente_id;
END;
$$;


ALTER FUNCTION "public"."admin_resolver_referente_operativo"("p_referido_tercero" boolean, "p_referente_id" integer, "p_referente_actual_id" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_set_role_permissions"("p_role_slug" "text", "p_permission_keys" "text"[]) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_role_id bigint;
begin
  if not public.auth_has_permission('rbac.manage') then
    raise exception 'Prohibido';
  end if;

  select id into v_role_id
  from public.rbac_roles
  where slug = lower(trim(coalesce(p_role_slug, '')))
  limit 1;

  if v_role_id is null then
    raise exception 'Rol no encontrado';
  end if;

  delete from public.rbac_role_permissions
  where role_id = v_role_id;

  insert into public.rbac_role_permissions(role_id, permission_id, granted)
  select
    v_role_id,
    p.id,
    true
  from public.rbac_permissions p
  where p.key = any(coalesce(p_permission_keys, array[]::text[]));

  perform public.rbac_rebuild_for_role(v_role_id);
end;
$$;


ALTER FUNCTION "public"."admin_set_role_permissions"("p_role_slug" "text", "p_permission_keys" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_set_staff_user_active"("p_user_id" "uuid", "p_active" boolean, "p_role_slug" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_target_role_slug text := lower(trim(coalesce(p_role_slug, 'secretaria')));
  v_target_role_id bigint;
begin
  if not public.auth_has_permission('staff.manage') then
    raise exception 'Prohibido';
  end if;

  if p_user_id is null then
    raise exception 'Usuario requerido';
  end if;

  if not exists (select 1 from public.perfiles where id = p_user_id) then
    raise exception 'Usuario no encontrado';
  end if;

  if p_active = false then
    perform public.admin_assign_user_roles(
      p_user_id := p_user_id,
      p_role_slugs := array['staff_inactivo']::text[],
      p_primary_role_slug := 'staff_inactivo'
    );
  else
    if v_target_role_slug in ('', 'paciente', 'staff_inactivo') then
      v_target_role_slug := 'secretaria';
    end if;

    select r.id
    into v_target_role_id
    from public.rbac_roles r
    where r.slug = v_target_role_slug
      and r.is_staff = true
      and r.slug <> 'staff_inactivo'
      and r.activo = true
    limit 1;

    if v_target_role_id is null then
      raise exception 'Rol de activación inválido';
    end if;

    perform public.admin_assign_user_roles(
      p_user_id := p_user_id,
      p_role_slugs := array[v_target_role_slug]::text[],
      p_primary_role_slug := v_target_role_slug
    );
  end if;
end;
$$;


ALTER FUNCTION "public"."admin_set_staff_user_active"("p_user_id" "uuid", "p_active" boolean, "p_role_slug" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_toggle_camara_activa"("p_camara_id" integer, "p_activa" boolean) RETURNS "public"."camaras"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_result public.camaras%ROWTYPE;
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF NOT public.auth_has_permission('config.camaras.manage') THEN
    RAISE EXCEPTION 'Prohibido';
  END IF;

  UPDATE public.camaras
  SET activa = coalesce(p_activa, false)
  WHERE id = p_camara_id
  RETURNING * INTO v_result;

  IF v_result.id IS NULL THEN
    RAISE EXCEPTION 'Camara no encontrada';
  END IF;

  IF v_result.activa THEN
    PERFORM public.generar_slots_camara_rango(
      v_result.id,
      v_result.capacidad,
      current_date,
      public.slots_horizonte_hasta()
    );
  END IF;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."admin_toggle_camara_activa"("p_camara_id" integer, "p_activa" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_toggle_consulta_horario_config"("p_horario_id" integer, "p_activo" boolean) RETURNS "public"."consultas_horarios_config"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_result public.consultas_horarios_config%rowtype;
begin
  if not public.can_manage_consultas() then
    raise exception 'Prohibido';
  end if;

  update public.consultas_horarios_config
  set activo = coalesce(p_activo, false)
  where id = p_horario_id
  returning * into v_result;

  if v_result.id is null then
    raise exception 'Horario no encontrado';
  end if;

  if v_result.activo then
    perform public.reparar_consultas_slots_rango(current_date, public.slots_horizonte_hasta());
  end if;

  return v_result;
end;
$$;


ALTER FUNCTION "public"."admin_toggle_consulta_horario_config"("p_horario_id" integer, "p_activo" boolean) OWNER TO "postgres";


