CREATE TABLE IF NOT EXISTS "public"."rbac_roles" (
    "id" bigint NOT NULL,
    "slug" "text" NOT NULL,
    "nombre" "text" NOT NULL,
    "descripcion" "text",
    "activo" boolean DEFAULT true NOT NULL,
    "is_system" boolean DEFAULT false NOT NULL,
    "is_staff" boolean DEFAULT true NOT NULL,
    "default_home" "text" DEFAULT '/usuario'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "public"."rbac_roles" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_upsert_role"("p_slug" "text", "p_nombre" "text", "p_descripcion" "text" DEFAULT NULL::"text", "p_activo" boolean DEFAULT true, "p_is_staff" boolean DEFAULT true, "p_default_home" "text" DEFAULT '/usuario'::"text") RETURNS "public"."rbac_roles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_role public.rbac_roles%rowtype;
begin
  if not public.auth_has_permission('rbac.manage') then
    raise exception 'Prohibido';
  end if;

  if coalesce(trim(p_slug), '') = '' or coalesce(trim(p_nombre), '') = '' then
    raise exception 'Slug y nombre requeridos';
  end if;

  insert into public.rbac_roles(slug, nombre, descripcion, activo, is_system, is_staff, default_home)
  values (
    lower(trim(p_slug)),
    trim(p_nombre),
    nullif(trim(coalesce(p_descripcion, '')), ''),
    coalesce(p_activo, true),
    false,
    coalesce(p_is_staff, true),
    coalesce(nullif(trim(coalesce(p_default_home, '')), ''), '/usuario')
  )
  on conflict (slug) do update
  set
    nombre = excluded.nombre,
    descripcion = excluded.descripcion,
    activo = excluded.activo,
    is_staff = excluded.is_staff,
    default_home = excluded.default_home,
    updated_at = now()
  returning *
  into v_role;

  perform public.rbac_rebuild_for_role(v_role.id);
  return v_role;
end;
$$;


ALTER FUNCTION "public"."admin_upsert_role"("p_slug" "text", "p_nombre" "text", "p_descripcion" "text", "p_activo" boolean, "p_is_staff" boolean, "p_default_home" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_validar_conflicto_consulta"("p_paciente_id" "uuid", "p_fecha" "date", "p_hora" "text", "p_slot_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if p_paciente_id is null or p_fecha is null or nullif(trim(coalesce(p_hora, '')), '') is null then
    raise exception 'Datos incompletos';
  end if;

  if exists (
    select 1
    from public.slots s
    where s.paciente_id = p_paciente_id
      and s.fecha = p_fecha
      and s.hora = p_hora
      and s.estado = 'ocupado'
  ) then
    raise exception 'El paciente ya tiene una sesion ocupada en el mismo bloque horario';
  end if;

  if exists (
    select 1
    from public.consultas_slots c
    where c.paciente_id = p_paciente_id
      and c.fecha = p_fecha
      and c.hora = p_hora
      and c.estado in ('confirmada', 'completada')
      and (p_slot_id is null or c.id <> p_slot_id)
  ) then
    raise exception 'El paciente ya tiene una consulta confirmada en el mismo bloque horario';
  end if;
end;
$$;


ALTER FUNCTION "public"."admin_validar_conflicto_consulta"("p_paciente_id" "uuid", "p_fecha" "date", "p_hora" "text", "p_slot_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."admin_validar_tope_obra_social_serie"("p_paciente_id" "uuid", "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_numero_autorizacion" "text", "p_sesiones_autorizadas" integer, "p_ciclo_obra_social_id" "uuid", "p_exclude_slot_ids" "uuid"[] DEFAULT ARRAY[]::"uuid"[], "p_unidades_nuevas" integer DEFAULT 1) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_total integer;
BEGIN
  IF coalesce(p_modalidad_cobro, 'particular') <> 'obra_social' THEN
    RETURN;
  END IF;

  v_total :=
    public.admin_contar_sesiones_historicas_serie(
      p_paciente_id,
      p_modalidad_cobro,
      p_numero_autorizacion,
      p_ciclo_obra_social_id
    )
    + public.admin_contar_unidades_programadas_serie(
      p_paciente_id,
      p_modalidad_cobro,
      p_numero_autorizacion,
      p_ciclo_obra_social_id,
      p_exclude_slot_ids
    )
    + greatest(coalesce(p_unidades_nuevas, 1), 0);

  IF v_total > p_sesiones_autorizadas THEN
    RAISE EXCEPTION 'La autorizacion permite % sesiones y el turno supera ese tope', p_sesiones_autorizadas;
  END IF;
END;
$$;


ALTER FUNCTION "public"."admin_validar_tope_obra_social_serie"("p_paciente_id" "uuid", "p_modalidad_cobro" "public"."modalidad_cobro_turno", "p_numero_autorizacion" "text", "p_sesiones_autorizadas" integer, "p_ciclo_obra_social_id" "uuid", "p_exclude_slot_ids" "uuid"[], "p_unidades_nuevas" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auth_current_profile_id"() RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_auth_uid uuid := auth.uid();
  v_profile_id uuid;
begin
  if v_auth_uid is null then
    return null;
  end if;

  select p.id
  into v_profile_id
  from public.perfiles p
  where p.auth_user_id = v_auth_uid
  order by p.created_at asc
  limit 1;

  if v_profile_id is null then
    select p.id
    into v_profile_id
    from public.perfiles p
    where p.id = v_auth_uid
    limit 1;
  end if;

  return v_profile_id;
end;
$$;


ALTER FUNCTION "public"."auth_current_profile_id"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auth_has_any_permission"("p_keys" "text"[]) RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select exists (
    select 1
    from unnest(coalesce(p_keys, array[]::text[])) as k(permission_key)
    where public.auth_has_permission(k.permission_key)
  );
$$;


ALTER FUNCTION "public"."auth_has_any_permission"("p_keys" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auth_has_permission"("p_permission_key" "text") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with current_profile as (
    select public.auth_current_profile_id() as id
  )
  select exists (
    select 1
    from current_profile cp
    join public.rbac_effective_permissions ep on ep.user_id = cp.id
    where ep.permission_key = p_permission_key
  );
$$;


ALTER FUNCTION "public"."auth_has_permission"("p_permission_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auth_has_role"("p_role_slug" "text") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with current_profile as (
    select public.auth_current_profile_id() as id
  )
  select exists (
    select 1
    from current_profile cp
    join public.rbac_user_roles ur on ur.user_id = cp.id and ur.expires_at is null
    join public.rbac_roles r on r.id = ur.role_id and r.activo = true
    where r.slug = p_role_slug
  );
$$;


ALTER FUNCTION "public"."auth_has_role"("p_role_slug" "text") OWNER TO "postgres";


