CREATE OR REPLACE FUNCTION "public"."consolidar_import_pacientes"("p_job_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_row         RECORD;
  v_perfil_id   uuid;
  v_hc_numero   bigint;
  v_inserted    integer := 0;
  v_duplicated  integer := 0;
  v_err_consol  integer := 0;
  v_created_by  uuid;
BEGIN
  SELECT j.created_by
  INTO v_created_by
  FROM public.import_jobs j
  WHERE j.id = p_job_id;

  FOR v_row IN
    SELECT * FROM public.import_pacientes_staging
    WHERE job_id = p_job_id AND estado = 'valido'
    ORDER BY row_number
  LOOP
    IF v_row.documento_identidad_normalizado IS NOT NULL AND EXISTS (
      SELECT 1 FROM public.perfiles
      WHERE documento_identidad_normalizado = v_row.documento_identidad_normalizado
        AND rol = 'paciente'
    ) THEN
      UPDATE public.import_pacientes_staging
        SET estado = 'duplicado',
            error_detalle = 'Paciente ya registrado con ese documento'
        WHERE id = v_row.id;

      INSERT INTO public.import_errors (job_id, row_number, campo, mensaje, raw_data)
        VALUES (
          p_job_id,
          v_row.row_number,
          'documento_identidad',
          'Paciente ya registrado: ' || COALESCE(v_row.documento_identidad, ''),
          jsonb_build_object(
            'nombre', v_row.nombre,
            'documento_identidad', v_row.documento_identidad
          )
        );

      v_duplicated := v_duplicated + 1;
      CONTINUE;
    END IF;

    v_perfil_id := gen_random_uuid();

    BEGIN
      INSERT INTO public.perfiles (
        id, auth_user_id,
        nombre, telefono,
        documento_identidad, documento_identidad_normalizado,
        email, condicion_iva_id, obra_social_id,
        numero_credencial_obra_social,
        nacionalidad, claustrofobico, notas,
        rol, datos_extra, opt_in_whatsapp, portal_habilitado
      ) VALUES (
        v_perfil_id, NULL,
        v_row.nombre, v_row.telefono,
        v_row.documento_identidad, v_row.documento_identidad_normalizado,
        v_row.email, v_row.condicion_iva_id, v_row.obra_social_id,
        v_row.numero_credencial_obra_social,
        v_row.nacionalidad, COALESCE(v_row.claustrofobico, false), v_row.notas,
        'paciente', '{}'::jsonb, false, false
      );

      IF v_row.numero_hc IS NOT NULL AND NOT EXISTS (
        SELECT 1 FROM public.historias_clinicas WHERE numero = v_row.numero_hc
      ) THEN
        INSERT INTO public.historias_clinicas (paciente_id, numero)
          VALUES (v_perfil_id, v_row.numero_hc);
        PERFORM setval(
          'public.historia_clinica_numero_seq',
          GREATEST(
            COALESCE((SELECT MAX(numero) FROM public.historias_clinicas), 1),
            v_row.numero_hc
          ),
          true
        );
      ELSE
        v_hc_numero := nextval('public.historia_clinica_numero_seq');
        INSERT INTO public.historias_clinicas (paciente_id, numero)
          VALUES (v_perfil_id, v_hc_numero);
      END IF;

      UPDATE public.import_pacientes_staging
        SET estado = 'insertado', perfil_id = v_perfil_id
        WHERE id = v_row.id;

      PERFORM public.admin_append_event(
        p_occurred_at := now(),
        p_actor_user_id := v_created_by,
        p_actor_label := NULL,
        p_action_code := 'paciente.creado',
        p_action_family := 'altas',
        p_entity_type := 'paciente',
        p_entity_id := v_perfil_id::text,
        p_agenda_type := NULL,
        p_paciente_id := v_perfil_id,
        p_paciente_nombre := v_row.nombre,
        p_medico_id := NULL,
        p_medico_nombre := NULL,
        p_title := 'Paciente creado',
        p_summary := v_row.nombre,
        p_source_system := 'perfiles',
        p_source_record_key := v_perfil_id::text,
        p_metadata := jsonb_strip_nulls(
          jsonb_build_object(
            'via', 'importacion',
            'import_job_id', p_job_id,
            'fila_excel', v_row.row_number
          )
        )
      );

      v_inserted := v_inserted + 1;

    EXCEPTION WHEN OTHERS THEN
      UPDATE public.import_pacientes_staging
        SET estado = 'error', error_detalle = SQLERRM
        WHERE id = v_row.id;

      INSERT INTO public.import_errors (job_id, row_number, campo, mensaje, raw_data)
        VALUES (
          p_job_id, v_row.row_number, NULL,
          'Error al insertar: ' || SQLERRM,
          jsonb_build_object(
            'nombre', v_row.nombre,
            'documento_identidad', v_row.documento_identidad
          )
        );

      v_err_consol := v_err_consol + 1;
    END;
  END LOOP;

  RETURN jsonb_build_object(
    'insertados',            v_inserted,
    'duplicados',            v_duplicated,
    'errores_consolidacion', v_err_consol
  );
END;
$$;


ALTER FUNCTION "public"."consolidar_import_pacientes"("p_job_id" "uuid") OWNER TO "postgres";


