CREATE OR REPLACE FUNCTION "public"."ensure_historia_clinica_for_patient"("p_paciente_id" "uuid") RETURNS "public"."historias_clinicas"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_result public.historias_clinicas%rowtype;
begin
  if p_paciente_id is null then
    raise exception 'Paciente no valido';
  end if;

  insert into public.historias_clinicas (paciente_id, numero)
  values (p_paciente_id, nextval('public.historia_clinica_numero_seq'))
  on conflict (paciente_id) do nothing;

  select *
  into v_result
  from public.historias_clinicas
  where paciente_id = p_paciente_id;

  return v_result;
end;
$$;


