CREATE OR REPLACE FUNCTION "public"."generar_consultas_slots_dia"("p_fecha" "date") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  h record;
begin
  for h in
    select hora
    from public.consultas_horarios_config
    where activo = true
    order by orden
  loop
    insert into public.consultas_slots (fecha, hora, estado)
    values (p_fecha, h.hora, 'libre')
    on conflict (fecha, hora) do nothing;
  end loop;
end;
$$;


ALTER FUNCTION "public"."generar_consultas_slots_dia"("p_fecha" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generar_slots_camara_rango"("p_camara_id" integer, "p_capacidad" integer, "p_fecha_desde" "date", "p_fecha_hasta" "date") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  h record;
  d date;
  lugar_idx integer;
BEGIN
  IF p_camara_id IS NULL OR p_capacidad IS NULL OR p_capacidad < 1 THEN
    RETURN;
  END IF;

  IF p_fecha_desde IS NULL OR p_fecha_hasta IS NULL OR p_fecha_desde > p_fecha_hasta THEN
    RETURN;
  END IF;

  FOR d IN
    SELECT generate_series(p_fecha_desde, p_fecha_hasta, '1 day'::interval)::date
  LOOP
    FOR h IN
      SELECT hora
      FROM public.horarios_config
      WHERE activo = true
      ORDER BY orden
    LOOP
      FOR lugar_idx IN 0..(p_capacidad - 1) LOOP
        INSERT INTO public.slots (fecha, hora, camara_id, lugar, estado)
        VALUES (d, h.hora, p_camara_id, lugar_idx, 'libre')
        ON CONFLICT (fecha, hora, camara_id, lugar) DO NOTHING;
      END LOOP;
    END LOOP;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."generar_slots_camara_rango"("p_camara_id" integer, "p_capacidad" integer, "p_fecha_desde" "date", "p_fecha_hasta" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generar_slots_dia"("p_fecha" "date") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
declare
  h record;
  cam record;
  lugar_idx integer;
begin
  for h in select hora from public.horarios_config where activo = true order by orden loop
    for cam in select * from public.camaras where activa = true loop
      for lugar_idx in 0..(cam.capacidad - 1) loop
        insert into public.slots (fecha, hora, camara_id, lugar, estado)
        values (p_fecha, h.hora, cam.id, lugar_idx, 'libre')
        on conflict (fecha, hora, camara_id, lugar) do nothing;
      end loop;
    end loop;
  end loop;
end;
$$;


ALTER FUNCTION "public"."generar_slots_dia"("p_fecha" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generar_slots_hora"("p_hora" "text") RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
declare
  cam record;
  lugar_idx integer;
  d date;
begin
  for d in select generate_series(current_date, public.slots_horizonte_hasta(), '1 day'::interval)::date loop
    for cam in select * from public.camaras where activa = true loop
      for lugar_idx in 0..(cam.capacidad - 1) loop
        insert into public.slots (fecha, hora, camara_id, lugar, estado)
        values (d, p_hora, cam.id, lugar_idx, 'libre')
        on conflict (fecha, hora, camara_id, lugar) do nothing;
      end loop;
    end loop;
  end loop;
end;
$$;


ALTER FUNCTION "public"."generar_slots_hora"("p_hora" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_perfil_id uuid := nullif(new.raw_user_meta_data->>'perfil_id', '')::uuid;
  v_rol public.rol_usuario := coalesce((new.raw_user_meta_data->>'rol')::public.rol_usuario, 'paciente');
begin
  if v_perfil_id is not null then
    update public.perfiles
    set
      auth_user_id = new.id,
      email = coalesce(email, new.email),
      portal_login_email = coalesce(portal_login_email, new.email),
      portal_habilitado = true,
      portal_habilitado_at = coalesce(portal_habilitado_at, now())
    where id = v_perfil_id
      and auth_user_id is null;

    if found then
      return new;
    end if;
  end if;

  insert into public.perfiles (
    id,
    auth_user_id,
    nombre,
    email,
    rol,
    portal_habilitado,
    portal_login_email
  )
  values (
    case when v_rol = 'admin' then new.id else gen_random_uuid() end,  -- era uuid_generate_v4()
    new.id,
    coalesce(new.raw_user_meta_data->>'nombre', split_part(coalesce(new.email, ''), '@', 1), 'usuario'),
    new.email,
    v_rol,
    (v_rol = 'paciente'),
    new.email
  );

  return new;
end;
$$;


ALTER FUNCTION "public"."handle_new_user"() OWNER TO "postgres";


