CREATE OR REPLACE FUNCTION "public"."me_actualizar_mis_datos"("p_nombre" "text" DEFAULT NULL::"text") RETURNS "public"."perfiles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_auth_user_id uuid := auth.uid();
  v_nombre text := nullif(trim(coalesce(p_nombre, '')), '');
  v_profile public.perfiles;
begin
  if v_auth_user_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('app.admin_panel.access') then
    raise exception 'Prohibido';
  end if;

  if v_nombre is null then
    raise exception 'El nombre es obligatorio';
  end if;

  update public.perfiles
  set
    nombre = v_nombre
  where auth_user_id = v_auth_user_id
  returning * into v_profile;

  if v_profile.id is null then
    raise exception 'Perfil no encontrado';
  end if;

  return v_profile;
end;
$$;


ALTER FUNCTION "public"."me_actualizar_mis_datos"("p_nombre" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."me_get_effective_access"() RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_profile_id uuid := public.auth_current_profile_id();
  v_permissions text[];
  v_roles text[];
  v_primary_role text;
  v_default_home text;
begin
  if v_profile_id is null then
    return jsonb_build_object(
      'profile_id', null,
      'roles', '[]'::jsonb,
      'effective_permissions', '[]'::jsonb,
      'primary_role', null,
      'default_home', '/login',
      'is_staff', false
    );
  end if;

  select array_agg(distinct ep.permission_key order by ep.permission_key)
  into v_permissions
  from public.rbac_effective_permissions ep
  where ep.user_id = v_profile_id;

  select array_agg(distinct r.slug order by r.slug)
  into v_roles
  from public.rbac_user_roles ur
  join public.rbac_roles r on r.id = ur.role_id
  where ur.user_id = v_profile_id
    and ur.expires_at is null
    and r.activo = true;

  select r.slug, r.default_home
  into v_primary_role, v_default_home
  from public.rbac_user_roles ur
  join public.rbac_roles r on r.id = ur.role_id
  where ur.user_id = v_profile_id
    and ur.is_primary = true
    and ur.expires_at is null
  limit 1;

  if v_primary_role is null then
    select null, '/login'
    into v_primary_role, v_default_home;
  end if;

  return jsonb_build_object(
    'profile_id', v_profile_id,
    'roles', to_jsonb(coalesce(v_roles, array[]::text[])),
    'effective_permissions', to_jsonb(coalesce(v_permissions, array[]::text[])),
    'primary_role', v_primary_role,
    'default_home', coalesce(v_default_home, '/login'),
    'is_staff', public.auth_is_staff()
  );
end;
$$;


ALTER FUNCTION "public"."me_get_effective_access"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."normalize_documento_identidad"("p_value" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  SELECT nullif(regexp_replace(upper(trim(coalesce(p_value, ''))), '[^A-Z0-9]', '', 'g'), '')
$$;


ALTER FUNCTION "public"."normalize_documento_identidad"("p_value" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."normalize_phone_to_e164"("p_value" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
DECLARE
  v_raw text := trim(coalesce(p_value, ''));
  v_digits text;
  v_local_digits text;
BEGIN
  IF v_raw = '' THEN
    RETURN NULL;
  END IF;

  v_digits := regexp_replace(v_raw, '\D', '', 'g');
  IF v_digits = '' THEN
    RETURN NULL;
  END IF;

  IF left(v_raw, 1) = '+' AND length(v_digits) >= 10 THEN
    RETURN '+' || v_digits;
  END IF;

  IF v_digits LIKE '549%' AND length(v_digits) >= 12 THEN
    RETURN '+' || v_digits;
  END IF;

  IF v_digits LIKE '54%' AND length(v_digits) >= 11 THEN
    RETURN '+549' || substring(v_digits from 3);
  END IF;

  v_local_digits := regexp_replace(v_digits, '^0+', '');
  IF length(v_local_digits) BETWEEN 10 AND 11 THEN
    RETURN '+549' || v_local_digits;
  END IF;

  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."normalize_phone_to_e164"("p_value" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."paciente_actualizar_mis_datos"("p_nombre" "text" DEFAULT NULL::"text", "p_email" "text" DEFAULT NULL::"text", "p_telefono" "text" DEFAULT NULL::"text") RETURNS "public"."perfiles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_paciente_id uuid := public.current_paciente_perfil_id();
  v_result public.perfiles%ROWTYPE;
BEGIN
  IF v_user_id IS NULL OR v_paciente_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  IF nullif(btrim(coalesce(p_nombre, '')), '') IS NULL THEN
    RAISE EXCEPTION 'Nombre requerido';
  END IF;

  IF nullif(btrim(coalesce(p_telefono, '')), '') IS NULL THEN
    RAISE EXCEPTION 'Telefono requerido';
  END IF;

  UPDATE public.perfiles
  SET
    nombre = btrim(p_nombre),
    email = nullif(btrim(coalesce(p_email, '')), ''),
    telefono = btrim(p_telefono)
  WHERE id = v_paciente_id
    AND rol = 'paciente'
  RETURNING * INTO v_result;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Paciente no encontrado';
  END IF;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."paciente_actualizar_mis_datos"("p_nombre" "text", "p_email" "text", "p_telefono" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."paciente_cancelar_slot"("p_slot_id" "uuid") RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_paciente_id uuid := public.current_paciente_perfil_id();
  v_slot public.slots%ROWTYPE;
  v_result public.slots%ROWTYPE;
BEGIN
  IF v_user_id IS NULL OR v_paciente_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  SELECT *
  INTO v_slot
  FROM public.slots
  WHERE id = p_slot_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Turno no encontrado';
  END IF;

  IF v_slot.fecha < current_date THEN
    RAISE EXCEPTION 'No se pueden cancelar turnos pasados';
  END IF;

  UPDATE public.slots
  SET
    paciente_id = null,
    estado = 'cancelado',
    es_tanda = false,
    es_bloque_completo = false,
    apartado_por = null,
    apartado_ts = null
  WHERE id = p_slot_id
    AND paciente_id = v_paciente_id
    AND estado = 'ocupado'
  RETURNING * INTO v_result;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Solo puedes cancelar tus propios turnos ocupados';
  END IF;

  PERFORM public.whatsapp_enqueue_cancelacion_turno(
    v_paciente_id,
    v_result.id,
    v_result.fecha,
    v_result.hora,
    'portal_paciente_cancelacion'
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."paciente_cancelar_slot"("p_slot_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."paciente_reservar_slot"("p_slot_id" "uuid") RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
  v_paciente_id uuid := public.current_paciente_perfil_id();
  v_slot public.slots%ROWTYPE;
  v_result public.slots%ROWTYPE;
BEGIN
  IF v_user_id IS NULL OR v_paciente_id IS NULL THEN
    RAISE EXCEPTION 'No autorizado';
  END IF;

  SELECT *
  INTO v_slot
  FROM public.slots
  WHERE id = p_slot_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Turno no encontrado';
  END IF;

  IF v_slot.fecha < current_date THEN
    RAISE EXCEPTION 'No se pueden reservar turnos pasados';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.slots s
    WHERE s.fecha = v_slot.fecha
      AND s.paciente_id = v_paciente_id
      AND s.estado = 'ocupado'
      AND s.id <> p_slot_id
      AND ABS(
        EXTRACT(HOUR FROM s.hora::time) -
        EXTRACT(HOUR FROM v_slot.hora::time)
      ) <= 1
  ) THEN
    RAISE EXCEPTION 'No puedes reservar turnos consecutivos en el mismo dia';
  END IF;

  UPDATE public.slots
  SET
    paciente_id = v_paciente_id,
    estado = 'ocupado',
    es_tanda = false,
    es_bloque_completo = false,
    apartado_por = null,
    apartado_ts = null
  WHERE id = p_slot_id
    AND paciente_id IS NULL
    AND estado IN ('libre', 'cancelado')
  RETURNING * INTO v_result;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'El turno ya no esta disponible';
  END IF;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."paciente_reservar_slot"("p_slot_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."portal_register_rate_limit_attempt"("p_scope" "text", "p_route" "text", "p_ip_hash" "text", "p_identifier_hash" "text", "p_window_seconds" integer, "p_limit" integer, "p_timestamp" timestamp with time zone DEFAULT "now"(), "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("blocked" boolean, "attempt_count" integer, "limit_value" integer, "remaining" integer, "window_started_at" timestamp with time zone, "just_crossed_threshold" boolean, "last_decision" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  v_scope text := coalesce(nullif(trim(p_scope), ''), 'portal_public');
  v_route text := coalesce(nullif(trim(p_route), ''), 'unknown');
  v_ip_hash text := coalesce(trim(p_ip_hash), '');
  v_identifier_hash text := coalesce(trim(p_identifier_hash), '');
  v_window_seconds integer := greatest(coalesce(p_window_seconds, 1), 1);
  v_limit integer := greatest(coalesce(p_limit, 1), 1);
  v_window_started_at timestamptz;
  v_attempt_count integer;
  v_previous_attempt_count integer;
  v_blocked boolean;
  v_last_decision text;
begin
  v_window_started_at := to_timestamp(
    floor(extract(epoch from p_timestamp) / v_window_seconds) * v_window_seconds
  );

  select bucket.attempt_count
  into v_previous_attempt_count
  from public.portal_rate_limit_buckets as bucket
  where bucket.scope = v_scope
    and bucket.route = v_route
    and bucket.ip_hash = v_ip_hash
    and bucket.identifier_hash = v_identifier_hash
    and bucket.window_started_at = v_window_started_at;

  insert into public.portal_rate_limit_buckets (
    scope,
    route,
    ip_hash,
    identifier_hash,
    window_seconds,
    window_started_at,
    attempt_count,
    first_attempt_at,
    last_attempt_at,
    metadata
  )
  values (
    v_scope,
    v_route,
    v_ip_hash,
    v_identifier_hash,
    v_window_seconds,
    v_window_started_at,
    1,
    p_timestamp,
    p_timestamp,
    coalesce(p_metadata, '{}'::jsonb)
  )
  on conflict on constraint portal_rate_limit_buckets_pkey
  do update set
    attempt_count = public.portal_rate_limit_buckets.attempt_count + 1,
    last_attempt_at = excluded.last_attempt_at,
    metadata = coalesce(public.portal_rate_limit_buckets.metadata, '{}'::jsonb)
      || coalesce(excluded.metadata, '{}'::jsonb)
  returning public.portal_rate_limit_buckets.attempt_count
  into v_attempt_count;

  v_blocked := v_attempt_count > v_limit;
  v_last_decision := case when v_blocked then 'block' else 'allow' end;

  update public.portal_rate_limit_buckets as bucket
  set last_decision = v_last_decision
  where bucket.scope = v_scope
    and bucket.route = v_route
    and bucket.ip_hash = v_ip_hash
    and bucket.identifier_hash = v_identifier_hash
    and bucket.window_started_at = v_window_started_at;

  return query
  select
    v_blocked,
    v_attempt_count,
    v_limit,
    greatest(v_limit - v_attempt_count, 0),
    v_window_started_at,
    coalesce(v_previous_attempt_count, 0) <= v_limit and v_attempt_count > v_limit,
    v_last_decision;
end;
$$;


ALTER FUNCTION "public"."portal_register_rate_limit_attempt"("p_scope" "text", "p_route" "text", "p_ip_hash" "text", "p_identifier_hash" "text", "p_window_seconds" integer, "p_limit" integer, "p_timestamp" timestamp with time zone, "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."portal_register_rate_limit_attempt"("p_scope" "text", "p_route" "text", "p_ip_hash" "text", "p_identifier_hash" "text", "p_window_seconds" integer, "p_limit" integer, "p_timestamp" timestamp with time zone DEFAULT "now"(), "p_metadata" "jsonb" DEFAULT '{}'::"jsonb", "p_dry_run" boolean DEFAULT false) RETURNS TABLE("blocked" boolean, "attempt_count" integer, "limit_value" integer, "remaining" integer, "window_started_at" timestamp with time zone, "just_crossed_threshold" boolean, "last_decision" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  v_scope text := coalesce(nullif(trim(p_scope), ''), 'portal_public');
  v_route text := coalesce(nullif(trim(p_route), ''), 'unknown');
  v_ip_hash text := coalesce(trim(p_ip_hash), '');
  v_identifier_hash text := coalesce(trim(p_identifier_hash), '');
  v_window_seconds integer := greatest(coalesce(p_window_seconds, 1), 1);
  v_limit integer := greatest(coalesce(p_limit, 1), 1);
  v_window_started_at timestamptz;
  v_attempt_count integer;
  v_previous_attempt_count integer;
  v_blocked boolean;
  v_last_decision text;
begin
  v_window_started_at := to_timestamp(
    floor(extract(epoch from p_timestamp) / v_window_seconds) * v_window_seconds
  );

  if p_dry_run then
    -- Read-only: return current state without modifying the bucket.
    select bucket.attempt_count
    into v_attempt_count
    from public.portal_rate_limit_buckets as bucket
    where bucket.scope = v_scope
      and bucket.route = v_route
      and bucket.ip_hash = v_ip_hash
      and bucket.identifier_hash = v_identifier_hash
      and bucket.window_started_at = v_window_started_at;

    v_attempt_count := coalesce(v_attempt_count, 0);
    v_blocked := v_attempt_count > v_limit;
    v_last_decision := case when v_blocked then 'block' else 'allow' end;

    return query
    select
      v_blocked,
      v_attempt_count,
      v_limit,
      greatest(v_limit - v_attempt_count, 0),
      v_window_started_at,
      false,  -- just_crossed_threshold is always false in dry_run
      v_last_decision;
    return;
  end if;

  select bucket.attempt_count
  into v_previous_attempt_count
  from public.portal_rate_limit_buckets as bucket
  where bucket.scope = v_scope
    and bucket.route = v_route
    and bucket.ip_hash = v_ip_hash
    and bucket.identifier_hash = v_identifier_hash
    and bucket.window_started_at = v_window_started_at;

  insert into public.portal_rate_limit_buckets (
    scope,
    route,
    ip_hash,
    identifier_hash,
    window_seconds,
    window_started_at,
    attempt_count,
    first_attempt_at,
    last_attempt_at,
    metadata
  )
  values (
    v_scope,
    v_route,
    v_ip_hash,
    v_identifier_hash,
    v_window_seconds,
    v_window_started_at,
    1,
    p_timestamp,
    p_timestamp,
    coalesce(p_metadata, '{}'::jsonb)
  )
  on conflict on constraint portal_rate_limit_buckets_pkey
  do update set
    attempt_count = public.portal_rate_limit_buckets.attempt_count + 1,
    last_attempt_at = excluded.last_attempt_at,
    metadata = coalesce(public.portal_rate_limit_buckets.metadata, '{}'::jsonb)
      || coalesce(excluded.metadata, '{}'::jsonb)
  returning public.portal_rate_limit_buckets.attempt_count
  into v_attempt_count;

  v_blocked := v_attempt_count > v_limit;
  v_last_decision := case when v_blocked then 'block' else 'allow' end;

  update public.portal_rate_limit_buckets as bucket
  set last_decision = v_last_decision
  where bucket.scope = v_scope
    and bucket.route = v_route
    and bucket.ip_hash = v_ip_hash
    and bucket.identifier_hash = v_identifier_hash
    and bucket.window_started_at = v_window_started_at;

  return query
  select
    v_blocked,
    v_attempt_count,
    v_limit,
    greatest(v_limit - v_attempt_count, 0),
    v_window_started_at,
    coalesce(v_previous_attempt_count, 0) <= v_limit and v_attempt_count > v_limit,
    v_last_decision;
end;
$$;


ALTER FUNCTION "public"."portal_register_rate_limit_attempt"("p_scope" "text", "p_route" "text", "p_ip_hash" "text", "p_identifier_hash" "text", "p_window_seconds" integer, "p_limit" integer, "p_timestamp" timestamp with time zone, "p_metadata" "jsonb", "p_dry_run" boolean) OWNER TO "postgres";


