CREATE OR REPLACE FUNCTION "public"."rbac_rebuild_effective_permissions"("p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if p_user_id is null then
    delete from public.rbac_effective_permissions;

    insert into public.rbac_effective_permissions (user_id, permission_key, source_role_id)
    select
      ur.user_id,
      perm.key,
      ur.role_id
    from public.rbac_user_roles ur
    join public.rbac_roles r on r.id = ur.role_id and r.activo = true
    join public.rbac_role_permissions rp on rp.role_id = ur.role_id and rp.granted = true
    join public.rbac_permissions perm on perm.id = rp.permission_id
    where ur.expires_at is null
    group by ur.user_id, perm.key, ur.role_id;
  else
    delete from public.rbac_effective_permissions where user_id = p_user_id;

    insert into public.rbac_effective_permissions (user_id, permission_key, source_role_id)
    select
      ur.user_id,
      perm.key,
      ur.role_id
    from public.rbac_user_roles ur
    join public.rbac_roles r on r.id = ur.role_id and r.activo = true
    join public.rbac_role_permissions rp on rp.role_id = ur.role_id and rp.granted = true
    join public.rbac_permissions perm on perm.id = rp.permission_id
    where ur.expires_at is null
      and ur.user_id = p_user_id
    group by ur.user_id, perm.key, ur.role_id;
  end if;
end;
$$;


ALTER FUNCTION "public"."rbac_rebuild_effective_permissions"("p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rbac_rebuild_for_role"("p_role_id" bigint) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid;
begin
  for v_user_id in
    select ur.user_id
    from public.rbac_user_roles ur
    where ur.role_id = p_role_id
  loop
    perform public.rbac_rebuild_effective_permissions(v_user_id);
  end loop;
end;
$$;


