CREATE OR REPLACE FUNCTION "public"."record_portal_login_failure"("p_documento_identidad_normalizado" "text", "p_timestamp" timestamp with time zone, "p_paciente_id" "uuid" DEFAULT NULL::"uuid", "p_paciente_nombre" "text" DEFAULT NULL::"text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  v_documento_identidad_normalizado text := coalesce(nullif(trim(p_documento_identidad_normalizado), ''), 'unknown');
  v_window_started_at timestamptz := date_trunc('hour', p_timestamp);
  v_attempt_count integer;
begin
  insert into public.portal_login_failures (
    documento_identidad_normalizado,
    window_started_at,
    attempt_count,
    first_attempt_at,
    last_attempt_at,
    paciente_id,
    paciente_nombre,
    metadata
  )
  values (
    v_documento_identidad_normalizado,
    v_window_started_at,
    1,
    p_timestamp,
    p_timestamp,
    p_paciente_id,
    p_paciente_nombre,
    jsonb_build_object(
      'first_attempt_at', p_timestamp,
      'last_attempt_at', p_timestamp,
      'paciente_id', p_paciente_id,
      'paciente_nombre', p_paciente_nombre
    )
  )
  on conflict (documento_identidad_normalizado, window_started_at)
  do update set
    attempt_count = public.portal_login_failures.attempt_count + 1,
    last_attempt_at = excluded.last_attempt_at,
    paciente_id = coalesce(excluded.paciente_id, public.portal_login_failures.paciente_id),
    paciente_nombre = coalesce(excluded.paciente_nombre, public.portal_login_failures.paciente_nombre),
    metadata = coalesce(public.portal_login_failures.metadata, '{}'::jsonb)
      || jsonb_build_object(
        'last_attempt_at', excluded.last_attempt_at,
        'paciente_id', coalesce(excluded.paciente_id, public.portal_login_failures.paciente_id),
        'paciente_nombre', coalesce(excluded.paciente_nombre, public.portal_login_failures.paciente_nombre)
      )
  returning attempt_count into v_attempt_count;

  return v_attempt_count;
end;
$$;


ALTER FUNCTION "public"."record_portal_login_failure"("p_documento_identidad_normalizado" "text", "p_timestamp" timestamp with time zone, "p_paciente_id" "uuid", "p_paciente_nombre" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reparar_consultas_slots_rango"("p_fecha_inicio" "date", "p_fecha_fin" "date") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_fecha date;
  v_total integer := 0;
begin
  if p_fecha_inicio is null or p_fecha_fin is null or p_fecha_fin < p_fecha_inicio then
    raise exception 'Rango invalido';
  end if;

  for v_fecha in
    select generate_series(p_fecha_inicio, p_fecha_fin, interval '1 day')::date
  loop
    perform public.generar_consultas_slots_dia(v_fecha);
    v_total := v_total + 1;
  end loop;

  return v_total;
end;
$$;


ALTER FUNCTION "public"."reparar_consultas_slots_rango"("p_fecha_inicio" "date", "p_fecha_fin" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."resolve_profile_id"("p_user_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_profile_id uuid;
begin
  if p_user_id is null then
    return null;
  end if;

  select p.id
  into v_profile_id
  from public.perfiles p
  where p.id = p_user_id
  limit 1;

  if v_profile_id is not null then
    return v_profile_id;
  end if;

  select p.id
  into v_profile_id
  from public.perfiles p
  where p.auth_user_id = p_user_id
  order by p.created_at asc
  limit 1;

  return v_profile_id;
end;
$$;


