CREATE OR REPLACE FUNCTION "public"."whatsapp_cancelar_slot"("p_slot_id" "uuid", "p_phone_e164" "text", "p_message_action_id" "uuid") RETURNS "public"."slots"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_slot public.slots%ROWTYPE;
  v_result public.slots%ROWTYPE;
  v_action public.whatsapp_message_actions%ROWTYPE;
  v_phone_e164 text := public.normalize_phone_to_e164(p_phone_e164);
  v_patient_phone_e164 text;
BEGIN
  IF p_slot_id IS NULL OR p_message_action_id IS NULL OR v_phone_e164 IS NULL THEN
    RAISE EXCEPTION 'Parametros invalidos';
  END IF;

  SELECT *
  INTO v_action
  FROM public.whatsapp_message_actions
  WHERE id = p_message_action_id
    AND slot_id = p_slot_id
    AND action_kind = 'cancelar_turno';

  IF v_action.id IS NULL THEN
    RAISE EXCEPTION 'Accion de WhatsApp no encontrada';
  END IF;

  IF v_action.phone_e164 <> v_phone_e164 THEN
    RAISE EXCEPTION 'Telefono no autorizado para esta accion';
  END IF;

  SELECT *
  INTO v_slot
  FROM public.slots
  WHERE id = p_slot_id;

  IF v_slot.id IS NULL THEN
    RAISE EXCEPTION 'Turno no encontrado';
  END IF;

  IF v_slot.fecha < current_date THEN
    RAISE EXCEPTION 'No se pueden cancelar turnos pasados';
  END IF;

  IF v_slot.estado <> 'ocupado' OR v_slot.paciente_id IS NULL THEN
    RAISE EXCEPTION 'Solo se pueden cancelar turnos ocupados';
  END IF;

  SELECT public.normalize_phone_to_e164(p.telefono)
  INTO v_patient_phone_e164
  FROM public.perfiles p
  WHERE p.id = v_slot.paciente_id
    AND p.rol = 'paciente';

  IF v_patient_phone_e164 IS NULL OR v_patient_phone_e164 <> v_phone_e164 THEN
    RAISE EXCEPTION 'El telefono no coincide con el paciente del turno';
  END IF;

  UPDATE public.slots
  SET
    paciente_id = null,
    estado = 'cancelado',
    es_bloque_completo = false,
    apartado_por = null,
    apartado_ts = null
  WHERE id = p_slot_id
    AND paciente_id = v_action.patient_id
    AND estado = 'ocupado'
  RETURNING * INTO v_result;

  IF v_result.id IS NULL THEN
    RAISE EXCEPTION 'El turno ya no esta disponible para cancelarse';
  END IF;

  PERFORM public.admin_insert_historial_bloque(
    v_slot.fecha,
    v_slot.hora,
    v_slot.camara_id,
    v_slot.id,
    v_slot.lugar,
    'cancelado_por_whatsapp',
    v_action.patient_id,
    null,
    'Paciente cancelo por WhatsApp',
    v_slot.referido_tercero,
    v_slot.referente_id,
    v_slot.modalidad_cobro,
    v_slot.obra_social_id,
    v_slot.numero_autorizacion,
    v_slot.sesiones_autorizadas,
    v_slot.ciclo_obra_social_id,
    v_slot.medico_id,
    v_slot.es_nuevo_ingreso,
    v_slot.obra_social_validada_por,
    v_slot.obra_social_validada_at,
    v_slot.tanda_id
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."whatsapp_cancelar_slot"("p_slot_id" "uuid", "p_phone_e164" "text", "p_message_action_id" "uuid") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."whatsapp_dispatch_queue" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "patient_id" "uuid" NOT NULL,
    "slot_id" "uuid",
    "tanda_id" "uuid",
    "kind" "text" NOT NULL,
    "template_key" "text" NOT NULL,
    "idempotency_key" "text" NOT NULL,
    "trigger_source" "text" DEFAULT 'system'::"text" NOT NULL,
    "payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "attempts" integer DEFAULT 0 NOT NULL,
    "last_error" "text",
    "locked_at" timestamp with time zone,
    "processed_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "whatsapp_dispatch_queue_kind_check" CHECK (("kind" = ANY (ARRAY['confirmacion'::"text", 'confirmacion_tanda'::"text", 'recordatorio_24h'::"text", 'cancelacion'::"text"]))),
    CONSTRAINT "whatsapp_dispatch_queue_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'processing'::"text", 'processed'::"text", 'failed'::"text", 'skipped'::"text"])))
);


ALTER TABLE "public"."whatsapp_dispatch_queue" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."whatsapp_claim_dispatch_queue"("p_limit" integer DEFAULT 25, "p_slot_ids" "uuid"[] DEFAULT NULL::"uuid"[]) RETURNS SETOF "public"."whatsapp_dispatch_queue"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH candidates AS (
    SELECT q.id
    FROM public.whatsapp_dispatch_queue q
    WHERE q.status IN ('pending', 'failed')
      AND (q.locked_at IS NULL OR q.locked_at < now() - interval '10 minutes')
      AND (p_slot_ids IS NULL OR q.slot_id = ANY(p_slot_ids))
    ORDER BY q.created_at
    LIMIT GREATEST(coalesce(p_limit, 25), 1)
    FOR UPDATE SKIP LOCKED
  )
  UPDATE public.whatsapp_dispatch_queue q
  SET
    status = 'processing',
    attempts = coalesce(q.attempts, 0) + 1,
    locked_at = now(),
    updated_at = now()
  FROM candidates c
  WHERE q.id = c.id
  RETURNING q.*;
END;
$$;


ALTER FUNCTION "public"."whatsapp_claim_dispatch_queue"("p_limit" integer, "p_slot_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."whatsapp_enlistar_recordatorios_dia"("p_fecha_objetivo" "date") RETURNS TABLE("slot_id" "uuid", "paciente_id" "uuid", "fecha" "date", "hora" "text")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    s.id AS slot_id,
    s.paciente_id AS paciente_id,
    s.fecha,
    s.hora
  FROM public.slots s
  JOIN public.perfiles p
    ON p.id = s.paciente_id
  WHERE s.estado = 'ocupado'
    AND s.paciente_id IS NOT NULL
    AND coalesce(p.opt_in_whatsapp, false) = true
    AND nullif(trim(coalesce(p.telefono, '')), '') IS NOT NULL
    AND s.fecha = p_fecha_objetivo
    AND NOT EXISTS (
      SELECT 1
      FROM public.whatsapp_messages wm
      WHERE wm.slot_id = s.id
        AND wm.kind = 'recordatorio_24h'
    )
    AND NOT EXISTS (
      SELECT 1
      FROM public.whatsapp_dispatch_queue wdq
      WHERE wdq.slot_id = s.id
        AND wdq.kind = 'recordatorio_24h'
        AND wdq.status IN ('pending', 'processing', 'processed')
    );
$$;


ALTER FUNCTION "public"."whatsapp_enlistar_recordatorios_dia"("p_fecha_objetivo" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."whatsapp_enqueue_cancelacion_multiple"("p_patient_id" "uuid", "p_slot_ids" "uuid"[], "p_operation_key" "text", "p_trigger_source" "text" DEFAULT 'cancelacion_admin'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_patient public.perfiles%ROWTYPE;
  v_queue_id uuid;
  v_idempotency_key text;
  v_representative_slot_id uuid;
  v_cancelled_slots jsonb := '[]'::jsonb;
  v_operation_key text := coalesce(nullif(trim(coalesce(p_operation_key, '')), ''), 'cancelacion_multiple');
BEGIN
  IF p_patient_id IS NULL OR coalesce(array_length(p_slot_ids, 1), 0) = 0 THEN
    RETURN NULL;
  END IF;

  SELECT *
  INTO v_patient
  FROM public.perfiles
  WHERE id = p_patient_id
    AND rol = 'paciente';

  IF v_patient.id IS NULL
     OR coalesce(v_patient.opt_in_whatsapp, false) IS NOT TRUE
     OR nullif(trim(coalesce(v_patient.telefono, '')), '') IS NULL
  THEN
    RETURN NULL;
  END IF;

  SELECT s.id
  INTO v_representative_slot_id
  FROM public.slots s
  WHERE s.id = ANY(p_slot_ids)
  ORDER BY s.fecha, s.hora, s.camara_id, s.lugar
  LIMIT 1;

  SELECT
    coalesce(
      jsonb_agg(
        jsonb_build_object(
          'slot_id', s.id,
          'fecha', s.fecha,
          'hora', s.hora
        )
        ORDER BY s.fecha, s.hora, s.camara_id, s.lugar
      ),
      '[]'::jsonb
    )
  INTO v_cancelled_slots
  FROM public.slots s
  WHERE s.id = ANY(p_slot_ids);

  IF v_representative_slot_id IS NULL OR v_cancelled_slots = '[]'::jsonb THEN
    RETURN NULL;
  END IF;

  v_idempotency_key := format('cancelacion_multiple:%s:%s', v_operation_key, p_patient_id);

  INSERT INTO public.whatsapp_dispatch_queue (
    patient_id, slot_id, kind, template_key, idempotency_key, trigger_source, payload
  )
  VALUES (
    v_patient.id,
    v_representative_slot_id,
    'cancelacion',
    'turno_cancelacion_multiple_v1',
    v_idempotency_key,
    coalesce(nullif(trim(coalesce(p_trigger_source, '')), ''), 'cancelacion_admin'),
    jsonb_build_object(
      'operation_key', v_operation_key,
      'cancelled_slots', v_cancelled_slots
    )
  )
  ON CONFLICT (idempotency_key) DO NOTHING
  RETURNING id INTO v_queue_id;

  RETURN v_queue_id;
END;
$$;


ALTER FUNCTION "public"."whatsapp_enqueue_cancelacion_multiple"("p_patient_id" "uuid", "p_slot_ids" "uuid"[], "p_operation_key" "text", "p_trigger_source" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."whatsapp_enqueue_cancelacion_turno"("p_patient_id" "uuid", "p_slot_id" "uuid", "p_fecha" "date", "p_hora" "text", "p_trigger_source" "text" DEFAULT 'cancelacion_admin'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_patient public.perfiles%ROWTYPE;
  v_slot public.slots%ROWTYPE;
  v_queue_id uuid;
  v_idempotency_key text;
BEGIN
  IF p_patient_id IS NULL OR p_slot_id IS NULL OR p_fecha IS NULL OR nullif(trim(coalesce(p_hora, '')), '') IS NULL THEN
    RETURN NULL;
  END IF;

  SELECT *
  INTO v_patient
  FROM public.perfiles
  WHERE id = p_patient_id
    AND rol = 'paciente';

  IF v_patient.id IS NULL
     OR coalesce(v_patient.opt_in_whatsapp, false) IS NOT TRUE
     OR nullif(trim(coalesce(v_patient.telefono, '')), '') IS NULL
  THEN
    RETURN NULL;
  END IF;

  SELECT *
  INTO v_slot
  FROM public.slots
  WHERE id = p_slot_id;

  IF v_slot.id IS NULL THEN
    RETURN NULL;
  END IF;

  v_idempotency_key := format(
    'cancelacion:%s:%s',
    p_slot_id,
    to_char(v_slot.updated_at AT TIME ZONE 'UTC', 'YYYYMMDDHH24MISSUS')
  );

  INSERT INTO public.whatsapp_dispatch_queue (
    patient_id, slot_id, kind, template_key, idempotency_key, trigger_source, payload
  )
  VALUES (
    v_patient.id,
    p_slot_id,
    'cancelacion',
    'turno_cancelacion_v1',
    v_idempotency_key,
    coalesce(nullif(trim(coalesce(p_trigger_source, '')), ''), 'cancelacion_admin'),
    jsonb_build_object(
      'cancelled_slots',
      jsonb_build_array(
        jsonb_build_object(
          'slot_id', p_slot_id,
          'fecha', p_fecha,
          'hora', p_hora
        )
      )
    )
  )
  ON CONFLICT (idempotency_key) DO NOTHING
  RETURNING id INTO v_queue_id;

  RETURN v_queue_id;
END;
$$;


ALTER FUNCTION "public"."whatsapp_enqueue_cancelacion_turno"("p_patient_id" "uuid", "p_slot_id" "uuid", "p_fecha" "date", "p_hora" "text", "p_trigger_source" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."whatsapp_enqueue_confirmacion_tanda"("p_tanda_id" "uuid", "p_trigger_source" "text" DEFAULT 'slot_ocupado'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_slot public.slots%ROWTYPE;
  v_patient public.perfiles%ROWTYPE;
  v_queue_id uuid;
  v_idempotency_key text;
BEGIN
  IF p_tanda_id IS NULL THEN
    RETURN NULL;
  END IF;

  SELECT *
  INTO v_slot
  FROM public.slots
  WHERE tanda_id = p_tanda_id
    AND estado = 'ocupado'
  ORDER BY fecha, hora, camara_id, lugar
  LIMIT 1;

  IF v_slot.id IS NULL OR v_slot.paciente_id IS NULL THEN
    RETURN NULL;
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.slots s
    WHERE s.tanda_id = p_tanda_id
      AND s.estado = 'ocupado'
      AND s.paciente_id IS DISTINCT FROM v_slot.paciente_id
  ) THEN
    RETURN NULL;
  END IF;

  SELECT *
  INTO v_patient
  FROM public.perfiles
  WHERE id = v_slot.paciente_id
    AND rol = 'paciente';

  IF v_patient.id IS NULL
     OR coalesce(v_patient.opt_in_whatsapp, false) IS NOT TRUE
     OR nullif(trim(coalesce(v_patient.telefono, '')), '') IS NULL
  THEN
    RETURN NULL;
  END IF;

  v_idempotency_key := format('confirmacion_tanda:%s', p_tanda_id);

  INSERT INTO public.whatsapp_dispatch_queue (
    patient_id, slot_id, tanda_id, kind, template_key, idempotency_key, trigger_source, payload
  )
  VALUES (
    v_patient.id,
    v_slot.id,
    p_tanda_id,
    'confirmacion_tanda',
    'turno_confirmacion_tanda_v1',
    v_idempotency_key,
    coalesce(nullif(trim(coalesce(p_trigger_source, '')), ''), 'slot_ocupado'),
    jsonb_build_object(
      'primer_slot_id', v_slot.id,
      'fecha', v_slot.fecha,
      'hora', v_slot.hora
    )
  )
  ON CONFLICT (idempotency_key) DO NOTHING
  RETURNING id INTO v_queue_id;

  RETURN v_queue_id;
END;
$$;


ALTER FUNCTION "public"."whatsapp_enqueue_confirmacion_tanda"("p_tanda_id" "uuid", "p_trigger_source" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."whatsapp_enqueue_turno_confirmado"("p_slot_id" "uuid", "p_trigger_source" "text" DEFAULT 'slot_ocupado'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_slot public.slots%ROWTYPE;
  v_patient public.perfiles%ROWTYPE;
  v_queue_id uuid;
  v_idempotency_key text;
BEGIN
  IF p_slot_id IS NULL THEN
    RETURN NULL;
  END IF;

  SELECT *
  INTO v_slot
  FROM public.slots
  WHERE id = p_slot_id;

  IF v_slot.id IS NULL OR v_slot.estado <> 'ocupado' OR v_slot.paciente_id IS NULL THEN
    RETURN NULL;
  END IF;

  SELECT *
  INTO v_patient
  FROM public.perfiles
  WHERE id = v_slot.paciente_id
    AND rol = 'paciente';

  IF v_patient.id IS NULL
     OR coalesce(v_patient.opt_in_whatsapp, false) IS NOT TRUE
     OR nullif(trim(coalesce(v_patient.telefono, '')), '') IS NULL
  THEN
    RETURN NULL;
  END IF;

  v_idempotency_key := format(
    'confirmacion:%s:%s',
    v_slot.id,
    to_char(v_slot.updated_at AT TIME ZONE 'UTC', 'YYYYMMDDHH24MISSUS')
  );

  INSERT INTO public.whatsapp_dispatch_queue (
    patient_id, slot_id, kind, template_key, idempotency_key, trigger_source, payload
  )
  VALUES (
    v_patient.id,
    v_slot.id,
    'confirmacion',
    'turno_confirmacion_v1',
    v_idempotency_key,
    coalesce(nullif(trim(coalesce(p_trigger_source, '')), ''), 'slot_ocupado'),
    jsonb_build_object(
      'fecha', v_slot.fecha,
      'hora', v_slot.hora,
      'camara_id', v_slot.camara_id
    )
  )
  ON CONFLICT (idempotency_key) DO NOTHING
  RETURNING id INTO v_queue_id;

  RETURN v_queue_id;
END;
$$;


ALTER FUNCTION "public"."whatsapp_enqueue_turno_confirmado"("p_slot_id" "uuid", "p_trigger_source" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."whatsapp_on_slot_ocupado"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.estado = 'ocupado'
     AND NEW.paciente_id IS NOT NULL
     AND (
       TG_OP = 'INSERT'
       OR OLD.estado IS DISTINCT FROM 'ocupado'
       OR OLD.paciente_id IS DISTINCT FROM NEW.paciente_id
     )
  THEN
    IF NEW.tanda_id IS NOT NULL THEN
      PERFORM public.whatsapp_enqueue_confirmacion_tanda(NEW.tanda_id, 'slot_ocupado');
    ELSE
      PERFORM public.whatsapp_enqueue_turno_confirmado(NEW.id, 'slot_ocupado');
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."whatsapp_on_slot_ocupado"() OWNER TO "postgres";


