-- Fix PG42P01 in admin_confirmar_cierre_diario.
CREATE OR REPLACE FUNCTION "public"."admin_parse_cierre_diario_detalles_submitted"("p_detalles" "jsonb") RETURNS TABLE("slot_id" "uuid", "turno_fuera_horario_id" "uuid", "asistio" boolean)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  with parsed as (
    select
      nullif(trim(coalesce(value ->> 'slot_id', '')), '')::uuid as slot_id,
      nullif(trim(coalesce(value ->> 'turno_fuera_horario_id', '')), '')::uuid as turno_fuera_horario_id,
      coalesce((value ->> 'asistio')::boolean, true) as asistio
    from jsonb_array_elements(coalesce(p_detalles, '[]'::jsonb)) as value
  ),
  submitted as (
    select slot_id, null::uuid as turno_fuera_horario_id, asistio
    from (
      select distinct on (slot_id) slot_id, asistio
      from parsed
      where slot_id is not null
        and turno_fuera_horario_id is null
      order by slot_id
    ) a
    union all
    select null::uuid, turno_fuera_horario_id, asistio
    from (
      select distinct on (turno_fuera_horario_id) turno_fuera_horario_id, asistio
      from parsed
      where turno_fuera_horario_id is not null
        and slot_id is null
      order by turno_fuera_horario_id
    ) b
  )
  select submitted.slot_id, submitted.turno_fuera_horario_id, submitted.asistio from submitted;
$$;

