GRANT ALL ON FUNCTION "public"."admin_parse_cierre_diario_detalles_submitted"("p_detalles" "jsonb") TO "authenticated";
GRANT ALL ON FUNCTION "public"."admin_parse_cierre_diario_detalles_submitted"("p_detalles" "jsonb") TO "service_role";

CREATE OR REPLACE FUNCTION "public"."admin_confirmar_cierre_diario"("p_fecha" "date", "p_detalles" "jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_actor_perfil_id uuid := public.auth_current_profile_id();
  v_cierre_id uuid;
  v_preview_count integer;
  v_submitted_count integer;
  v_matching_count integer;
begin
  if v_user_id is null or v_actor_perfil_id is null then
    raise exception 'No autorizado';
  end if;

  if not public.auth_has_permission('turnos.cierre_diario') then
    raise exception 'Prohibido';
  end if;

  if p_fecha is null then
    raise exception 'Fecha requerida';
  end if;

  if exists (select 1 from public.cierres_diarios where fecha = p_fecha) then
    raise exception 'La fecha ya tiene un cierre diario confirmado';
  end if;

  select count(*) into v_preview_count
  from public.admin_build_cierre_diario_preview_rows(p_fecha);

  if coalesce(v_preview_count, 0) = 0 then
    raise exception 'No hay turnos para cerrar en esa fecha';
  end if;

  select count(*) into v_submitted_count
  from public.admin_parse_cierre_diario_detalles_submitted(p_detalles);

  select count(*) into v_matching_count
  from public.admin_build_cierre_diario_preview_rows(p_fecha) preview
  join public.admin_parse_cierre_diario_detalles_submitted(p_detalles) s
    on preview.slot_id is not distinct from s.slot_id and preview.turno_fuera_horario_id is not distinct from s.turno_fuera_horario_id;

  if v_submitted_count <> v_preview_count or v_matching_count <> v_preview_count then
    raise exception 'Los turnos del cierre cambiaron. Recarga el cierre diario antes de confirmar';
  end if;

  insert into public.cierres_diarios (fecha, estado, cerrado_por, cerrado_at)
  values (p_fecha, 'cerrado', v_actor_perfil_id, now())
  returning id into v_cierre_id;

  insert into public.cierre_diario_detalles (
    cierre_id,
    slot_id,
    turno_fuera_horario_id,
    slot_ids,
    paciente_id,
    fecha,
    hora,
    camara_id,
    paciente_numero_dia,
    nombre_paciente,
    sesion_numero,
    sesion_numero_historico,
    modalidad_cobro,
    obra_social_id,
    obra_social_nombre,
    obra_social_abreviatura,
    importe,
    numero_autorizacion,
    sesiones_autorizadas,
    ciclo_obra_social_id,
    es_nuevo_ingreso,
    medico_id,
    medico_nombre,
    es_monoxido,
    es_oxibarica,
    asistio
  )
  select
    v_cierre_id,
    preview.slot_id,
    preview.turno_fuera_horario_id,
    preview.slot_ids,
    preview.paciente_id,
    preview.fecha,
    preview.hora,
    preview.camara_id,
    preview.paciente_numero_dia,
    preview.nombre_paciente,
    preview.sesion_numero,
    preview.sesion_numero_historico,
    preview.modalidad_cobro,
    preview.obra_social_id,
    preview.obra_social_nombre,
    preview.obra_social_abreviatura,
    0::numeric(12,2),
    preview.numero_autorizacion,
    preview.sesiones_autorizadas,
    preview.ciclo_obra_social_id,
    preview.es_nuevo_ingreso,
    preview.medico_id,
    preview.medico_nombre,
    preview.es_monoxido,
    preview.es_oxibarica,
    s.asistio
  from public.admin_build_cierre_diario_preview_rows(p_fecha) preview
  join public.admin_parse_cierre_diario_detalles_submitted(p_detalles) s
    on preview.slot_id is not distinct from s.slot_id
   and preview.turno_fuera_horario_id is not distinct from s.turno_fuera_horario_id;

  insert into public.sesiones (
    paciente_id,
    slot_id,
    fecha,
    hora,
    camara_id,
    modalidad_cobro,
    obra_social_id,
    numero_autorizacion,
    sesiones_autorizadas,
    ciclo_obra_social_id,
    cierre_id
  )
  select
    detalle.paciente_id,
    detalle.slot_id,
    detalle.fecha,
    detalle.hora,
    detalle.camara_id,
    detalle.modalidad_cobro,
    case when detalle.modalidad_cobro = 'obra_social' then detalle.obra_social_id else null end,
    case when detalle.modalidad_cobro = 'obra_social' then detalle.numero_autorizacion else null end,
    case when detalle.modalidad_cobro = 'obra_social' then detalle.sesiones_autorizadas else null end,
    case when detalle.modalidad_cobro = 'obra_social' then detalle.ciclo_obra_social_id else null end,
    v_cierre_id
  from public.cierre_diario_detalles detalle
  where detalle.cierre_id = v_cierre_id
    and detalle.asistio = true;

  update public.perfiles p
  set primera_sesion_efectivizada = true
  where p.id in (
    select distinct detalle.paciente_id
    from public.cierre_diario_detalles detalle
    where detalle.cierre_id = v_cierre_id
      and detalle.asistio = true
      and detalle.paciente_id is not null
  );

  return v_cierre_id;
end;
$$;

ALTER FUNCTION "public"."admin_confirmar_cierre_diario"("p_fecha" "date", "p_detalles" "jsonb") OWNER TO "postgres";

-- SEC-205 / TM-029.
CREATE OR REPLACE FUNCTION public.admin_event_from_import_job()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $$
declare
  v_actor_user_id uuid := coalesce(new.created_by, public.auth_current_profile_id());
  v_action_code text;
  v_title text;
  v_summary text;
  v_source_record_key text;
begin
  if tg_op = 'INSERT' then
    v_action_code := 'import.job_created';
    v_title := 'Importación iniciada';
    v_summary := coalesce(nullif(trim(new.file_name), ''), 'Archivo') || ' • ' || coalesce(nullif(trim(new.import_type), ''), 'pacientes');
    v_source_record_key := format('import_jobs:%s:created', new.id);

    perform public.admin_append_event(
      p_occurred_at => coalesce(new.created_at, now()),
      p_actor_user_id => v_actor_user_id,
      p_action_code => v_action_code,
      p_action_family => 'importaciones',
      p_entity_type => 'import_job',
      p_entity_id => new.id::text,
      p_title => v_title,
      p_summary => v_summary,
      p_source_system => 'import_jobs',
      p_source_record_key => v_source_record_key,
      p_metadata => jsonb_strip_nulls(jsonb_build_object(
        'job_id', new.id,
        'import_type', new.import_type,
        'estado', new.estado,
        'file_name', new.file_name
      ))
    );

    return new;
  end if;

  if tg_op = 'UPDATE' then
    if coalesce(old.estado, '') is distinct from coalesce(new.estado, '') then
      if new.estado = 'completed' then
        v_action_code := 'import.job_completed';
        v_title := 'Importación completada';
      elsif new.estado = 'completed_with_errors' then
        v_action_code := 'import.job_completed_with_errors';
        v_title := 'Importación completada con errores';
      elsif new.estado = 'failed' then
        v_action_code := 'import.job_failed';
        v_title := 'Importación fallida';
      else
        v_action_code := 'import.job_state_changed';
        v_title := 'Importación actualizada';
      end if;

      v_summary := coalesce(nullif(trim(new.file_name), ''), 'Archivo') || ' • ' || coalesce(nullif(trim(new.estado), ''), 'estado');
      v_source_record_key := format('import_jobs:%s:estado:%s', new.id, coalesce(nullif(trim(new.estado), ''), 'unknown'));

      perform public.admin_append_event(
        p_occurred_at => coalesce(new.updated_at, now()),
        p_actor_user_id => v_actor_user_id,
        p_action_code => v_action_code,
        p_action_family => 'importaciones',
        p_entity_type => 'import_job',
        p_entity_id => new.id::text,
        p_title => v_title,
        p_summary => v_summary,
        p_source_system => 'import_jobs',
        p_source_record_key => v_source_record_key,
        p_metadata => jsonb_strip_nulls(jsonb_build_object(
          'job_id', new.id,
          'import_type', new.import_type,
          'estado', new.estado,
          'estado_prev', old.estado,
          'file_name', new.file_name
        ))
      );
    end if;

    return new;
  end if;

  return new;
end;
$$;

DROP TRIGGER IF EXISTS admin_event_feed_import_jobs ON public.import_jobs;
CREATE TRIGGER admin_event_feed_import_jobs
AFTER INSERT OR UPDATE ON public.import_jobs
FOR EACH ROW
EXECUTE FUNCTION public.admin_event_from_import_job();

CREATE OR REPLACE FUNCTION public.admin_crear_nota_paciente(p_paciente_id uuid, p_mensaje text)
RETURNS public.notas_paciente
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $$
declare
  v_actor_user_id uuid := public.auth_current_profile_id();
  v_actor_label text;
  v_paciente_nombre text;
  v_result public.notas_paciente%rowtype;
begin
  if not public.can_pacientes_editar() then
    raise exception 'Prohibido';
  end if;

  select nombre into v_actor_label from public.perfiles where id = v_actor_user_id;
  select nombre into v_paciente_nombre from public.perfiles where id = p_paciente_id;

  insert into public.notas_paciente (paciente_id, autor_id, mensaje)
  values (p_paciente_id, v_actor_user_id, nullif(trim(coalesce(p_mensaje, '')), ''))
  returning * into v_result;

  perform public.admin_append_event(
    p_actor_user_id => v_actor_user_id,
    p_actor_label => v_actor_label,
    p_action_code => 'paciente.nota_creada',
    p_action_family => 'consultas',
    p_entity_type => 'nota_paciente',
    p_entity_id => v_result.id::text,
    p_paciente_id => p_paciente_id,
    p_paciente_nombre => v_paciente_nombre,
    p_title => 'Nota creada',
    p_summary => coalesce(v_paciente_nombre, 'Paciente'),
    p_source_system => 'notas_paciente',
    p_source_record_key => format('%s:created', v_result.id),
    p_metadata => jsonb_strip_nulls(jsonb_build_object(
      'nota_id', v_result.id,
      'paciente_id', p_paciente_id
    ))
  );

  return v_result;
end;
$$;

CREATE OR REPLACE FUNCTION public.admin_eliminar_nota_paciente(p_nota_id uuid)
RETURNS uuid
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $$
declare
  v_actor_user_id uuid := public.auth_current_profile_id();
  v_actor_label text;
  v_paciente_id uuid;
  v_paciente_nombre text;
  v_deleted_id uuid;
begin
  if not public.can_pacientes_editar() then
    raise exception 'Prohibido';
  end if;

  select nombre into v_actor_label from public.perfiles where id = v_actor_user_id;

  select paciente_id into v_paciente_id
  from public.notas_paciente
  where id = p_nota_id;

  if v_paciente_id is not null then
    select nombre into v_paciente_nombre from public.perfiles where id = v_paciente_id;
  end if;

  delete from public.notas_paciente
  where id = p_nota_id
  returning id into v_deleted_id;

  if v_deleted_id is null then
    raise exception 'Nota no encontrada';
  end if;

  perform public.admin_append_event(
    p_actor_user_id => v_actor_user_id,
    p_actor_label => v_actor_label,
    p_action_code => 'paciente.nota_eliminada',
    p_action_family => 'consultas',
    p_entity_type => 'nota_paciente',
    p_entity_id => v_deleted_id::text,
    p_paciente_id => v_paciente_id,
    p_paciente_nombre => v_paciente_nombre,
    p_title => 'Nota eliminada',
    p_summary => coalesce(v_paciente_nombre, 'Paciente'),
    p_source_system => 'notas_paciente',
    p_source_record_key => format('%s:deleted', v_deleted_id),
    p_metadata => jsonb_strip_nulls(jsonb_build_object(
      'nota_id', v_deleted_id,
      'paciente_id', v_paciente_id
    ))
  );

  return v_deleted_id;
end;
$$;

CREATE OR REPLACE FUNCTION public.admin_export_cierre_diario(p_fecha date DEFAULT null::date, p_cierre_id uuid DEFAULT null::uuid)
RETURNS TABLE(
  cierre_id uuid,
  slot_id uuid,
  turno_fuera_horario_id uuid,
  paciente_id uuid,
  fecha date,
  hora text,
  camara_id integer,
  paciente_numero_dia integer,
  nombre_paciente text,
  sesion_numero integer,
  modalidad_cobro public.modalidad_cobro_turno,
  obra_social_id integer,
  obra_social_nombre text,
  obra_social_abreviatura text,
  importe numeric,
  numero_autorizacion text,
  es_nuevo_ingreso boolean,
  medico_id integer,
  medico_nombre text,
  es_monoxido boolean,
  es_oxibarica boolean
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $$
declare
  v_actor_user_id uuid := public.auth_current_profile_id();
  v_cierre_id uuid;
begin
  if not public.can_reportes_export() then
    raise exception 'Prohibido';
  end if;

  select coalesce(p_cierre_id, c.id)
  into v_cierre_id
  from public.cierres_diarios c
  where (p_cierre_id is not null and c.id = p_cierre_id)
     or (p_cierre_id is null and p_fecha is not null and c.fecha = p_fecha)
  order by c.created_at desc
  limit 1;

  perform public.admin_append_event(
    p_actor_user_id => v_actor_user_id,
    p_action_code => 'export.cierre_diario',
    p_action_family => 'reportes',
    p_entity_type => 'cierre_diario',
    p_entity_id => coalesce(v_cierre_id::text, coalesce(p_fecha::text, 'sin-fecha')),
    p_title => 'Export de cierre diario',
    p_summary => coalesce(p_fecha::text, 'sin-fecha'),
    p_source_system => 'cierres_diarios',
    p_source_record_key => format('export:cierre_diario:%s:%s', coalesce(v_cierre_id::text, 'unknown'), to_char(clock_timestamp() at time zone 'UTC', 'YYYYMMDDHH24MISSUS')),
    p_metadata => jsonb_strip_nulls(jsonb_build_object(
      'cierre_id', v_cierre_id,
      'fecha', p_fecha
    ))
  );

  return query
    select * from public.admin_get_cierre_diario_export(p_fecha => p_fecha, p_cierre_id => p_cierre_id);
end;
$$;

CREATE OR REPLACE FUNCTION public.admin_export_cierre_mensual(p_anio integer, p_mes integer)
RETURNS TABLE(
  cierre_id uuid,
  slot_id uuid,
  turno_fuera_horario_id uuid,
  paciente_id uuid,
  fecha date,
  hora text,
  camara_id integer,
  paciente_numero_dia integer,
  nombre_paciente text,
  sesion_numero_mes integer,
  modalidad_cobro public.modalidad_cobro_turno,
  obra_social_id integer,
  obra_social_nombre text,
  obra_social_abreviatura text,
  importe numeric,
  numero_autorizacion text,
  es_nuevo_ingreso boolean,
  medico_id integer,
  medico_nombre text,
  es_monoxido boolean,
  es_oxibarica boolean,
  factura_numero text
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $$
declare
  v_actor_user_id uuid := public.auth_current_profile_id();
begin
  if not public.can_reportes_export() then
    raise exception 'Prohibido';
  end if;

  perform public.admin_append_event(
    p_actor_user_id => v_actor_user_id,
    p_action_code => 'export.cierre_mensual',
    p_action_family => 'reportes',
    p_entity_type => 'cierre_mensual',
    p_entity_id => format('%s-%s', p_anio, lpad(p_mes::text, 2, '0')),
    p_title => 'Export de cierre mensual',
    p_summary => format('%s-%s', p_anio, lpad(p_mes::text, 2, '0')),
    p_source_system => 'cierres_diarios',
    p_source_record_key => format('export:cierre_mensual:%s-%s:%s', p_anio, lpad(p_mes::text, 2, '0'), to_char(clock_timestamp() at time zone 'UTC', 'YYYYMMDDHH24MISSUS')),
    p_metadata => jsonb_strip_nulls(jsonb_build_object(
      'anio', p_anio,
      'mes', p_mes
    ))
  );

  return query
    select * from public.admin_get_cierre_mensual_export(p_anio => p_anio, p_mes => p_mes);
end;
$$;

GRANT ALL ON FUNCTION public.admin_export_cierre_diario(p_fecha date, p_cierre_id uuid) TO anon, authenticated, service_role;
GRANT ALL ON FUNCTION public.admin_export_cierre_mensual(p_anio integer, p_mes integer) TO anon, authenticated, service_role;

-- SEC-206 / TM-036 alertas mínimas.
create or replace function public.admin_event_emit_minimum_alerts()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
declare
  v_now timestamptz := coalesce(new.occurred_at, now());
  v_count integer := 0;
  v_bucket text;
  v_entity_id text;
begin
  if new.action_family = 'security_alert' then
    return new;
  end if;

  if new.action_code = 'portal.login_failed' then
    select count(*)
      into v_count
      from public.admin_event_feed e
     where e.action_code = 'portal.login_failed'
       and e.entity_id = new.entity_id
       and e.occurred_at >= (v_now - interval '15 minutes');

    if v_count >= 6 then
      v_bucket := to_char(date_trunc('minute', v_now), 'YYYYMMDDHH24MI');
      insert into public.admin_event_feed (
        occurred_at, actor_user_id, actor_label, action_code, action_family,
        entity_type, entity_id, title, summary, source_system, source_record_key, metadata
      )
      values (
        v_now, null, 'Sistema', 'security.alert.login_failures', 'security_alert',
        'portal_access', coalesce(new.entity_id, 'portal-sign-in'),
        'Alerta: intentos fallidos elevados',
        'Se detectaron multiples intentos fallidos en ventana corta.',
        'security_alerts', concat('login_failures:', coalesce(new.entity_id, 'unknown'), ':', v_bucket),
        jsonb_build_object(
          'threshold', 6,
          'window_minutes', 15,
          'observed_count', v_count,
          'source_action', new.action_code
        )
      )
      on conflict (source_system, source_record_key) do nothing;
    end if;
  end if;

  if new.action_code in ('portal.access_token_reset_requested', 'portal.access_token_reset_issued', 'portal.access_reset_completed') then
    select count(*)
      into v_count
      from public.admin_event_feed e
     where e.action_code in ('portal.access_token_reset_requested', 'portal.access_token_reset_issued', 'portal.access_reset_completed')
       and e.paciente_id is not distinct from new.paciente_id
       and e.occurred_at >= (v_now - interval '24 hours');

    if new.paciente_id is not null and v_count >= 3 then
      v_bucket := to_char(date_trunc('hour', v_now), 'YYYYMMDDHH24');
      insert into public.admin_event_feed (
        occurred_at, actor_user_id, actor_label, action_code, action_family,
        entity_type, entity_id, paciente_id, paciente_nombre, title, summary,
        source_system, source_record_key, metadata
      )
      values (
        v_now, null, 'Sistema', 'security.alert.repeated_resets', 'security_alert',
        'paciente', new.paciente_id::text, new.paciente_id, new.paciente_nombre,
        'Alerta: resets repetidos de acceso',
        'Paciente con multiples eventos de alta/reset en 24h.',
        'security_alerts', concat('repeated_resets:', new.paciente_id::text, ':', v_bucket),
        jsonb_build_object(
          'threshold', 3,
          'window_hours', 24,
          'observed_count', v_count,
          'source_action', new.action_code
        )
      )
      on conflict (source_system, source_record_key) do nothing;
    end if;
  end if;

  if new.action_code in ('paciente.nota_creada', 'paciente.nota_eliminada', 'export.cierre_diario', 'export.cierre_mensual') then
    select count(*)
      into v_count
      from public.admin_event_feed e
     where e.action_code in ('paciente.nota_creada', 'paciente.nota_eliminada', 'export.cierre_diario', 'export.cierre_mensual')
       and e.actor_user_id is not distinct from new.actor_user_id
       and e.occurred_at >= (v_now - interval '60 minutes');

    if new.actor_user_id is not null and v_count >= 20 then
      v_bucket := to_char(date_trunc('hour', v_now), 'YYYYMMDDHH24');
      insert into public.admin_event_feed (
        occurred_at, actor_user_id, actor_label, action_code, action_family,
        entity_type, entity_id, title, summary, source_system, source_record_key, metadata
      )
      values (
        v_now, new.actor_user_id, coalesce(new.actor_label, 'Sistema'),
        'security.alert.anomalous_clinical_access', 'security_alert',
        'actor', new.actor_user_id::text,
        'Alerta: acceso clinico anomalo',
        'Se detecto un volumen inusual de eventos clinicos en una hora.',
        'security_alerts', concat('clinical_access:', new.actor_user_id::text, ':', v_bucket),
        jsonb_build_object(
          'threshold', 20,
          'window_minutes', 60,
          'observed_count', v_count,
          'source_action', new.action_code
        )
      )
      on conflict (source_system, source_record_key) do nothing;
    end if;
  end if;

  if new.action_code like 'function.error.%' then
    v_entity_id := coalesce(new.entity_id, split_part(new.action_code, 'function.error.', 2), 'unknown_function');
    select count(*)
      into v_count
      from public.admin_event_feed e
     where e.action_code like 'function.error.%'
       and e.entity_id = v_entity_id
       and e.occurred_at >= (v_now - interval '10 minutes');

    if v_count >= 5 then
      v_bucket := to_char(date_trunc('minute', v_now), 'YYYYMMDDHH24MI');
      insert into public.admin_event_feed (
        occurred_at, actor_user_id, actor_label, action_code, action_family,
        entity_type, entity_id, title, summary, source_system, source_record_key, metadata
      )
      values (
        v_now, null, 'Sistema', 'security.alert.repeated_function_errors', 'security_alert',
        'edge_function', v_entity_id,
        'Alerta: errores repetidos en funcion publica',
        'Se detectaron multiples errores en una Edge Function publica.',
        'security_alerts', concat('function_errors:', v_entity_id, ':', v_bucket),
        jsonb_build_object(
          'threshold', 5,
          'window_minutes', 10,
          'observed_count', v_count,
          'source_action', new.action_code
        )
      )
      on conflict (source_system, source_record_key) do nothing;
    end if;
  end if;

  return new;
end;
$$;

drop trigger if exists admin_event_feed_minimum_alerts on public.admin_event_feed;
create trigger admin_event_feed_minimum_alerts
after insert on public.admin_event_feed
for each row
execute function public.admin_event_emit_minimum_alerts();
